const articlesData = [{"slug": "article-11056", "title": "מהי שיטת תרפיית קו הזמן", "category": "NLP", "date": "", "excerpt": "מהי שיטת תרפיית קו הזמן או טיים ליין תרפי מאת עדנה מימון", "content": "שיטת תרפיית קו הזמן עולה אפילו על שיטת NLP, בכך שהיא מעלימה רגשות שליליים תוך זמן סופר קצר.\n\nאת שיטת תרפיית קו הזמן המציא דר' טד ג'יימס.\n\nלפני כעשר שנים, כשלמדתי אצלו את השיטה בארה\"ב, הייתי כבר מורה מנוסה לNLP, העברתי סדנאות שליטה בכעסים, וסדנאות ביטחון עצמי. עם זאת, כשהשתמשתי בשיטת תרפיית קו הזמן על עצמי, הייתי בהלם טוטלי. חיפשתי בתוכי את הרגש השלילי ולא יכולתי למצוא אותו. היה לי קשה להאמין שרגש שלילי, שהכרתי אותו כל כך הרבה זמן, שהיה מוכר לי היטב ( כמו חבר קרוב), נעלם כלא היה בתוך כמה דקות. השוק היה כל כך גדול שנבהלתי, ומיד לאחר מכן ירדו לי דמעות של אושר. דמעות של שיחרור. הייתי בהיי מטורף.\n\nכמובן שבאותו רגע הבנתי שיש לי משהו גדול בידיים (או יותר נכון בראש). התחלתי לדמיין איך אני מיישמת את שיטת תרפיית קו הזמן בסדנאות שליטה בכעסים שלי, בסדנאות ביטחון עצמי, וגם בקורס NLP Practitioner בתור בונוס. מיותר לציין שהשתמשתי בשיטת תרפיית קו הזמן גם בטיפולים אישיים / אימון אישי, מה שנקרא פגישות פרטניות אחד על אחד. התוצאות היו מדהימות. הן עברו את הדמיון הפרוע ביותר שלי ביחס לטיפול ברגשות שליליים ולהתנהגויות לא רצויות.\n\nהעולם לא יחזור להיות אותו הדבר!\n\nהעולם השתנה לחלוטין. התפיסה לגבי משך טיפולים השתנתה לחלוטין.\n\nטיפול בכעסים/עצבים וטיפול בחרדות ופחדים קיבלו תפנית חדה.\n\nמעכשיו והלאה אפשר להגיד ששיחרור כעסים ושיחרור פחדים וחרדות יכול להיות תהליך קצר טווח באופן משמעותי.\n\nשיטת תרפיית קו הזמן או טיים ליין תרפי שינתה את כללי המשחק בתחום הטיפול. לפני שמטפלים בשיטת תרפיית קו הזמן, חשוב להתעדכן בשני כללים בנוגע לתודעה ורגשות:\n\nאחד הדברים החשובים ביותר שחשוב לדעת בנוגע לרגשות הוא שרגשות נמצאים בתוך הגוף, במובן שהם תופסים מקום פיזי ממש.\n\nוידיעה מרעישה נוספת היא שרגשות שליליים גורמים לגוף שהוא בריא להיות חולה. זאת אומרת, שיש סיבה רגשית לבעיה בריאותית. בעיות בריאותיות הנוצרות לפתע, הן תוצאה של רגשות שליליים.\n\nלדברי דר' טד ג'יימס, תרפיית קו הזמן מבוססת על תגלית של דר' האמר מגרמניה, שגילה שרגשות שליליים גורמים לבעיות בריאותיות. דר' האמר, שהיה רופא משפחה, גילה שלכל רגש שלילי יש השלכה על איבר מסוים בגוף.\n\nלדוגמא, בן אדם שבעברו הרגיש שלא מקשיבים לו, ושלא נותנים לו להתבטא, הוא עלול לפתח בעיות בגרון.\n\nהוא עוד גילה שבחורה שיש לה עניינים לא פתורים עם אמא שלה או עם אחותה, יכולה לפתח סרטן שד.\n\nדר' האמר עצמו, שעד גיל 67 לא חלה אף פעם, חלה בפעם הראשונה בסרטן האשכים, עקב רציחתו של בנו יחידו שהיה בן 17. הקשר הוא שבנו הוא צאצא שלו, זרע שלו. דר' האמר גילה שבעיה בריאותית היא תוצאה של טראומה. אין הכוונה לכל טראומה, אלא למצב שבו הגוף אינו יכול לשאת זאת יותר.\n\nדר' האמר טיפל בחולים רבים באופן שהוא רגשי, ושיחרר אנשים רבים מהצורך בלקיחת תרופות או ניתוחים.\n\nונחזור לשיטת תרפיית קו הזמן, או טיים ליין תרפי. שיטה זו מבריאה אנשים ממחלות למיניהן, ואף מונעת מחלות בכך שהיא משחררת את הגוף מהרגש השלילי. אני יכולה להעיד על עצמי, שמאז שטיפלתי בעצמי בשיטה זו, אני אדם בריא לחלוטין.\n\nהשיטה שונה מטיפול פסיכולוגי, מכיוון שבטיפול פסיכולוגי מחזירים את הלקוח אל הטראומה, כדי לפתור אותה. מסתבר שהחזרת הלקוח אל הטראומה שהוא חווה לא רק שהיא לא מטפלת בטראומה, אלא אף מגדילה אותה. מכיוון שבעוד הלקוח מספר על הטראומה שחווה בעברו, הוא חווה אותה שוב. ומבחינת הגוף, זו טראומה נוספת. וזו הסיבה שהיא לא נעלמת.\n\nלעומת הטיפול הפסיכולוגי, שיטת תרפיית קו הזמן, או טיים ליין תרפי אינה גורמת ללקוח לחוות את הטראומה שוב, אלא משחררת אותה.\n\nשיטת תרפיית קו הזמן היא ידידותית למטופל. המטופל לא חווה טראומה נוספת ומיותרת. ובכל זאת, תוך זמן קצר מאוד המטופל משתחרר מטראומה שליוותה אותו שנים רבות.\n\nשיטת תרפיית קו הזמן, או טיים ליין תרפי דוגלת בלקיחת למידות מן העבר שלנו, מכיוון שהלמידות יכולות לשחרר רגשות שליליים. בנוסף לכך, חשוב מאוד לשחרר קונפליקטים הנמצאים בתת המודע, הגורמים לבעיות בריאותיות.\n\nכמובן שמטפל מנוסה יכול לזהות את הקונפליקטים של אנשים ולשחרר אותם.\n\nעל פי גישה זו מומלץ לסלוח על העבר לחלוטין, לקבל את השונה, לחשוב חיובי ועוד.\n\nלסיכום, שיטת תרפיית קו הזמן, או טיים ליין תרפי היא שיטה גאונית, חדשנית לטיפול בכעסים, בחרדות, בפחדים, בהתנהגויות לא אפקטיביות, בקונפליקטים ובכל רגש שלילי. כל זה תוך זמן קצר מאוד.\n\nגם טיפול זוגי שנעשה בשיטת תרפיית קו הזמן, או טיים ליין תרפי, יהיה יעיל פי כמה וכמה מטיפול זוגי רגיל. זאת מכיוון שבעיות בזוגיות מקורן בבעיות אישיות של כל אחד מהצדדים.\n\nגם בעיות במיניות, הלם קרב, טראומות, חרדות, דיכאון, בדידות, אי מציאת זוגיות, חוסר סלחנות, אונס וכו', ניתנות לטיפול מהיר בשיטת תרפיית קו הזמן.\n\nהמלצתי לקוראים: מינעו מחלות! תשחררו רגשות שליליים. ויש לזה בונוס גדול: אושר אמיתי.\n\nשיחת יעוץ מקצועית חינם.\n\nעדנה מיימון\n\nמאסטרית בשיטת תרפיית קו הזמן (טיים ליין תרפי) ו NLP, טריינר, מנחה סדנאות לשליטה בכעסים, ניהול כעסים, ביטחון עצמי, טיפול בחרדות, טיפול בפחדים ובטראומות. מורה מוסמכת בינלאומית ללימודי NLP, עם נסיון עשיר והצלחות מוכחות.\n\n* אני ממליצה מאוד שתשתפו מאמר זה, כי הרבה אנשים מפסידים את החיים האמיתיים, רק בגלל שהם לא מודעים ליתרונות הגדולים של שינוי. הם רגילים לקשיים, בעוד שלמעשה, היום, בזכות שימוש בתת המודע, שינוי הוא כמו משחק. גם משחקים וגם נהנים. העולם מתפתח, ואנחנו מתפתחים איתו.\n\nכל אחד יכול לבחור בין סדנא לתהליך פרטני. היום, האפשרויות החדשות מקלות עלינו ומאפשרות לנו לשמוח ולהנות כל יום מחדש. לתאריכי סדנאות"}, {"slug": "article-12283", "title": "איך להעלות את הביטחון העצמי", "category": "ביטחון עצמי", "date": "", "excerpt": "לעתים נדמה לנו שאנשים מפורסמים ויפים נהנים גם מדימוי עצמי גבוה. אך המציאות מראה שלא תמיד הדבר  כך . אם תקראו על גילויים עצמיים של ידוענים (סלבריטיז), כולל שחקנים מן השורה הראשונה, דוגמנויות יפהפיות, ז", "content": "הגדרה של המונח: ביטחון עצמי:\n\nהאמונה שאדם מסוים יכול לעשות משהו.\n\nהגדרה של המונח: דימוי עצמי:\n\nאיך אדם רואה את עצמו ביחס לאחרים.\n\nלעתים נדמה לנו שאנשים מפורסמים ויפים נהנים גם מדימוי עצמי גבוה. אך המציאות מראה שלא תמיד הדבר כך . אם תקראו על גילויים עצמיים של ידוענים (סלבריטיז), כולל שחקנים מן השורה הראשונה, דוגמנויות יפהפיות, זמרים מצליחים, שחקנים, סטנדאפיסים ועוד, תגלו שרובם סובלים מבעיות דימוי עצמי רבות. למשל, לא מרוצים מהמראה שלהם, או ממשקלם וכו'. חלקם סובלים מחרדות, למשל מחרדת קהל, מחרדה ממה יגידו, מחרדה מכישלון, מחרדה ממחלה, מחרדה חברתית, מביטחון עצמי ירוד, מדיכאון, מדימוי עצמי נמוך ועוד הרבה פחדים.\n\nאחת הדוגמאות הבולטות ביותר היא מייקל ג'קסון. כל ניתוחי הפלסטיק הרבים שהוא עבר, גרמו לו לקבל מראה מעוות ולא אטרקטיבי. הוא לא קיבל את עצמו כמו שהוא. למעשה, השינויים שהוא גזר על עצמו מוכיחים שהוא שנא את עצמו וברח ממה שהוא ראה במראה. מן הסתם, אם היה מטפל בבעיית הדימוי העצמי הנמוך שלו בהערכה העצמית הנמוכה, בדיכאונות שלו, בחרדות שלו, ובכלל בפחדים שלו, היה חוסך לעצמו את הסבל הרב.\n\nיש כמה דוגמאות טובות בסגנון הזה לגבי סלבריטיז מישראל, אך מסיבות ברורות לא אכנס לזה. תפעילו את הדימיון.\n\nאחד המכשולים העיקריים בקרב חלק מהאנשים בעלי דימוי עצמי נמוך הוא חוסר יכולת לשים מראה מול העיניים. זאת אומרת, הם לא מסוגלים להודות שהם באמת צריכים עזרה. מסיבה זו הם לא פונים לקבלת עזרה, והמצב נשאר אותו דבר, או אף נהיה גרוע יותר.\n\nמכשול נוסף הוא התחושה שנושא זה אינו כל כך חשוב. מחשבות כמו: \"כזה אני\", כך הם החיים\", ככה נולדתי\" וכו', הן מחשבות מוטעות. החשיבה כי יש נושאים חשובים יותר מאשר לטפל בדימוי העצמי מובילה לבעיות נוספות, אשר אנשים אפילו לא מעלים בדעתם כי זה הגורם לכך.\n\nלדוגמא: אדם בעל דימוי עצמי נמוך מחליט לקחת על עצמו פרוייקט גדול, בהנחה כי זה יחזק את דימויו העצמי. הרעיון כשלעצמו חיובי מאוד, אך במהלך הפרוייקט, אדם כזה עלול להחליט החלטות מוטעות מכיוון שהחשיבה שלו עדיין נמצאת במקום הלא נכון. הוא עדיין מחליט החלטות המושפעות אך ורק מפחדים של: \"מה אנשים יגידו\".\n\nואז, דוקא בגלל הפחד, הוא עלול לעשות טעויות, שלאחר מכן הוא יתחרט על בחירותיו. הוא יאשים את עצמו: \"למה עשיתי את זה\". למה לא עשיתי משהו אחר\".\n\nעומת זאת, ברגע שאותו אדם מכוון את מהלכיו ממניעים אחרים, ממניעים של ביטחון עצמי וידיעה ברורה כיצד פרוייקט X צריך להתנהל, ללא קשר למה שאנשים יגידו, או אז הסיכוי שהפרוייקט יתנהל נכונה יגדל.\n\nאנשים העובדים שעות רבות (מדובר בעיקר בשכירים) ומשקיעים מעל ומעבר בעבודה וחשוב להם שהכל יהיה טיפ טופ, ובסוף מוצאים את עצמם מותשים - שישאלו את עצמם: האם הם עושים את זה כדי לקבל הערכה? אם התשובה שעולה היא חיובית, מומלץ לטפל בזה דחוף!\n\nדוגמא נוספת היא בחירת בן/בת זוג. פעמים רבות בחירת בן/בת זוג מושפעת מרמת הדימוי העצמי שלנו. דוקא בחירה זו עלולה להוות מכשול במערכת היחסים. לרוב, אנשים בעלי דימוי עצמי נמוך בוחרים בן/בת זוג בעלי דימוי עצמי נמוך. חלק אחר מהאנשים בעלי דימוי עצמי נמוך בוחרים באנשים חלשים מהם, כדי להרגיש טוב עם עצמם, וחלק מהאנשים דווקא בוחרים בן/בת זוג בעלי דימוי עצמי גבוה. זאת בתקווה, כי זוגיות זו תמנף את הדימוי העצמי שלהם. אך, לאחר זמן מה הם מגלים שעובדה זו היא בעוכריהם. ואז מתחילים ויכוחים, אי הסכמות ותסכולים רבים, אשר ללא הדרכה מתאימה (מומלץ לקחת איש מקצוע), עלולים להוביל לאומללות או לגירושין.\n\nאנשים רבים נפגעים מחבריהם או מעמיתיהם לעבודה, או מכל אדם אחר, כאשר הסיבה לכך היא לא החבר, אלא מה שהאדם חושב על עצמו. במקרה כזה, יכול להיות שהחבר שם לו מראה, מבלי לשים לב לכך. ואז המראה עשתה את האפקט שלה ויצרה את ההיפגעות. לדוגמא: אם חבר שלך אמר לך שאתה סתום/שמן/מכוער/טיפש וכו', באופן טבעי זה יכול לפגוע בך. נשאלת השאלה: מה גרם לאותו חבר להגיד עליך מילים כאלה? התשובה היא: אתה. זאת אומרת, מה ששידרת. כל אחד משדר לאחר את הדימוי העצמי של עצמו. זה עובר על ידי ניואנסים בשפת הגוף ובדיבור. וכך, כשזה חוזר על עצמו שוב ושוב, נוצרת תקשורת סמויה שמאפשר לחבר להגיד לך מילים פוגעות. מסיבה זו, חשוב מאוד לפתח דימוי עצמי אפקטיבי, חוסן נפשי וביטחון עצמי. ובכך לקדם את עצמך. זו עובדה ידועה שמחשבות שליליות פוגעות מאוד בהתקדמות. ומחשבות חיוביות עוזרות להתקדמות ולביטחון העצמי.\n\nמסקנה: דימוי עצמי נמוך והערכה עצמית נמוכה גורמים לירידה בבטחון העצמי ולהפסדים רבים בחיים. לכן, מומלץ לא לדחות קבלת עזרה, אלא לעשות משהו בנדון. מתי? עכשיו! . מניסיוני, אנשים, אשר עברו אימון אישי או סדנא לחיזוק הביטחון העצמי והדימוי העצמי, העלאת הביטחון העצמי והעלאת הדימוי העצמי, דיווחו שסוף סוף הם מתחילים לחיות, ושהם מאושרים באופן שרק הם יכולים לדמיין את זה. הם גם דיווחו שהם מרגישים שהם בן אדם חדש. בן אדם שמסתכל לאנשים בעיניים, מיישר מבט, מדבר בקול בטוח, עם שפת גוף פתוחה וחושב יותר על מה שחשוב לו (ולא לאחרים). הוא גם חי יותר בשקט ובשלמות עם עצמו, מכיוון שכבר עבד על העלאת הביטחון העצמי שלו ועל העלאת הדימוי העצמי שלו.\n\nלמי מיועדת הסדנה:\n\nאיך לשפר ביטחון עצמי, איך לפתח ביטחון עצמי, לחזק ולהעלות את הדימוי העצמי\n\nאם אתה מרצים אחרים (מוותרים על עצמכם ומתאמצים למען אחרים, כדי שיעריכו אתכם, או כדי שיאהבו אתכם, או כדי שיחזירו לכם), אתם כנראה מוצאים את עצמכם מתאמצים מאוד, ולעתים מתאכזבים בגדול, סדנא לבטחון עצמי ודימוי עצמי בשבילכם בדיוק.\n\nאם אתם לא מצליחים להחליט החלטות, לא עומדים במילה שלכם כלפי עצמכם, מאחרים, מסתכלים במראה לעתים קרובות, משקיעים הרבה זמן בשיער, בלהתלבש, בלהתאפר, מתאפרות באופן מוגזם, נוגעים בשיער הרבה, נבהלים מאוד מ\"חצ'קון\" שצץ, גבכם מכופף, סובלים מחרדות, פוחדים ממה שיגידו, עסוקים באופן אובססיבי במראה הפנים והגוף, עסוקים מדי במשקל, פרפקציוניסטים, לא מאמינים בעצמכם, סובלים מחרדת מבחנים (או כל חרדה אחרת), פוחדים מלהתחיל עם בחורה, פוחדים מזוגיות, נמנעים מלהיפגש עם חברים, שקטים מדי בחברה, פוחדים להביע את דעתכם, חושבים מחשבות שליליות, משווים את עצמכם לאחרים, חשוב לכם מה יגידו, פוחדים מביקורת, מרגישים לא מספיק טובים, קשה לכם להתמודד עם החיים, חוויתם שיימינג בעבר, חברים פוגעים בכם, מרגישים תקועים וכו', סדנא בטחון עצמי ודימוי עצמי מדוייקת לכם. סדנה זו תגרום לכם לחזק את הביטחון העצמי, לחזק ולהעלות את הדימוי העצמי.\n\nאם אתם רוצים לחזק את הבטחון העצמי שלכם,, להעלות את הבטחון העצמי, לשפר את הבטחון העצמי, להאמין בעצמכם, לעשות, להתקדם, לחזק את היכולות שלכם, לחדד את הזיכרון, להרחיב את התודעה, להרגיש שליטה בחיים, להיות ממוקדים, להתקדם בחיים, להעלות את הדימוי העצמי שלכם, לייצר דימוי עצמי מנצח, לדבר עם ביטחון עצמי בקבוצה, לעמוד על שלכם, להחליט החלטות, לבטא את עצמכם בבטחון, להנות מהדרך, להרגיש שווים, להיות בחופש רגשי, לחיות טוב ועוד, זו הסדנא בשבילכם.\n\nהנה הטיפים לחיזוק הדימוי העצמי והביטחון העצמי, העלאת הביטחון העצמי והעלאת הדימוי העצמי\n\n1. תחמיאו לעצמכם. תבינו שאתם שווים בדיוק כמו אחרים. אתם אנשים מיוחדים. אין עוד אחד כמוכם. תעריכו את זה. במקום לרצות להיות כמו אחרים, תרצו להיות מה שאתם.\n\n2. תפסיקו להשוות את עצמכם לאחרים. אנשים המשווים את עצמם לאחרים פוגעים בעצמם, בהערכה העצמית שלהם ובדימוי העצמי שלהם.\n\n3. תפסיקו לחשוב \"מה יגידו\", \"מה יחשבו עלי\", \"איך יתפסו אותי\", \"איך יגיבו\", \"בוחנים אותי\", \"ילעגו לי\", \"יצחקו עלי\"....\n\nזה לא באמת קורה. זה רק בראש שלכם.\n\nתוציאו את זה מהראש שלכם ושחררו.\n\n4. תפסיקו לרצות אחרים. נכון שבטווח הקרוב אתם משיגים מזה הערכה וגם שקט. אך בטווח הרחוק זה פוגע בכם. תעשו מה שטוב לכם.\n\n5. דמיינו שהאדם מולכם קטן ומסכן, כמו תינוק. ושהוא זקוק מאוד לעזרתכם. בלעדיכם הוא אבוד. זה יתן לכם ביטחון.\n\n6. תפסיקו עם הצורך להיות מושלמים. תפסיקו עם הפרפקציוניזם. פרפקציוניזם טוב רק במקומות מסוימים. ברוב המקומות מומלץ לשחרר.\n\n7. אם אתם טיפוסים שחושבים בדרך של: \"או הכל או לא כלום\" - כדאי שתדעו שיש גם עוד מצבים בחיים. החיים הם לא שחור או לבן. קיימים עוד צבעים. תחשבו על אפשרויות נוספות. תהיו גמישים מחשבתית. תצאו מן הקופסה.\n\n8. תרשמו את הצלחותיכם באופן יומיומי. זה ימקד אתכם להצלחה.\n\n9. רצוי מאוד לא להשתתף בתחרויות. אתם לא צריכים להוכיח שום דבר לאף אחד. פשוט תעשו רק מה שעושה לכם טוב.\n\nאני יודעת שקשה לשמוע או לקרוא את המשפט הזה. יכול להיות שזה כבר גרם לכם להתנגדות כלשהי. אך לאחר התהליכים שתעברו בסדנא לביטחון עצמי ודימוי עצמי, תבינו בעצמכם למה הכוונה, ובאופן טבעי תסכימו איתי.\n\nכל דבר בזמנו:)\n\nאיך לשפר את הביטחון העצמי, עדנה מימון, סדנה לביטחון עצמי, דימוי עצמי\n\nStay\n\nIN TOUCH\n\nמאמרים\n\nהמלצות\n\nציטוטים ללא תרגום\n\nסיפורים עם מוסר השכל\n\nציטוטים\n\nצור קשר\n\nסדנה שליטה בכעסים"}, {"slug": "article-7437", "title": "ניהול כעסים - איך לנהל כעסים", "category": "כעסים", "date": "", "excerpt": "אנשים רבים שואלים אותי האם אפשר לנהל כעסים, ואם כן, איך עושים את זה.על מנת לענות על שאלה זו, אני אעלה שאלה משלי: מה זה בדיוק לנהל כעסים: מה עושים איתם? אוקיי. אני מבינה שאנשים אומרים לעצמם: אי אפשר לה", "content": "נתחיל בכך שנבין שניהול ותיעול כעסים אינו עניין של מה בכך. זה דורש עבודה פנימית. זה דורש אומץ להודות בדברים, נכונות לעשות דברים חדשים, נכונות לצאת מאזור הנוחות, נכונות לוותר על הרבה מחשבות ונכונות לאמץ מחשבות חדשות, אשר לעתים מנוגדות למה שחשבת עד כה.\n\nאם החלטת שאתה מוכן לקפוץ למים, קרא מאמר זה בעיון רב, ואפילו כמה פעמים.\n\nהנה כמה טיפים לניהול כעסים:\n\n1. תודה בכעס. לאנשים רבים חשוב מאוד להדגיש שהם לא כועסים כל הזמן, כאילו רוצים לפלס את הדרך לכך שמישהו יגיד להם: \"אתה בסדר. אתה לא צריך לשנות כלום. זה נורמלי לכעוס\".\n\nאם אתה מחפש שיגידו לך זה נורמלי לכעוס, זה לא המאמר בשבילך. מכיוון שמאמר זה מיועד למי שרוצה לוותר על כעסיו - וזה לא משנה אם זה נורמלי או לא. זה כמו שבן אדם שמפחד להכנס למעלית יגיד לי שזה נורמלי לפחד. למעשה, הכל נורמלי. השאלה היא לא אם נורמלי או לא נורמלי, אלא האם אתה מוכן להפסיק את הסיפורים שאתה מספר לעצמך, ולשנות את מה שמפריע לך. לשנות את מה שכואב לך ולסביבה שלך.\n\nאם כבר דיברנו על פחדים, אתן דוגמא על כך: בן אדם שיש לו פחד מלהתחיל עם בחורה. זה טבעי מאוד. זה נורמלי. האם בגלל שזה נורמלי, הוא לא ירצה לשנות את זה? הוא לא ירצה לטפל בפחד? האם עדיף להשאר ללא זוגיות?\n\nונעבור לשלב הבא:\n\n2. לאחר שהודית בכעס, תסכים איתי שבחלק גדול מכעסיך מעורב חוש הצדק. חשוב לך מאוד שיידעו שאתה צודק, שיידעו שאתה מבין, שיידעו שאתה חכם, שיידעו איך להתנהג, שיידעו מה דעתך, שיידעו שאתה לא מסכים למה שנאמר. בקיצור: שיהיה צדק בעולם. כאילו לקחת אחריות על הצדק ועל השפיות.\n\nולאחר שהסכמת איתי, הצעד הבא הוא להבין שאתה לא היחידי בחשיבה הזו. למעשה, כל אחד חושב שהוא הצודק. שהוא הידען, שהוא המבין וכו', ולכן זה לא משנה בכלל אם זה מה שמניע אותך או לא. ובמקרה כזה, עדיף שתבחר במשהו אחר. לידיעתך, עד כמה שאתה בטוח בצדקתך, אחרים עוד יותר בטוחים בצדקתם, ובדעה הפוכה משלך. עד כמה שאתה בטוח שאחרים לא שפויים ולא נורמלים ולא חכמים, יש מלא אנשים שיחשבו את אותו הדבר בדיוק עליך.\n\nנכון שאתה תגיד שאתה צודק והם טועים. זה בדיוק מה שהם אומרים מהצד שלהם: שהם צודקים ואתה טועה.\n\nבקיצור, זה לא הכיוון. הכיוון הוא: להבין שזה לא חשוב מי הצודק ומי השפוי, אלא מי יותר תקשורתי. מי יותר עם חוסן נפשי. מי יותר בשליטה עצמית. כמו שאומרים: \"אל תהיה צודק. היה חכם\". זאת אומרת שבן אדם שמחפש להיות צודק אינו בוחר בחוכמה. על מנת שיהיה שינוי, הפעם אתה תבחר להיות חכם.\n\nובשביל זה תשאל: \"מה אני רוצה במקום זה?\"\n\nלאחר שהחלטת להיות חכם, קיים מכשול בלעבור לשלב הבא: אנשים רבים נתקעים בשלב הזה, מכיוון שהם לא יודעים במה לבחור במקום הכעסים. הם כל כך רגילים להביע את דעתם, להיות צודקים, להגן על הצדק, להגן על עקרונותיהם, שהם באמת מתקשים לחשוב על משהו אחר.\n\nבמקרה כזה, אני מציעה על הקשבה והבנה.\n\nשתי יכולות אלה הן כמו שריר, שאם לא משתמשים בו זמן רב, הוא מתנוון, ויוצא מכלל האפשרויות של האדם. וזה גורם לאדם להגיע למצב שבו הוא לא יודע איך לבצע את זה.\n\nיחד עם זאת, כמו שעושים כושר לשרירים האחרים בגוף, כך גם מומלץ לעשות זאת בשרירי ההקשבה וההבנה.\n\nכמובן שזה לא יהיה קל בהתחלה. כמו בכל דבר חדש, בהתחלה זה יהיה קשה מאוד, וזה יהווה אתגר לא קטן. יחד עם זאת, מי שמתמיד, יוכל לקטוף את הפירות. הכלל החשוב הוא: להסכים ליפול הרבה. בהתחלה, הצורך לדבר יהיה מיידי. לאחר מספר פעמים זה יפחת.\n\nכדי להקל על ההקשבה וההבנה, עליך לדעת למה בכלל שתקשיב ותבין.\n\nהמטרה של ההקשבה וההבנה היא שתדע לתקשר עם אנשים. אחרי הכל, אתה מדבר עם מישהו. אתה רוצה שיקשיב לך, אך כשמגיע תורך להקשיב, אתה קוטע את השני באמצע. איך היית מרגיש אם היו עושים לך את זה?\n\nבנוסף ליכולת לתקשר עם אנשים, כדי שיקשיבו לך, אתה בוודאי רוצה לדבר בנימוס ובצורה תרבותית.\n\nלידיעתך: כאשר אתה מרים את קולך, או קוטע אנשים באמצע דיבורם, הם מאבדים את יכולת ההקשבה. יכול להיות שהם שותקים, אך הם לא באמת מקשיבים, ועל אחת כמה וכמה שלא משוכנעים מדבריך.\n\nמסקנה: אם אתה צועק, או קוטע אחרים באמצע דיבור, או מקלל או מרים יד, אתה לא משכנע!\n\n3. כדי לתרגל את ההקשבה, הנה תרגיל טוב, שעוזר מאוד: עשה תרגיל זה כאשר הנך לבד, במקום שקט. לא בזמן נהיגה!\n\nתרגיל לניהול כעס, טכניקה לניהול כעסים:\n\nחשוב על סיטואציה שבה כעסת.\n\nשים לב למיקום של הכעס בגוף. קבל את הכעס. לא לגרש אותו. תן לו להיות. בלי מלחמה.\n\nהיה מודע לתחושות, לדופק, לשרירים, לקול, לעיניים.\n\nעצום את עיניך.\n\nתן נשימה עמוקה ואיטית (ספור עד 4 בהכנסת האויר).\n\nהוצא את כל האויר מהגוף.\n\nחזור על תהליך הנשימה 5 פעמים.\n\nחזור על המנטרה: \"אני קשוב, אני מבין. אני רוצה להיות תקשורתי\". חזור על תרגיל זה 3 פעמים ביום (בוקר,צהריים, ערב). זה לוקח מעט מאוד זמן בכל יום. אתה משקיע 5 דקות כל פעם, ותקבל תוצאות משמעותיות.\n\nמגיע לך שתשקיע בעצמך. אתה שווה את זה, מסכים איתי?\n\nעדנה מיימון\n\nמאסטרית, טריינר, מנחה סדנאות לשליטה בכעסים, ניהול כעסים, ביטחון עצמי, טיפול בחרדות, טיפול בפחדים ובטראומות. מורה מוסמכת בינלאומית ללימודי NLP, עם נסיון עשיר והצלחות מוכחות.\n\nמעוניין בסדנא או תהליך אישי?\n\nהשאר פרטיך בטופס למטה, או בטופס בצד שמאל למעלה\n\nותהיה חלק מהאנשים ששיפרו את איכות חייהם באופן משמעותי\n\nלתאריכי הסדנאות הקרובות\n\nStay\n\nIN TOUCH\n\nמאמרים\n\nהמלצות\n\nציטוטים ללא תרגום\n\nסיפורים עם מוסר השכל\n\nציטוטים\n\nצור קשר\n\nסדנה שליטה בכעסים"}, {"slug": "article-8325", "title": "מאמר למי שמתנגד לשינוי", "category": "שינוי", "date": "", "excerpt": "אנשים רבים חוששים משינוי. חלק ממש מתנגדים לשינוי. חושבים ששינוי זה דבר רע, או חושבים: ", "content": "אנשים רבים חוששים משינוי. חלק ממש מתנגדים לשינוי. חושבים ששינוי זה דבר רע, או חושבים: \"מי שלא בסדר צריך להשתנות. ואני בסדר. אז מה פתאום שאני אשתנה? תשתנו אתם!\"\n\nאני מבינה. שינוי יכול להפחיד.\n\nאנשים רבים נותנים לחיים שלמים לעבור עם כעסים ופגיעויות, עם תיסכולים ותשישות נפשית, רק בגלל שהם חוששים משינוי. מצד אחד הם רוצים שינוי, הם עייפים מהכעסים של עצמם וממה שזה גורם להם, גם מבחינה בריאותית, וגם מבחינת ההשפעה ההרסנית על הסביבה ועל החיים בכלל.\n\nמצד שני, הם חושבים שזכותם לכעוס ולהתעצבן, כי מישהו עשה משהו מכעיס, משהו שהוא לא היה אמור לעשות, ולכן, צריך להתעצבן עליו. שידע שככה לא מתנהגים. שידע שעשה מעשה לא ראוי, מעשה לא פייר, לא הוגן. ושישנה את ההתנהגות שלו במהירות.\n\nעד כאן זה ברור ומובן.\n\nהעניין הוא שאם אנחנו מצפים ממישהו אחר שישתנה, בזמן שבעצמנו חוששים משינוי, האם זה פייר, האם זה הוגן שנצפה ממישהו אחר להשתנות?\n\nויכול להיות שהטענה היא שאנחנו בסדר, ואחרים לא בסדר.\n\nאולי כדאי שנבדוק טענה זו:\n\nאם אנחנו בסדר, כנראה אנחנו לא מקללים, לא עוברים על חוקי התנועה, לא מדברים בטלפון בזמן נהיגה, לא מכורים לסמרטפון בכלל, ובודאי לא לכל מיני רשתות חברתיות. אנחנו לא מדברים סרה מאחורי גבם של אנשים, לא עושים הכללות על עדות, על נשים, על גברים, על ילדים, על חברי כנסת, על ישראלים, על המדינה, על ארצות אחרות וכו', כי אנחנו בסדר. כנראה שאנחנו לא שופטים אנשים במובן השלילי: לא אומרים הוא כזה היא כזו, כי אנחנו בסדר. כנראה שאנחנו לא מרימים את קולנו על אחרים, כי התקשורת שלנו מכבדת. כנראה אנחנו לא מדברים בטון מצווה על ילדים כי אנחנו בסדר. כנראה אנחנו לא דורשים דרישות מבן זוג/בת זוג, כי אנחנו יודעים לדבר יפה. כנראה אנחנו לא מעגלים פינות לטובתנו. אנחנו לא קשים עם אחרים, כי אנחנו אנשים מבינים, אנחנו יודעים שאחרים יכולים לטעות, ולכן אנחנו סלחנים. אנחנו בסדר. גם אם אנשים נפגעו מאיתנו, הם לא בסדר שנפגעו. זו בעיה שלהם. אנחנו בסדר.\n\nמרגיש לכם שזה לא ממש כך?\n\nאל תגידו לי שלנו מותר ולאחרים אסור. הרי אנחנו פיירים, אנחנו הוגנים, נכון? הרי רק אחרים מתנהגים לא יפה, ולכן מגיע להם שנכעס עליהם.\n\nאנחנו בסדר. אחרים לא.\n\nאנחנו נורמלים, ואחרים לא.\n\nאנחנו בסדר ואחרים מזלזלים.\n\nאנחנו בסדר ואחרים מתנשאים.\n\nאנחנו בסדר ואחרים עושים אפליות.\n\nאנחנו בסדר ואחרים מתלוננים.\n\nאנחנו בסדר ואחרים לא יודעים לפרגן.\n\nאנחנו בסדר ואחרים מקללים ומדברים בשפה לא מכבדת.\n\nאנחנו נורמלים ואחרים לא נורמלים.\n\nאנחנו כל היום עושים טוב, ואחרים עושים רע.\n\nאנחנו רואים נכון, ואחרים לא.\n\nאנחנו שומעים נכון, ואחרים לא.\n\nאנחנו הגיוניים, ואחרים לא.\n\nאנחנו מציאותיים, ואחרים לא.\n\nאנחנו הצודקים, ואחרים לא.\n\nאנחנו הטובים (כבר אמרנו), ואחרים הרעים.\n\nוכשהם עושים רע, מגיע להם שנקלל אותם, שנצעק עליהם, שנגיד להם מי זו אמא שלהם באמת, שנוציא עליהם זעם רב, שיידעו שלא נשתוק להם.\n\nברור שאנחנו נורמלים. ברור שאחנו מדברים בשפה מכבדת ובטון מכבד. הקללות זה רק למי שמגיע. הצעקות זה רק למי שמגיע. הזעם והעצבים זה רק למי שמגיע. זה רק למי שלא מבין. זה רק למי שלא נורמלי, זה רק למי שלא קולט, כי אין לו יכולת קליטה. ההאשמות שאנו מאשימים, זה רק למי שמגיע. השיפוטיות שאנו מפעילים, זה לא שיפוטיות, אלא אמת. אנחנו רק מבטאים את מה שהם ומי שהם באמת. אנחנו מגלים להם את האמת על עצמם, שידעו.\n\nומי אלה האחרים?\n\nאלה שלא הסכימו איתנו.\n\nוכל מי שלא הסכים איתנו הוא טיפש. הוא לא מציאותי. הוא לא נורמלי. הוא לא הגיוני. הוא לא יודע מה הוא אומר. הוא לא יודע לחשוב. יש לו בעיה בחשיבה.\n\nאני לא יודעת מה איתכם, אבל אני מזהה פה קונפליקטים רבים. בעיקר לאור העובדה שמצד אחד אנחנו טוענים שאנחנו אלה המתורבתים, אנחנו הצד הטוב, ומצד שני כשאנחנו מזכירים למישהו מי זו אמא שלו, או אומרים לו שילך לעזאזל, אנחנו עדיין מתורבתים. אנחנו רק אומרים לו שיידע מי הוא ומה הוא... הוא לא יודע בעצמו... כדאי שיעשה משהו בעניין ומהר. כדאי שישתנה מהר.\n\nשישתנה?\n\nממתי אנחנו בעד שינוי?\n\nשרק אחרים ישתנו. אנחנו לא צריכים להשתנות....\n\nקונפליקטים, קונפליקטים. קונפליקטים.\n\nכן. בני האדם יכולים להיות מלאים בקונפליקטים.\n\nלפני שאסביר איך ומה לעשות, אני רוצה לציין שאין בן אדם שלא משתנה. אנחנו כל הזמן משתנים. מרגע שנולדנו השתננו הרבה. גופנו השתנה הרבה. ובהתאם לגופנו, התנהגותנו השתנתה. גם אם לא רצינו, המציאות טפחה על פנינו, והשתננו. לפעמים השינוי היה מפחיד, ובכל זאת קיבלנו על עצמנו את השינוי. לאחר זמן מה התרגלנו לשינוי.\n\nאם חווינו כל כך הרבה שינויים, כיצד זה אנחנו מתנגדים לשינוי נוסף, ודוקא הפעם שינוי שיקל עלינו מאוד, וגם ישפר את התקשורת שלנו עם הסביבה? השינוי שעליו אני מדברת ישפר לנו את הזוגיות, את התקשורת עם ילדינו, עם הורינו, עם חברינו, עם חברינו לעבודה, ובכלל ישפר לנו את הרגשתנו הפנימית. השינוי יוריד לנו סטרס, יוריד חרדות, יוריד תיסכולים, יוריד צעקות וקללות, יוריד מחלות ובכך יבריא את הגוף. השינוי יחזק את ההערכה העצמית ואת תחושת השלמות.השינוי ינטרל קונפליקטים, וזה יביא לנו לשלום הפנימי הנחוץ לנו.\n\nובכלל, איך זה שלמרות כל הטוב הזה, אנחנו עדיין מתנגדים לשינוי?\n\nהתשובה היא: פחד\n\nפחד משינוי כולל:\n\nפחד ממה זה אומר עלי\n\nפחד ממה יגידו\n\nפחד מלאבד את הזהות שלי\n\nפחד מלהתאמץ\n\nפחד מלהיות חלש\n\nפחד מלאבד שליטה\n\nפחד מלהיות רובוט\n\nועוד הרבה פחדים.\n\nוכאן אני רוצה להרגיע אתכם:\n\nמה זה אומר עלי? זה אומר עלי שאני אדם אמיץ, חכם, חושב נכון ומתקדם.\n\nלא יגידו עלי דברים שליליים, אלא רק חיוביים. ואפילו ירצו להיות כמוני. זה עדיף, לא?\n\nלא תאבדו את הזהות האמיתית שלכם. אדרבא, תחזקו את הזהות החיובית שלכם.\n\nלא תצטרכו להתאמץ. אתם תאהבו כל רגע בתהליך.\n\nלא תהיו חלשים. להפך בדיוק: תהיו חזקים ובשליטה אמיתית.\n\nלא תהיו חסרי רגש. להפך: תגלו רגשות חיוביים נהדרים, שיעזרו לכם להיות מחוברים יותר לעצמכם.\n\nאיך עושים את זה?\n\nנתחיל בכך שנשאל את עצמנו שאלה חשובה מאוד, שיכול להיות שלא חשבנו עליה קודם:\n\nהאם יכול להיות שקשה לנו להודות שגם אנחנו יכולים לטעות?\n\nהאם יכול להיות שקשה לנו להסתכל במראה ולהודות שבתת המודע אנחנו מתלוננים, כדי שלא יתלוננו עלינו?\n\nהאם יכול להיות שקשה לנו להודות שבתת המודע אנחנו מאשימים, כדי שלא יאשימו אותנו?\n\nהאם יכול להיות שקשה לנו להודות שבתת המודע אנחנו שופטים, כדי שלא ישפטו אותנו?\n\nוזה הזמן לזכור, שהמאמר מדבר על הפחד משינוי. ולכן, האם יכול להיות שבתת המודע שלנו אנחנו פוחדים שאם נשתנה, נהיה חלשים וחשופים להיפגעות?\n\nעובדה היא שבתת המודע שלנו קיים זיכרון ארוך ומלא מרגע שנולדנו ועד היום. זיכרון זה כולל סיטואציות שחווינו, שחלקן היו קשות. חלקן כללו האשמות, ביקורת, דרישות, חוסר אהבה, חוסר קבלה, חוסר פירגון. בסיטואציות מסוימות לא ראו אותנו, לא שמעו אותנו. היינו כאילו לא קיימים. וסיטואציות אלה מקשות עלינו גם היום, כי הזיכרון נשאר בתת המודע. סיטואציות אלה מניעות אותנו להגיב כמו שאחנו מגיבים.\n\nזאת אומרת, התגובה למישהו שהכעיס אותנו, קשורה ישירות לזיכרון מן העבר שלנו. ותגובתנו איננה קשורה לבן אדם שהכעיס אותנו, אלא לזיכרון שהיה דומה לזה בעברנו.\n\nמסקנה:\n\nכאשר אנחנו כועסים, הכעס הוא כעס ישן מן העבר. אנחנו משליכים אותו על בן אדם מהסיטואציה בהווה.\n\nדומה הדבר להשלכת הפסולת שלנו בחצרו של מישהו אחר, ללא רשותו, וגם להצדיק את עצמנו.\n\nעל מנת שנפסיק להשליך את הפסולת שלנו בחצרו של מישהו אחר, מוטב שנעשה שינוי בתת המודע שלנו.\n\nוהפעם, נבין ששינוי זה טוב, כי זה מחזק אותנו, בכך שננקה את הזיכרונות הכואבים מעברנו.\n\nואחרי שננקה את הזיכרונות הכואבים מעברנו, נרגיש הקלה, רוגע, שלמות פנימית, סיפוק, שמחה, הערכה עצמית, ביטחון עצמי, חיבור לעצמי, פרופורציות, כבוד עצמי ושלום פנימי.\n\nוכל זה יגרום לנו לתחושת אושר רב.\n\nמסקנה:\n\nשינוי זה נפלא. שינוי זה מחזק. שינוי נותן כוח וחוסן נפשי.\n\nאיך נתגבר על הזיכרונות הכואבים?\n\nנציין את הצלחותנו כל יום.\n\nנחמיא לעצמנו כל יום.\n\nנבין שאנחנו פה בזכות. מגיע לנו לחיות חיים טובים. מגיע לנו להנות. מגיע לנו לשמוח.\n\nנבין שאחרים לא קשורים לכל זה.\n\nניקח אחריות על הלכי הרוח שלנו.\n\nנרגיל את עצמנו למשפט: \"זה לא הוא/היא, וגם זה לא אני. לכן, אבחר בהבנה, שמחה, פרופורציות ואסתכל על הסיטואציה מתוך זוית ראיה אחרת\".\n\nנגיד את המשפט הזה כל יום, גם אם לא היתה סיטואציה. זאת על מנת לשכנע את תת המודע שיש שינוי והשינוי אמיתי ועושה לנו טוב.\n\nנבין שלכל בן אדם יש שק כלשהו על גבו שהוא סוחב, ושבעצם כולנו דומים בהרבה.\n\nנדע שמה שקורה בחוץ, לא בהכרח מעיד על מה שקורה בפנים.\n\nנבין שפרשנות היא רק דעה. פרשנות איננה מציאות. ומעכשיו והלאה, בכל סיטואציה נשאל את עצמנו: האם זו מציאות, או דעה?\n\nנסלח לעצמנו על טעויות. בני אדם מתפתחים מטעויות. טעות היא לא דבר שלילי. הלמידה מטעות יכולה לקדם אותנו.\n\nנגיד תודה על טעויות, כי הלמידה מטעויות נעשית רק כאשר אנחנו רגועים.\n\nנשתמש רק בשפה נקיה, חיובית. שפה שלילית גורמת לכעסים ולפגיעה בבריאות.\n\nנאהב את עצמנו.\n\nנאהב את העולם.\n\nנאהב את החיים.\n\nנאהב אנשים.\n\nנתאהב בשינויים, כי שינויים מחדדים את המוח, מרגיעים, מקדמים, מבריאים ויוצרים שמחה והתרגשות בחיים.\n\nוהכי חשוב: נתחבר לעצמנו. נהיה אנחנו באמת. לא נאמץ דמות אחרת, אלא נהיה מחוברים לאני האמיתי שלנו. אנחנו טובים באמת כאשר אנחנו מחוברים. הגיוני, לא?\n\nעדנה מיימון\n\nמאסטרית, טריינר, מנחה סדנאות לשליטה בכעסים, ניהול כעסים, ביטחון עצמי, טיפול בחרדות, טיפול בפחדים ובטראומות. מורה מוסמכת בינלאומית ללימודי NLP, עם נסיון עשיר והצלחות מוכחות.\n\n* אני ממליצה מאוד שתשתפו מאמר זה, כי הרבה אנשים מפסידים את החיים האמיתיים, רק בגלל שהם לא מודעים ליתרונות הגדולים של שינוי. הם רגילים לקשיים, בעוד שלמעשה, היום, בזכות שימוש בתת המודע, שינוי הוא כמו משחק. גם משחקים וגם נהנים. העולם מתפתח, ואנחנו מתפתחים איתו.\n\nכל אחד יכול לבחור בין סדנא לתהליך פרטני. היום, האפשרויות החדשות מקלות עלינו ומאפשרות לנו לשמוח ולהנות כל יום מחדש. לתאריכי סדנאות\n\nStay\n\nIN TOUCH\n\nמאמרים\n\nהמלצות\n\nציטוטים ללא תרגום\n\nסיפורים עם מוסר השכל\n\nציטוטים\n\nצור קשר\n\nסדנה שליטה בכעסים"}, {"slug": "article-9460", "title": "מהם 3 דברים המונעים ממך להפסיק לכעוס", "category": "כעסים", "date": "", "excerpt": "אנשים רבים מנסים להפסיק לכעוס בדרכים שלהם. הם מנסים ומנסים, שוב ושוב, אך בכל פעם הם מגלים שהם חוזרים על אותן טעויות", "content": "קרה לכם שהחלטתם להפסיק לכעוס באופן עצמאי, אך הזמן עבר ושום שינוי לא נראה לעין?\n\nאמרתם לעצמכם: \"זהו, החלטתי שבפעם הבאה אני לא אכעס על ילדי\". ולמרבה האכזבה, הפעם הבאה הגיעה, ואיתה הכעסים. או שאמרתם: \"בפעם הבאה אני לא אכעס על התנהגותו של הבוס/בוסית\", או \"התנהגותה של בת זוגי,\" או \"התנהגותו של בן זוגי\", אך, נדמה שהתגובה האוטומטית חזקה יותר מכם.\n\nלעתים גם קורה שאינדיווידואל מסוים מצליח להחזיק את עצמו לתקופה מסוימת (המתגלה כקצרה מאוד) , אך בסיומה הוא מתפרץ אפילו באופן קיצוני יותר ממה שנהג לעשות.\n\nוכך, אותו אינדיווידואל, ורבים אחרים כמותו, חווים אכזבה אחר אכזבה, שבסיומה קובעים שהכעס הוא חלק מהם, ולכן אין סיכוי שהם יצליחו להפסיק לכעוס.\n\nוזה חבל!\n\nאיך יוצרים שליטה בכעסים?\n\nלפני שנבין את זה, אציין שהמשפט: \"כל אחד יכול\" הוא קלישאה נכונה. אני מכירה קלישאות רבות שנכונות. הנה דוגמא נוספת לקלישאה נכונה: \"טעות לעולם חוזרת\". ועוד אחת: \"זה הכל בראש\", ואחרונה חביבה: \"רק אהבה מביאה אהבה\", ויש עוד הרבה.\n\nדרך אגב, הקלישאה: \"הזמן יעשה את שלו\" לצערי, לא תמיד נכונה. לפעמים היא אפילו הפוכה. הייתי אומרת שיש מקרים שבהם מי שמחכה שהזמן יעשה את שלו, מגלה שעם כל יום שעובר, שבו הוא לא יזם שום שינוי, הוא נכנס לתקיעות עמוקה יותר, נפשית ופיזית. זאת מכיוון שתת המודע שלנו מתכנת אותנו להתרגל לנוחות.\n\nואם אתם שואלים מדוע שתת המודע יתכנת אותנו להתרגל לנוחות, התשובה היא שחלק מתפקידיו של תת המודע הוא מינימום מאמץ. יש בזה יתרונות וחסרונות. אחד היתרונות הגדולים הוא שאם למדתי לעשות משהו חדש, למשל לדבר בשפה מסוימת, לאחר מספר מסוים של חזרות, הוא יגרום לי לזכור את השפה, ולכן, לא אצטרך ללמוד את השפה כל יום מחדש. וכך הוא חוסך מאמצים.\n\nמצד שני, אינדיווידואל למד לכעוס, גם זה יהפוך להרגל לאחר מספר פעמים של תירגול.\n\nמכאן המסקנה היא שתת המודע לא מבחין בין טוב לרע. האבחנה של \"טוב ורע\" היא באחריות המודע, מכיוון שהמודע יודע לשפוט. תת המודע לא יודע לשפוט.\n\nתת המודע הוא כמו מחשב, המכיל הרבה תוכנות. וכמו שהמחשב לא מבין בין טוב לרע, כך גם תת המודע שלנו.\n\nונחזור לנושא המאמר: מהם 3 דברים המונעים ממך להפסיק לכעוס\n\nובכן, 3 הדברים המונעים מאנשים לכעוס הם:\n\n1. האמונה ש\"הכעס שלי מוצדק, אז למה שאפסיק לכעוס? להפך, אני אכעס, ועוד איך אכעס, עד שיבינו\".\n\nלכאורה, אמונה זו נשמעת הגיונית, ואני מבינה לליבו של אדם החושב כך.\n\nהעניין הוא שכל בן אדם חושב את אותה מחשבה. למעשה, המחשבה: \"כעסי מוצדק\" שייכת לכל בן אדם כועס. תחשבו על המקרה הבא: שני בני אדם מתווכחים ביניהם, ואף צועקים זה על זה. כל אחד מהם חושב שכעסו מוצדק. ואפילו, כל אחד בטוח שהשני לא צודק.\n\nהאם אתם חושבים שההצדקה של הכעס עוזרת?\n\nבוודאי שלא.\n\nוכך, אנשים ימשיכו לכעוס לנצח, אלא אם כן, מישהו יחליט להפסיק את השרשרת המכשילה הזאת.\n\n2. האמונה שאם אני אוותר, או אשתוק, אני אהיה סמרטוט, ולא תהיה לי מילה.\n\nבזמן שאני מבינה את הטענה הזאת, אני רוצה לציין שאמונה זו נכונה במקרים מסוימים, ולא נכונה בהרבה מקרים אחרים. במציאות, יש אנשים שמוותרים מתוך פחד, ומצד שני יש אנשים שמוותרים מתוך חוזק. אלה אנשים שמעריכים את עצמם ובוטחים בעצמם. אלה אנשים שיודעים מי הם ומה הם, ולכן, הם מוותרים. יכול להיות שעד עכשיו חשבת שלוותר פירושו להיות חלש. ועכשיו, יש לך הזדמנות לאפשרות נוספת, הקיימת בעולם, אך לא הרבה מכירים אותה: לוותר פירושו להיות אמיץ וחזק!\n\nמי שמפחד להיות סמרטוט, כנראה שיש לו אמונה שמי שמוותר או שותק, הוא סמרטוט. כפי שכבר ציינתי, במציאות קיימים אנשים רבים המוותרים, ואפילו לרגע אחד לא מרגישים סמרטוט. להפך, הם מרגישים גאים בעצמם על כך שמנעו מריבה ואי נעימות. וגם הם חשבו לטווח רחוק, כי כבר ראו את ההמשך בדמיונם, וידעו שהם לא רוצים המשך לא נעים.\n\nמסקנה: כשבן אדם מוותר מתוך עוצמה, הוא חזק יותר ממי שלא מוותר. אם שני יריבים נלחמים בכוח זה מול זה, הם מאבדים הרבה אנרגיה לשווא. למעשה שניהם מפסידים. ופה אנצל את ההזדמנות לציין קלישאה נוספת: \"במלחמה יש רק מפסידים\". עדיף ללמוד מאייקידו, או שיטות נוספות הדוגלות בעיקרון: אם אחד מהיריבים זז הצידה, לשני לא יהיה עם מי להלחם.\n\n3. האמונה ש\"אני הוא הכעס. זה מי שאני\".\n\nאנשים רבים אומרים לי את המשפט הזה, ולא שמים לב עד כמה הם יורים לעצמם ברגליים. זאת מכיוון שכאשר לבן אדם יש אמונה לגבי מי שהוא, כביכול הוא הכעס, יווצר מצב שלא משנה כמה הוא ינסה, הוא לא יצליח להפסיק לכעוס. כידוע לכם, האמונות שלנו יוצרות לנו את המציאות שלנו. הרבה פעמים אלה אמונות הנמצאות בתת המודע של אינדיווידואל, כאשר הוא כלל לא מודע לכך.\n\nהאמונה שאתה רוצה לאמץ לעצמך היא שלא נולדת עם הכעס. אתה למדת לכעוס. ועכשיו יש לך הזדמנות ללמוד משהו אחר.\n\nתרומתו של מאמר זה היא בכך שהיא פותחת לאנשים את העיניים ומביאה אותם למודעות בנוגע לאמונות שלהם. וברגע שבן אדם יודע שיש לו אמונות לא אפקטיביות, הוא תמיד יוכל לבחור לשנות אותן.\n\nלסיכום:\n\nהקלישאה/אמונה ש\"כל אחד יכול\" היא אפקטיבית ונכונה. מודעות לאמונה מהווה טריגר, שיגרום לבן אדם עם כעסים לפתוח ערוץ נוסף במוח, ובמקום לכעוס, לבחור לעשות שינוי, למענו, למען בריאותו ולמען האנשים שמסביבו, שכנראה סובלים מאוד.\n\nוזיכרו: מי שבוחר בשינוי מעריך את עצמו ומכבד את עצמו יותר ממי שמחכה. שינוי קורה כאשר בן אדם סקרן מספיק ללמוד משהו חדש ומאמין מספיק שיש עוד דברים ללמוד.\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP בינלאומית (קורס NLP Practitioner, וקורס NLP Master Practitioner).\n\n050-7378535"}, {"slug": "האם-אתה-אבא-טוב", "title": "האם אתה אבא טוב?", "category": "הורות", "date": "", "excerpt": "תאר לך שאתה עובד במקצוע חשוב מאוד. המשרה שלך חשובה לך ביותר. המשכורת שווה כל מאמץ. התפקיד דורש עבודה של שעות רבות, פלוס מאמץ למצוא פתרונות לבעיות העולות מדי פעם.האם היית מתאמץ כמיטב יכולתך על מנת להגי", "content": "תאר לך שאתה עובד במקצוע חשוב מאוד. המשרה שלך חשובה לך ביותר. המשכורת שווה כל מאמץ. התפקיד דורש עבודה של שעות רבות, פלוס מאמץ למצוא פתרונות לבעיות העולות מדי פעם.\n\nהאם היית מתאמץ כמיטב יכולתך על מנת להגיע לתוצאות הטובות ביותר?\n\nהרשה לי לענות במקומך: כמובן שכן!\n\nהרי לא היית רוצה לזלזל בתפקיד כל כך משמעותי, עם משכורת נאה בצידו.\n\nמן הסתם, אם היית מזלזל בתפקידך, התוצאות היו עגומות, ואתה היית מוצא את עצמך מפוטר.\n\nעד כאן בעבודה מחוץ לבית.\n\nומה לגבי עבודה בתוך הבית?\n\nמניסיוני עם הרבה משפחות, מסתבר שהרבה אבות בטוחים שהם נחשבים ל\"טובים\", כשהמציאות מראה שהמצב אפילו אינו קרוב.\n\nנכון, אין כלל הקובע אם אתה אבא טוב או לא. אך זה בדיוק העניין. דווקא מכיוון שאין כלל כזה, הרבה אבות מרשים לעצמם להתנהג באופן שאינו הולם את תפקידו של אב. הרי לא תידבק בהם סטיגמה של \"אב לא טוב\", והם גם לא יעמדו בפני פיטורין.\n\nכל זה הולך להשתנות. אב לא טוב אומנם לא יעמוד בפני פיטורין, אך תידבק בו הסטיגמה: \"אב לא טוב\".\n\nהבה נבדוק אם אתה אב (עובד) טוב:\n\nהמשרה: אבא\n\nראיון עבודה:\n\nשלב א':\n\n1. האם אתה מתעניין בילדך? הווה אומר, יושב איתו (רצוי בחדרו, או במקום נעים מחוץ לבית), משוחח איתו על מה שמעניין אותו, על מה שקשה לו, על שאיפותיו, על אהבותיו, על אכזבותיו, על קשייו, על תחביביו?\n\nאזהרה: דעתך לא כל כך חשובה. ההקשבה שלך היא החשובה. פשוט הקשב.\n\n2. כשאתה איתו, האם שפת גופך במאה אחוזים איתו?\n\n3. האם הנייד שלך כבוי?\n\n4. האם נכנסת אליו לחדר ללא עתון ביד?\n\n5. האם הודעת לשאר חברי המשפחה שלא להעביר לך שיחות, ולא להפריע בשום אופן (כולל העולל החמוד, בן השנתיים)?\n\n6. האם אתה נינוח ונותן תחושה שאתה רוצה להישאר?\n\n7. האם אתה מסתכל לילדך בעיניים כשאתה מדבר אליו?\n\n8. האם אתה אומר לו שאתה אוהב אותו?\n\n9. האם אתה אומר לו כמה שאתה גאה בו, ושמח שאתה אבא שלו, והוא הבן שלך?\n\n10. האם אתה חוזר על שיחה זו פעם בשבוע ?\n\n11. האם שיחה זו היתה מתוכננת מראש (רשומה כחלק מתוכנית העבודה שלך)?\n\n12. האם אתה מחמיא לו יותר מאשר מעיר לו? זכור: אם כבר אתה לא יכול להתאפק מלהעיר, אזי היחס צריך\n\nלהיות 1 ל- 10, היינו, הערה אחת על כל עשר מחמאות. וגם אז, על ההערה להיות בונה. היינו ממקום של לעזור, ולא כתלונה או האשמה.\n\nשלב ב':\n\n1. האם אתה לוקח חלק פעיל בחינוך ילדיך? את הילד לא מעניין שאין לך זמן ואתה עובד קשה. הוא צריך אב הלוקח אחריות עליו. כך הוא מרגיש בטוח. זה נותן לו ביטחון עצמי.\n\n2. האם אתה נותן תפקידים לילדיך? האם אתה בודק שהם ממלאים אותם על הצד הטוב ביותר? את הילד לא מעניין שאימו נותנת לו תפקידים. הוא צריך שגם אביו ייתן לו תפקידים.\n\nזכור: ילד מפנים את מה שהוא רואה וגם את מה שהוא לא רואה! לדוגמא, אם אביו לא נותן לו תפקידים, אלא רק אימו, הוא מבין שאבות אינם נותנים תפקידים ושתפקידים אינם דבר חשוב.\n\n3. אם הוא צופה יותר מדי שעות בטלויזיה (ויודע שאביו מודע לזה, אך לא אומר לו כלום), הוא מבין שזה בסדר לצפות שעות רבות בטלויזיה.\n\n4. אם הוא לא קורא ספרים (ויודע שאביו מודע לזה, אך לא אומר לו כלום), הוא מבין שזה בסדר לא לקרוא ספרים.\n\n5. אם הוא התחצף לאימו, ואביו שמע, אך לא הגיב, הוא מבין שזה בסדר להתחצף לאמו.\n\nכלל: החינוך יכול להתבצע גם אם אתה עובד שעות רבות, ובקושי רואה את ילדיך. אין יותר תירוצים!\n\nשלב ג':\n\nהתמודדות: כשמשהו לא מסתדר, האם אתה לוקח את העניינים לידיים ומנסה לפתור את הבעיה, או שמאשים אחרים במצב (לא משנה את מי)? להזכירך, ילדים צופים בהוריהם ומפנימים. אם הם רואים אב שלא נכנס לפניקה, ולא מתחיל להאשים ולצעוק על אחרים, אלא בתושיה מנסה להתמודד עם הבעיה, הם לומדים שכך צריך להתנהג, ולהיפך: אם תגיב בפניקה, בהאשמות ובצעקות, הם יבינו שכך צריך להתנהג.\n\nשלב ד':\n\nזוגיות: האם יחסך אל אשתך חיובי ואוהב? זכור: זוגיות עם כבוד ואהבה (ללא האשמות) משפיעה לטובה על ילדיך. אם אתה מזלזל באישתך, ילדיך יזלזלו בה, ובעתיד יזלזלו בנשותיהם.\n\nשלב ה':\n\nבריאות: האם אתה עוסק בספורט כלשהו? רצוי עם הילד. זה יכול להיות זמן איכות נהדר. זכור שוב: ילדים מפנימים מה שהם רואים, וגם מה שהם לא רואים.\n\nאם אתה מעשן, הורד לעצמך 10 נק'. הורה מעשן נותן דוגמא שלילית ביותר לילדיו. הוא בעצם משדר להם: \"אני חלש. אני נכנע לדברים שליליים, אין לי עמוד שידרה\". לכן, אין פלא שילדיו גדלים באותו אופן. שמעתי הרבה הורים מעשנים שאומרים \" אני מסביר לילדי שהעישון הוא טעות גדולה, שאם מתחילים לעשן, יהיה קשה להפסיק. ולכן, שלא יעזו להתחיל\". מלים אלו הן הבל הבלים. הרי, כפי שכבר טענתי, ילדים מפנימים את מה שהם רואים, והרבה פחות את מה שהם שומעים.\n\nלסיכום\n\nהכן את ילדך לחיים האמיתיים. הצטרף אליו לטיולים, קח אותו איתך למקומות וארועים שונים. חזק את דימויו העצמי ואת ביטחונו העצמי. אפשר לו להתנסות בחוויות רבות ככל הניתן. אם יש לך כמה ילדים, תארגן גם בילויים משפחתיים וגם בילויים עם כל אחד לחוד! אפשר לילדך להיות מה שהוא רוצה להיות, ולא מה שאתה רוצה שהוא יהיה. תכבד את חבריו ואת השקפת עולמם. אל תרכל מאחורי גבם של אנשים ואל תנבל את פיך. ילדים מפנימים הכל. אל תכריח אותו לאכול את מה שהוא לא אוהב. אל תבחר עבורו חוגים או תחומי עניין. אפשר לו לעשות זאת. אל תתאכזב אם הוא נכשל במבחן. יש לכך סיבה. לרוב הסיבה רגשית.\n\nהמשך כך, גם אם הילד עבר את גיל ההתבגרות!\n\nניקוד:\n\nשלב א' = 40 נקודות (שאלה מס' 1 = 4 נק', כל השאר = 3 נק')\n\nשלב ב' = 15 נקודות (כל שאלה: 3 נק')\n\nשלב ג' = 20 נקודות\n\nשלב ד' = 15 נקודות\n\nשלב ה' = 10 נקודות\n\nעל פי הסיכום, החלט אם היית מקבל את עצמך לעבודה.\n\nבמחשבה שנייה, עדיין לא מאוחר. שפר את ביצועיך ובחן את עצמך שוב.\n\nבהצלחה!\n\nהערה א': השימוש במילה \"ילד\" ולא \"ילדה\" נעשה מטעמי נוחות בלבד. הכוונה כמובן לשני המינים.\n\nהערה ב': עכשיו, תן לאישתך למלא את השאלון (לגביך). הניקוד שלה יכול להיות שונה משלך (ומן הסתם אמין יותר...).\n\nעדנה מימון\n\nטריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, מאמנת אישית להעלמת רגשות שליליים והעלמת טראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: זוגיות לעניין. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות, מורה מוסמכת ל NLP\n\n050-7378535"}, {"slug": "האם-אתה-טיפוס-מתיש", "title": "האם אתה טיפוס מתיש?", "category": "תקשורת", "date": "", "excerpt": "במאמר הזה אספק פרופיל של בן אדם שמתיש את הסביבה שלו. יש אנשים המתישים את סביבתם על בסיס קבוע, ויש אנשים העושים זאת עם בן אדם מסוים (תופסים קורבן תורן...). חלק מודעים לכך ובכל זאת ממשיכים בזה, וחלק מעד", "content": "כן. יש גם כאלה....\n\n* במאמר זה אספק פרופיל של בן אדם שמתיש את הסביבה שלו. יש אנשים המתישים את סביבתם על בסיס קבוע, ויש אנשים העושים זאת עם בן אדם מסוים (תופסים קורבן תורן...). חלק מודעים לכך ובכל זאת ממשיכים בזה, וחלק מעדיפים שלא לחשוב על זה.\n\nמאמר זה מיועד לאלה המעדיפים שלא לחשוב על זה...\n\nתבדוק: האם אתה טיפוס שואב אנרגיה מאנשים ומתיש אותם?\n\nאנשים המתישים את סביבתם הם כמו עלוקה. הם נדבקים ולא עוזבים. בשלב מסוים אתה תרצה להתרחק מהם קצת כדי לנשום, ואז אתה לא יודע לאיזו מלכודת נכנסת: הטיפוס המתיש יגיב בפגיעות עמוקה ובכעס רב. וזו רק ההתחלה. הוא עוד ימצוץ לך את הדם על כך שתפסת ממנו קצת מרחק. אתה עוד תצטרך להתנצל בפניו על ההתרחקות הזאת, כי הוא כבר ידאג להאשים אותך עד כמה אתה לא בסדר, עד כמה אתה לא הוגן, עד כמה אתה לא חבר, עד כמה אתה בן אדם רע, עד כמה אתה כפוי טובה וכו' וכו'....\n\nהטיפוס המתיש נעשה חבר שלך עוד לפני שידעת. הוא לא מחכה לבדוק אם מתאים לך להיות חבר שלו או לא. הוא כבר יכנס לחייך מהר מאוד: לעתים על ידי נתינת מתנות, לעתים על ידי עזרה כלשהי (מבלי שתבקש), לעתים על ידי שיחה נעימה איתך. ואז, לאחר שנתפסת ברשתו הגעת למצב של \"אל חזור\".\n\nלטיפוס המתיש אין חיים משלו. זו הסיבה לכך שהוא מחפש כל הזמן אנשים שיתנו לו חיים. אך לאחר זמן מה הוא מגלה שאנשים אלה לא מוכנים להיות החיים של מישהו אחר, רק שאז ה\"מתיש\" כבר מרגיש שאנשים חייבים לו.\n\nניתן לזהות טיפוסים מתישים על ידי צורת הדיבור שלהם:\n\n\"נתתי לו כל כך הרבה! כל פעם שהיה צריך משהו, מיד רצתי לעזור לו. עזבתי הכל והשקעתי בו. במקום לעזור למשפחה שלי, עזרתי לו. ישבנו שעות רבות ביחד ושוחחנו רבות. השיחה זרמה. היה חיבור בינינו. ביקרתי אצלו בבית לעתים קרובות. הייתי אצלו בבית יותר מאשר בבית שלי, תמיד הבאתי איתי משהו. תמיד עזרתי. התקשרתי אליו כל יום כדי להתעניין ולשאול לשלומו. וגם כשהתקשרתי שוחחנו ארוכות. הראתי עניין אמיתי. תמיד שאלתי אם הוא צריך משהו. גם אם לא היה צריך, אני עזרתי. כי כזה אני. אני אוהב לעזור, הבית שלי היה כמו הבית שלו.... ואז התחילה ההדרדרות. הוא התחיל לסנן אותי. וזה משהו שאני לא סובל. בטח לא מחבר קרוב. ככה לא מתנהגים לחבר. בנוסף לזה, שמתי לב שהוא מתחמק ממני. אין לו זמן בשבילי. כל מה שאני מציע, הוא אומר \"לא עכשיו\", או \"אין לי זמן\", או \"אני עסוק\", או \"אני נכנס לפגישה\", או \"אני עייף\" או \"שכחתי לחזור אליך\" ועוד תירוצים. עד שבשבוע שעבר גיליתי את פרצופו האמיתי: הוא אמר לי: \"אתה מציק לי\". אני מציק לו? אני???? איך אני יכול להציק לו? ככה מדברים לחבר? זה חבר זה? אני אומר לך: עד שהוא לא יתנצל על ההתנהגות שלו, אני לא אסלח לו. איך הוא לא מתבייש....ממש חוצפה....שיתבייש לו.....חסר נימוס....כמובן שהוא התחיל. אני דיברתי אליו יפה. לא התחצפתי. הוא זה שהתחצף. איך אני הצקתי לו? איך הוא לא מתבייש להגיד את זה? אני דיברתי בתמימות. שאלתי אותו לשלומו. הכל בתמימות. הכל מתוך רצון טוב. אני לא אנוח ולא אשקוט עד שיתנצל\".\n\nאחרי יומיים....\n\nהמתיש מרגיש את הריקנות, מרגיש שאין לו חיים, ושהוא זקוק לחבר. הוא הרי עלוקה. ועלוקה זקוקה לקורבן. הוא מתקשר ל\"חבר\" ומסביר לו שהוא סולח לו ושאין לו טינה כלפיו.\n\nעד מהרה מתחיל סיבוב של התשה נוסף, שאחריו מגיע שלב הנפגעות, הכעסים והעצבים וחוזר חלילה....\n\nאז מה הבעיה הכי גדולה?\n\nהבעיה היא ששני סוגי המתישים ימשיכו בהתנהגותם גם במקרה שיעירו להם על כך. הם ימשיכו לחשוב שהם קורבן ושנעשה להם עוול גדול.\n\nלכן, במידה שזיהית את עצמך כמתיש, אנא פנה לקבלת עזרה באופן דחוף! אתה גורם לסבל רב לאנשים סביבך. אתה תקוע חזק. אנשים בסביבתך מותשים.\n\nבמידה שזיהית את עצמך כמותש, תזהה את הטיפוסים המתישים ותתרחק מהם כבר בהתחלה. אל תנסה לעזור להם. אל תרגיש נקיפות מצפון (המתישים מעולים בלגרום לאנשים כמוך נקיפות מצפון). תהיה אסרטיבי ותברח מה\"חברות\" הזאת ובכך תציל את עצמך.\n\n* המאמר כתוב בלשון זכר לשם נוחות בלבד. כמובן שהוא מיועד גם לנשים.\n\nכתבה: עדנה מימון מורה מוסמכת לNLP מטעם ממציא הNLP, מאמנת אישית ומנחה סדנאות לשליטה בכעסים, שיפור הזוגיות, ביטחון עצמי, חשיבה חיובית, טיפול בטראומות, חרדות, פחדים, פוביות, טיפול ברגישות יתר ובהעלבות/נפגעות/פגיעות"}, {"slug": "הקשר-בין-הצלחה-אושר-ודיכאון", "title": "הקשר בין הצלחה, אושר ודיכאון", "category": "הצלחה", "date": "", "excerpt": "לפני כשבועיים חליתי בשפעת קשה מאוד.לא הבנתי מאיפה זה בא לי. אני בדרך כלל בריאה (גם כשיש מסביבי חולים). זה לא מתאים לי. מה קרה לי?ביום הרביעי לשפעת, כאשר יכולת החשיבה חזרה אלי אט אט, בדקתי זאת עם תת המ", "content": "לפני כשבועיים חליתי בשפעת קשה מאוד.\n\nלא הבנתי מאיפה זה בא לי. אני בדרך כלל בריאה (גם כשיש מסביבי חולים). זה לא מתאים לי.\n\nמה קרה לי?\n\nביום הרביעי לשפעת, כאשר יכולת החשיבה חזרה אלי אט אט, בדקתי זאת עם תת המודע שלי.\n\nההסבר שקיבלתי מתת המודע זיעזע אותי: דיכאון\n\nכן. מסתבר שהייתי בדכאון ולא ממש הייתי מודעת לזה. עכשיו, כשאני משחזרת את ארועי החודשיים האחרונים, אכן לא היה לי תיאבון ולא היתה לי שמחת חיים מזה כחודשיים!\n\nלא הבנתי איך זה יכול להיות. הרי אני מלמדת אנשים להיות מאושרים. אני גם מאמנת אנשים באופן אישי להיות מאושרים. בתהליכי אימון אישי אני עוזרת לאנשים להעלים רגשות שליליים מן העבר שלהם, להעלים דכאונות, פחדים, חרדות, לחזק בטחון עצמי וכו', אני עוזרת לזוגות לפתור קונפליקים קשים ומחזירה אותם לימים היפים והטובים שהיו להם בעבר אז מה קרה לי?\n\nובכן, עלו לי שתי תובנות עקריות:\n\nאחת: תסמונת המובן מאליו - אני התיחסתי להצלחות שלי כמובנות מאליהן. ז\"א, לא טפחתי לעצמי על השכם למרות ההצלחות האדירות שחוויתי עם לקוחותי, אפילו לא אמרתי לעצמי: \"כל הכבוד\", או \"הצלחתי שוב\" או חיוך, או כל אמירה מחזקת אחרת.\n\nבשבילי, להצליח, היה כמו לצחצח שיניים לפני שינה מובן מאליו.\n\nוזה שוחק!\n\nמהר מאוד, בלי לשים לב מגיעים לחשיבה של: \"אז מה אם עשיתי X?\", \"אז מה עם עשיתי Y?\", \"זה רגיל\", \"זה דבר שבשיגרה\" וכו'.\n\nבמצב כזה מחכים לדבר שנותן את תחושת האושר הגדול אך זה לא מגיע.\n\nזה כמו אנשים שלוקחים סמים, אך בשלב מסוים המינון הרגיל לא מספיק, ולכן הם מעלים את המינון, או מגבירים את התדירות.\n\nאז אל תחכו לתחושת האושר הגדול! תייצרו את התחושה! תחגגו הצלחות!\n\nוכדי שההצלחות שלכם לא יהיו מובנות מאליהן, תעשו לכם רשימה של ההצלחות. לאחר זמן מה תגלו שזה עושה ממש טוב. אנשים לא שמים לב שרוב היום הם חווים הצלחות. הם לוקחים את זה כמובן מאליו.\n\nאם קמתם בבוקר זו הצלחה. אנשים רבים לא מצליחים לקום בבוקר.\n\nאם אירגנתם את הילדים זו הצלחה.\n\nאם הגעתם לעבודה זו הצלחה.\n\nאפילו אם חשבתם מחשבה חיובית זו הצלחה. וכו'.\n\nשום דבר אינו מובן מאליו. כך עובד תת המודע.\n\nומה היא התובנה השניה?\n\nהתובנה השניה היא: זמן לעצמנו\n\nאנשים יקרים, אם אתם מאלה שמתקתקים עניינים, אתם קמים בבוקר, מכינים ומארגנים את הילדים, אח\"כ עבודה, אח\"כ שוב בית, בישולים, ילדים, קניות, נקיונות, כביסות וכו', וגם אם אין לכם ילדים, אבל אתם עמוסים בעשיה ללא רגע מנוחה היזהרו!\n\nזה עלול לשחוק! שפעת מגיעה כתוצאה משחיקה!\n\nזמן איכות לעצמכם הוא חשוב מאוד. ולכן, אם בתוך התוכנית היומית שלכם אין לכם זמן השקעה בעצמכם ובתחביבים שלכם תעשו טובה לעצמכם ותכניסו את זה ללו\"ז. ואם לא כל יום, אז לפחות פעם פעמיים בשבוע.\n\nאחרת, אם הדיכאון יגיע, אל תגידו שלא הזהרתי.\n\nומה בנוגע אלי?\n\nהחלטתי להתמקד בהצלחות שלי ולהשקיע זמן בעצמי. אני שוב מאושרת. התיאבון חזר. עוד מעט אנעל נעלי ספורט ואצא להליכה.\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nednamaim@gmail.com"}, {"slug": "הרהורים-עקב-תוכנית-ריאליטי", "title": "הרהורים עקב תוכנית ריאליטי", "category": "כללי", "date": "", "excerpt": "אני לא נוהגת לראות טלויזיה. יחד עם זאת, לעתים אני רואה דוקא את תוכניות הריאליטי. זאת, כדי לבדוק דינמיקה קבוצתית ומצבים רגשיים שאליהם מגיעים אנשים תחת לחץ. מצבים רגשיים אלה באים לידי ביטוי בהתנהגויותיה", "content": "זוגיות\n\nאני לא נוהגת לראות טלויזיה. יחד עם זאת, לעתים אני רואה דוקא את תוכניות הריאליטי. זאת, כדי לבדוק דינמיקה קבוצתית ומצבים רגשיים שאליהם מגיעים אנשים תחת לחץ. מצבים רגשיים אלה באים לידי ביטוי בהתנהגויותיהם.\n\nלדוגמה, באחת התוכניות היה זוג שהגיע למצב של \"או שמוצאים פתרון, או שמתגרשים\".\n\nמה היתה הבעיה?\n\nמבחינת הבעל: האישה פוחדת לחפש עבודה. אי אפשר להמשיך כך.\n\nמבחינת האישה: הבעל סגור, אינו מדבר על רגשותיו. אם לא ידבר, היא תתגרש ממנו.\n\nזה לקח אותי למקום ששאלתי את עצמי:\n\nמעניין כמה אנשים מגיעים למצבים של חוסר אונים מוחלט, ובכל זאת לא עושים את הדבר הנכון לשינוי? אנשים רבים מצפים שבני/בנות הזוג יבינו אותם כי יש להם חרדות ופחדים. אנשים רבים מצפים מבני/בנות הזוג שיבינו אותם בגלל שקשה להם בעבודה, שהם בדיכאון, שלא מוצאים עבודה, שיש להם כעסים, שחסר להם ביטחון, שסובלים מאובססיות למיניהן וכו'.\n\nהם נפגעים אם בן/בת הזוג לא יכול/ה לשאת את החרדות והפחדים שלהם לאורך זמן. הם מתרגמים את חוסר היכולת של בן/בת הזוג כחוסר רגישות, חוסר הבנה, חוסר הקשבה וכו'.\n\nנשאלת השאלה:\n\nאיך זה שאנשים מעדיפים לסבול, לריב עם בני/בנות הזוג ובלבד שלא יבקשו עזרה חיצונית?\n\nתשובה אחת היא: הם חושבים שהמצב שלהם טבעי. וכל מה שטבעי צריך לחיות איתו.\n\nהתשובה השניה (מתת המודע) היא: הם פוחדים מהשינוי יותר מאשר מהגירושין. אנשים רבים בטעות מתיחסים לפחדים וחרדות כטבע שני או כאופי. ולכן הם חוששים שהם לא יהיו הם ללא החרדות.\n\nאחרים חוששים שאם יוותרו על החרדות, הם עלולים להיות חשופים לפגיעות.\n\nקיימות סיבות רבות לשמירת המצב הקיים (איזור נוחות וכו').\n\nזה לא משנה מהן הסיבות. מה שמשנה הוא שהגיע הזמן שאנשים יבינו כמה הם מפסידים כשהם נמנעים מבקשת עזרה חיצונית.\n\nכיום, עם שיטות שעובדות עם תת המודע, אפשר להעלים חרדות ופחדים. אפשר לחזק בטחון עצמי, אפשר להרחיב את התודעה, לחזק את החוסן הנפשי, לפתור טראומות, לשנות את ההתיחסות לקשיים (גם אם העבודה קשה פיזית וגם אם היא קשה נפשית), לקבל את החיים בקלות, לקבל את העולם בקלות, לחיות באושר ושלווה וכו'.\n\nדוגמה נוספת מתוך התוכנית: אישה שלא יכולה לסבול את הבלגן של בעלה. היא אוהבת אותו. הוא אוהב אותה.\n\nבסופו של דבר היא החליטה לפרק את המשפחה (יש להם ילדה), ובלבד שלא תחיה עם בן אדם שלא \"מקשיב לה\" (לא מוכן לשמור על סדר).\n\nכאן אני רוצה לנצל את הבמה שניתנה לי כדי להביע את דעתי:\n\nא. לא ברור לי איך זה שהפסיכולוג שטיפל בהם לא עבד איתה על שינוי התפיסה שלה.\n\nב. אפשר היה להשאיר את המשפחה שלמה ומאושרת, אם שני בני הזוג היו עוברים תהליך לשינוי בתת המודע.\n\nג. בדיון שהיה ביניהם הבחור דיבר יפה והסביר את כאבו. לעומתו, אשתו לא הקשיבה לו, נכנסה בדבריו, טענה שהוא לא מקשיב לה וכו'. היא רצתה שיבין שסדר חשוב לה, אך מנגד, היא לא הבינה את רצונותיו של בעלה.\n\nלסיכום:\n\nאם קשה לכם, במקום להרים ידיים ולהתיאש, תעברו תהליך לשיפור הזוגיות. ואם עברתם תהליך טיפול בזוגיות, וזה לא עזר, תחפשו מישהו אחר, מישהו יותר מקצועי. מה שחשוב הוא: תשמרו על התקוה. תאמינו שקיימת האפשרות לשפר ולהתחזק. תבינו שהכל אפשרי. אם אובמה היה אומר לעצמו: 'הרבה אנשים שחורים ניסו להיבחר לנשיאות ולא הצליחו, אז אין סיכוי. זה לא יילך' - הוא לא היה נבחר. הוא נבחר אך ורק בזכות האמונה שלו שגם אם קודמיו לא הצליחו (ולא משנה כמה הם ניסו) - הוא יצליח.\n\nטיפ לשיפור התחושה (דומה לדימיון מודרך)\n\nקחו לעצמכם כמה דקות לבד.\n\nעצמו עיניים. תיזכרו בסיטואציה שמחה בחיים שלכם. תחשבו על סיטואציה ממש שמחה שהיתה לכם. מה היה שם? מה גרם לכם לשמחה? איך יצרתם את השמחה? מה ראיתם שם? מה שמעתם? איפה בגוף הרגשתם את השמחה? מה הרגשתם בשרירים? איך היתה הנשימה שלכם? תתרכזו בתחושה הזאת. תזכרו אותה.\n\nכל פעם שתרצו להרגיש טוב, תוכלו לייצר את ההרגשה הטובה הזאת שוב.\n\nבהצלחה:)\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nednamaim@gmail.com"}, {"slug": "טיפול-בעצבים-שליטה-בעצבים", "title": "טיפול בעצבים, שליטה בעצבים", "category": "כעסים", "date": "", "excerpt": "אנשים רבים מלאים בכעסים רבים. יש כאלה שכמעט כל דבר מרגיז אותם. הם מתעצבנים כמעט מכל שטות. הערות של אנשים, צורת הדיבור שלהם, הנשימה שלהם, העשיה שלהם, חוסר עשיה שלהם....", "content": "מהו הדבר שאנשים לא חושבים עליו כשהם מתעצבנים?\n\nאנשים רבים מלאים בכעסים רבים. יש כאלה שכמעט כל דבר מרגיז אותם. הם מתעצבנים כמעט על כל שטות: על הערות של אנשים, צורת הדיבור שלהם, הנשימה שלהם, העשיה שלהם, חוסר עשיה שלהם, המראה שלהם, התזוזה שלהם, האופן בו הם הולכים, האופן בו הם מסדרים את השיער, האופן בו הם אוכלים או לועסים את האוכל, הרעש שהלעיסה יוצרת, המשקל שלהם, הקצב בו הם מדברים, הקצב בו הם חושבים, הקצב בו הם פועלים וכו'. כל הדברים האלה או חלק מהם יכולים לגרום להם לעצבים.\n\nבנוסף, אנשים רבים כועסים על המדינה, על המורים, על אנשי מכירות, על מרכזי קניות ומה לא.\n\nעל אנשים כאלה להבין שככל שהם כועסים יותר, או מתרגזים, או מתעצבנים, כך הבעיה שלהם גדולה יותר.\n\nהבעיה שלהם אינה קשורה באמת לסובבים אותם או לסביבה שלהם, אלא היא קשורה באופן ישיר למה שמתרחש בתוכם בפנים עמוק עמוק.\n\nאנשים רבים התרגלו לברוח מעצמם, לברוח מלהרגיש, לברוח מלהודות ברגשות למיניהם, לברוח מלהכנס פנימה לחדרי החדרים של עצמם ולבדוק היכן הם טעו. הם כל כך רגילים לברוח, עד כדי כך שהם לא מוכנים לחשוב שיכול להיות שהם הטועים. זה עלול למוטט את כל עולמם, ולזה הם עדיין לא מוכנים. הם אינם מעוניינים להתמודד עם האמת, כי הם כבר מנחשים שזה יכאב. ובכך הם בורחים מכאב. ככל שהכעס גדול יותר, כך הבריחה גדולה יותר.\n\nאם התחברתם לנאמר לעי\"ל, מומלץ שתקחו לעצמכם כל יום כמה דקות כדי להרהר ולחשוב.\n\nשלב ראשון:\n\nתשאלו את עצמכם: \"איך זה יכול להיות שתמיד אחרים טועים ואחרים לא בסדר, ורק אני בסדר?\"\n\nכי, תחשבו על זה: אולי בכל זאת הטעות היא אצלכם עמוק כל כך בפנים שאתם לא מוכנים להתמודד?\n\nהרי לא יכול להיות שכל כך הרבה אנשים לא צודקים, או טיפשים, או סתומים, או לא קולטים, או לא פיירים וכו'.\n\nהרבה יותר הגיוני שאתם לא מצאתם עדיין את הדרך להבנת האחר, או הבנת המוח של האחר, כי כל\n\nאחד עושה תהליכים בראש שלו, אשר מביאים לו את התוצאה שהוא מקבל. גם אתם עושים תהליכים בראש שאתם מקבלים את התוצאה שקיבלתם.\n\nאם כן, ההבדל הוא במה שכל אחד עושה בראש. וזה לא אומר שהוא סתום, אלא הוא עושה תהליכים שונים בראש.\n\nומה שכל אחד עושה בראש הוא תוצאה של האמונות שלו על עצמו ועל העולם, הערכים שלו, דפוסי חשיבה שלו, זכרונות שלו, העדפות שלו, ההתמקדות שלו וכו'.\n\nלכן, שכל אחד יגיד לעצמו: \"מי אני שאשפוט אחרים?\"\n\nשלב שני:\n\nהשלב השני מקדם אתכם לשאלה החשובה יותר: \"אם התובנה היא שכנראה אני עושה משהו לא\n\nאפקטיבי בראש, מהו הדבר? מהו הדבר שאני חוזר עליו שוב ושוב, ובכך תוקע את עצמי באותו מקום,\n\nולא מתקדם למשהו אמיתי?\"\n\n\"מהו הדבר שגורם לי כל פעם מחדש לשפוט אנשים?\" (תהיו אמיתיים עם עצמכם).\n\nשלב שלישי:\n\nתשאלו את עצמכם: האם אני מוכן להודות בדברים שעד כה לא הודתי בהם?\n\nכי, בעצם, אם אני חושב שאחרים טיפשים, כנראה אני חושב שאני טיפש.\n\nולכן, אני מוותר מרגע זה והלאה על שפיטת אחרים (כולל את: \"הוא חוצפן\", \"הם לא מבינים אותי. נמאס לי. זה מתסכל\").\n\nוזו תובנה חשובה מאוד. תובנה זו תעזור מאוד להתקדם לעבר השינוי.\n\nהתובנה כוללת הבנה שחיזוק ההערכה העצמית, הדימוי העצמי וקבלת השונה יכולים לעזור לכם לייצר שינוי משמעותי, ובכך להגיע לשליטה בכעסים, שליטה ברגשות ובהתנהגויות.\n\nכיצד תחזקו את ההערכה העצמית שלכם?\n\nטיפים לשיפור ההערכה העצמית\n\n1. תציינו את ההצלחות שלכם. כל יום ויום, לפני שאתם הולכים לישון, תזכירו לעצמכם את ההצלחות שהיו לכם באותו יום. חשוב להדגיש שהעובדה שקמתם בבוקר היא הצלחה. זה לא מובן מאליו בכלל. הרבה אנשים אינם יכולים לקום בבוקר.\n\nמי שאומר לעצמו: \"זו לא הצלחה לקום בבוקר\" הוא טועה וגם הורס את ההתקדמות שלו.\n\nכל פעולה היא הצלחה! יש הרבה אנשים שיש להם שתי רגליים ושתי ידיים, אבל הם לא קמים (מתוך קשיים רגשיים למיניהם).\n\nשבו עם עצמכם כל יום ותנשמו פנימה במודעות מלאה. שימו לב עד להיכן מגיעה הנשימה שלכם. חשוב מאוד שתעצמו עיניים בזמן הנשימות. זה יחבר אתכם לעצמכם, לאני שלכם.\n\n2. שבו עם עצמכם כל יום ותנשמו פנימה במודעות מלאה. שימו לב עד להיכן מגיעה הנשימה שלכם. חשוב מאוד שתעצמו עיניים בזמן הנשימות. זה יחבר אתכם לעצמכם, לאני שלכם.\n\n3. תבינו שאנשים אחרים, בדיוק כמוכם, רוצים שיהיה טוב, רוצים הערכה ואהבה, רוצים הבנה, רוצים יחס טוב. אנשים לא קמים בבוקר כדי לגרום לכם לכעסים. כל מה שהם רוצים זה \"להגיע הביתה בשלום\". לכן, תרגיעו.\n\n4. תאמינו בעצמכם. תבינו שאתם בסדר (למרות הכעסים). ותפתחו דף חדש. אחרי שתחזרו הרבה על ההתנהגות החדשה, זה יהפוך לאוטומט (בשיטת NLP יש טכניקה להפוך את זה לאוטומט תוך 5 דקות. את זה לומדים בקורס NLP ובסדנאות לשליטה בכעסים וביטחון עצמי).\n\nעדנה מימון\n\nמנחה סדנאות, ומאמנת אישית לחיזוק, שיפור ושידרוג הזוגיות, ניהול ושליטה בכעסים וביטחון עצמי. מורה מוסמכת ל NLP מטעם ממציא ה NLP.\n\nNLP Trainer, NLP Master Practitioner, NLP Master Coach,\n\nמאסטר בטכניקת תרפיית קו הזמן (שיטה גאונית ומהירה להעלמת רגשות שליליים, כולל פחדים, חרדות, טראומות, פוביות וכו', תוך זמן קצר מאוד)\n\n050-7378535\n\nednamaim@gmail.com\n\nלפרטים: השאירו פרטיכם כאן ונציגינו יחזרו אליכם\n\nלתאריכי סדנא לשליטה בכעסים\n\nלמעוניינים בתהליך פרטני/אישי גם השאירו פרטיכם בקישור. נציגינו יחזרו אליכם"}, {"slug": "טיפול-זוגי-טעויות-נפוצות", "title": "טיפול זוגי - טעויות נפוצות", "category": "זוגיות", "date": "", "excerpt": "אחת הטעויות הנפוצות בזוגיותבעיות בזוגיות נוצרות מסיבות רבות. אחת הנפוצות ביניהן היא:פנקס חשבונאות. עוד על אחת הטעויות הנפוצות בזוגיות", "content": "אחת הטעויות הנפוצות בזוגיות\n\nבעיות בזוגיות נוצרות מסיבות רבות. אחת הנפוצות ביניהן היא:\n\nפנקס חשבונאות.\n\nכן. זהו פנקס שחור ותמיד במצב זמין, כי הוא במוח (במיינד). יש לו מקום של כבוד במיינד, והוא מופיע בכל רגע שצריכים אותו. בקרב חלק קטן מאוד מבני זוג/בנות זוג, לעתים הוא מסרב להופיע בקלות, ואז נאמר המשפט: \"חבל שלא רשמתי את זה. היתה יכולה להיות לי הוכחה נהדרת עכשיו\". יש גם בודדים ממש יחידי סגולה שאכן רושמים את זה על דף.\n\nהבעיה בפנקס הזה היא ההתמקדות שלנו. פנקס כזה, שזמין לנו כל כך, מראה לנו על מה אנחנו חושבים, ומהו הפוקוס שלנו.\n\nלדוגמה, אם בן הזוג לא שטף כלים כמה פעמים למרות שזה תפקידו בת הזוג זוכרת (באופן אוטומטי זה נרשם בפנקס השחור), ואז, בזמן ויכוח היא שולפת את ההוכחה שלה, את הקלף המנצח שלה.\n\nדוגמה נוספת: אם בת הזוג דיברה בטלפון כמה פעמים עם אמא שלה, ובאותו שבוע, או חודש לא הספיקה לעשות כמה משימות, וגם חשה עייפות רבה (רחמנא ליצלן), בזמן ויכוח, בן הזוג ישלוף דוקא את השיחות עם האמא ויציין כי הסיבה לחוסר זמן ולעייפות שלה היא השיחות הרבות והארוכות (על פי פרשנותו כמובן) עם אימה.\n\nפנקס שחור הוא לא סתם שחור. הוא משחיר את התמונה שנמצאת לנגד עיניו של האדם, ונוצר מצב שכאשר הוא חושב על הבן אדם שמולו, כל מה שהוא רואה זה שחור. והשחור הזה יכול לגדול מיום ליום. לכן, אין פלא שנוצרת פגיעה ברגשות / בזוגיות.\n\nבמסגרת תפקידי כמטפלת זוגית אני שומעת הרבה דוגמאות כאלה. המסקנה היא: קל מאוד למלא את הפנקס השחור. השאלה החשובה היא:\n\nבשביל מה?\n\nבשביל לנצח בויכוח? בשביל להראות שאנחנו צודקים? בשביל לגרום לפרטנר להשתנות? בשביל להראות כמה אנחנו מסכנים ובסדר, והשני לא בסדר?\n\nואז מה?\n\nאז נהיינו מסכנים וצודקים. מה יצא לנו מזה?\n\nמה שיצא מזה זה: בן זוג / בת זוג שמרגישים רע, מרגישים מובסים, מרגישים שלא מקשיבים להם ושלא מבינים אותם. מרגישים שאולי הזוגיות הזאת היא לא מה שחשבנו, לא מה שציפינו.\n\nבקיצור: הפנקס השחור פוגע בזוגיות.\n\nלכן, בזוגיות מומלץ לזרוק את הפנקס השחור לפח. במקומו לפתוח פנקס אחר, צבעוני, עם אייקונים משמחים, ולרשום את כל הדברים הטובים שבן הזוג/בת הזוג עושים.\n\nאתם מדמיינים את הדברים הטובים שזה יעשה לזוגיות שלכם?\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, לטיפול ברגשות שליליים וטיפול בטראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי.\n\nמנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות. מטפלת זוגית ומשפחתית\n\n050-7378535\n\nednamaim@gmail.com"}, {"slug": "יתרונות-האימון-הקבוצתי", "title": "יתרונות האימון הקבוצתי", "category": "אימון אישי", "date": "", "excerpt": "אין ספק שאימון אישי הוא כלי עוצמתי  מאוד ובעל יתרונות רבים. אך, נדמה שיתרונותיו של האימון הקבוצתי אינם באים לידי ביטוי במידה מספקת באמצעי המדיה השונים. מסתבר, שהאימון הקבוצתי הוא כלי עוצמתי לא פחות מה", "content": "אין ספק שאימון אישי הוא כלי עוצמתי מאוד, ובעל יתרונות רבים. אך נדמה שיתרונותיו של האימון הקבוצתי אינם באים לידי ביטוי במידה מספקת באמצעי המדיה השונים.\n\nמסתבר שהאימון הקבוצתי הוא כלי חזק מאוד, ובעל השפעה מרחיקת לכת, לא פחות מהאימון האישי. לעתים, לאימון הקבוצתי יש יתרונות העולים על האימון האישי.\n\nבמהלך האימון האישי, המשתתפים חווים את ההתפתחות האישית והצמיחה האישית בחברותא. הם גם עדים לשינויים ולהתפתחות האישית של חבריהם לקבוצה. תהליכים אלה מדרבנים אותם לייצר יותר שינויים אישיים רבים יותר, מהירים יותר וומהנים יותר. חוויות אלה נשארות בזיכרון לאורך זמן רב יותר.\n\nכמו כן, הדינמיקה בתהליך האימון הקבוצתי יוצרת פתיחות רבה בין המשתתפים, ועוזרת להשיל את הקליפות בקלות יותר.\n\nכל המוזכר לעי\"ל יוצר מוטיבציה רבה להבנת עצמנו בעומקים שלא חשבנו עליהם קודם.\n\nלעתים עומקים אלה באים לידי ביטוי בהתנגדויות אוטומטיות שיש לנו מסיבות רבות, ושמות לנו מראה על מה כדאי לנו לעבוד.\n\nכמובן שכל עבודה אישית, קטנה כגדולה, היא לא מובנת מאליה. היא משמעותית, ומשפיעה לטובה על הרגשות שלנו, על ההתנהגויות שלנו, על התקשורת שלנו עם עצמנו ועל התקשורת שלנו עם אחרים.\n\nוזה עוזר לנו לחיות עם עצמנו ועם אחרים בשלוה, בשלום פנימי, בסיפוק ובאושר.\n\nיתרונות אלה מתווספים ליתרון נוסף שהוא יצירת חברויות חדשות והגדלת מעגל ההכרויות בתחומים שונים, כגון קשרים חברתיים ועסקיים.\n\nלדוגמא, אחת המשתתפות חיפשה דירה באזור מסוים. משתתפת אחרת הכירה מישהו באותו אזור שרצה למכור את דירתו. החיבור ביניהם היה מיידי.\n\nדוגמא נוספת: אחת המשתתפות היתה גרושה. משתתפת אחרת סיפרה שהיא מכירה מישהו פנוי ושהיא תשמח להכיר ביניהם.\n\nמסקנה: לקבוצה יש הרבה כוח, והרבה יתרונות.\n\nתוכלו לבחור להרשם לסדנאות העצמה והתפתחות שאנו מציעים: סדנאות שליטה בכעסים והתפרצויות זעם,\n\nסדנא לביטחון עצמי\n\nסדנא לשיפור הזוגיות,\n\nקורס NLP Practitioner\n\nכל זה, בנוסף לאימון אישי עוצמתי (למי שמעדיף תהליך אישי/פרטני)"}, {"slug": "יתרונות-הסדנא", "title": "יתרונות הסדנה", "category": "כללי", "date": "", "excerpt": "הנחיית סדנאות, הנחיית קבוצות, הינה שיטה אפקטיבית ביותר להעברת מסרים, להבנה עמוקה של המסרים ולהפנמתם. מדוע ?", "content": "מכיוון שבזמן הסדנא אנו עוברים תהליכים משמעותיים, אשר עוזרים לנו להכיר טוב יותר את עצמנו, את מחשבותינו ואת רצונותינו האמיתיים. אלה מאוויים שקיימים אצלנו, אך אנו נוטים לבטל אותם בגלל התחושה ש\"זה לא מגיע לי\", או \"זה לא אני\", או \"זה לא חשוב כרגע\", או \"הרי גם כך אין סיכוי\", \"אין לי זמן עכשיו\", \"טוב לי ככה\" ועוד מחשבות בסגנון זה.\n\nאם אנו רוצים להרגיש שהפעם \"נפל האסימון\", והנה אנו חשים את התחושה שזז אצלנו משהו בחשיבה - שלעתים מקובעת מאוד- סדנאות יכולות להיות התשובה המתאימה ביותר.\n\nאל לנו לשכוח שבסדנא אנו מגלים שגם אחרים חושבים כמונו. שזו איננה בושה להיות, או להרגיש, את מה שאנו חשים. האינטראקציה עם אנשים מסייעת בתובנות כגון:\n\nאיפה אני כרגע ביחס לאחרים?\n\nהאם זה נורמלי?\n\nהאם אני רוצה לשנות פה משהו?\n\nהאם בכלל כדאי לי לשנות?\n\nמה נותן לי השינוי?\n\nהאם זה יעשה אותי לאדם עם יותר בטחון עצמי?\n\nעם יותר מחויבות כלפי עצמי?\n\nהאם זה יעשה אותי לבן אדם יותר מאושר?\n\nהאם זה ישנה את יחסי כלפי אחרים?\n\nהאם זה ישנה את יחסם של אחרים כלפי? ואן כן - באיזה אופן: חיובי או שלילי?\n\nאנו פתאום מגלים שמותר לנו לחלום - ואף להגשים את אותו חלום.\n\nכעקרון: ככל שמשתתפים ביותר סדנאות, השינוי שנוצר גדול יותר.\n\nומה לגבי אירגונים?\n\nיותר ויותר אירגונים רואים בסדנאות מנוף להעצמת האירגון ביחד עם העצמת העובד. כשלעובד טוב יותר, יש לו הספק גדול יותר בעבודה. הוא מלא יותר במרץ, ומזדהה יותר עם האירגון. כתוצאה מכך, נמנעים קונפליקטים בין העובד לבין האירגון בו הוא עובד, ובין העובד לקולגות שלו.\n\nמצב זה שבו העובד והאירגון מרוצים (win-win) הוא המצב האידאלי, שאליו שואפים אירגונים רציניים.\n\nהסדנאות כוללות הפעלות מהנות ביחד עם רכישת מיומנויות.\n\nניתן להצטרף ל סדנאות העצמה בנושאים הבאים:\n\nסדנה לניהול כעסים / טיפול בכעסים,\n\nסדנה להתמודדות עם שינוי,\n\nסדנה לשיפור הזוגיות: התדר הזוגי\n\nסדנה לשיפור הביטחון העצמי\n\nסדנה לשיפור התקשורת הבינאישית\n\nזכרו\n\nלפעמים שינוי קטן מהווה צעד מכריע לקראת שינוי גדול,\n\nלכן מומלץ לא להתייאש, להמשיך לחלום ולהתמלא באמביציות.\n\nהשינוי בוא יבוא!\n\nתחשבו על כל האנשים הגדולים, אשר הגיעו רחוק. ללא אמביציות\n\nהם לא היו מגיעים לאן שהגיעו.\n\nאם אתם מרגישים:\n\nשאתם רוצים זוגיות בריאה, עם שיתוף, אמון, הבנה, אהבה ועוד\n\nשאתם רוצים להקל על עצמכם\n\nשאתם רוצים להרגיש רוגע, שלוה, שמחה, סיפוק, שלמות, חופש ועוד\n\nשאתם רוצים שינוי\n\nשאתם רוצים להגשים את שאיפותיכם\n\nשאתם רוצים לחזק את הבטחון העצמי, את ההערכה העצמית ואת הדימוי העצמי\n\nשאתם רוצים אושר ושפע\n\nשאתם רוצים סוף סוף לחיות באמת.\n\nהשאירו פרטיכם בטופס למטה ותשנו את חייכם לטובה.\n\nהסדנאות מבוססות על ידע מתחום ה-NLP וטכניקות קו הזמן, לשינוי אמיתי ועוצמתי בעזרת תת המודע. כי רק בעזרת תת המודע ניתן ליצור שינוי אמיתי המחזיק לאורך זמן.\n\nעדנה מימון\n\nטריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאמנת אישית להעלמת רגשות שליליים והעלמת טראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות, מורה מוסמכת ל NLP\n\n050-7378535"}, {"slug": "כוחו-ועוצמתו-של-תת-המודע", "title": "כוחו ועוצמתו של תת המודע", "category": "תת מודע", "date": "", "excerpt": "אנשים רבים מחזיקים בדעות מוטעות לגבי תת המודע. חלק חושבים שזה משהו מפחיד. לעומתם, חלק אחר אומרים: ", "content": "כמה חידודים בנוגע לתת המודע\n\nאנשים רבים מחזיקים בדעות מוטעות לגבי תת המודע. חלק חושבים שזה משהו מפחיד. לעומתם, חלק אחר אומרים: \"טוב. שמעתי. מה זה מעניין אותי תת מודע, לא תת מודע. אני מחליט מה לעשות ומה לא לעשות בחיים שלי. ארצה - אעשה. לא ארצה - לא אעשה....זה החיים שלי ואני אחליט!\"\n\nואני שואלת: באמת? תרצה - תעשה, לא תרצה - לא תעשה? בוא נבדוק....\n\nלאחר כשבוע פגשתי את אחד הבחורים שאמרו לי את המשפט הזה ושאלתיו:\n\n\"מהי המטרה שלך?\"\n\n\"הייתי רוצה להיות עשיר, להיות בריא יותר, להיות רגוע, כי אני רוב הזמן עצבני. לא יזיק לי לשנות את הקול הפנימי שמציק לי הרבה (הוא פטפטן כבד-הקול הזה), וגם למחוק את הסרטים המפחידים שיש לי בראש.\"\n\n\"נהדר,\" עניתי. \"תעשה את זה, לְמה או למי אתה מחכה?\"\n\n\"ניסיתי. אני מנסה כל הזמן. זה לא הולך. יש סיבות שמונעות ממני. זה לא תלוי בי.\"\n\n\"אילו סיבות? כמו מה?\" שאלתי כמיתממת.\n\n\"לא יודע. לא משנה. גם כך זה אבוד. את לא תוכלי לעזור לי\"\n\n\"אתה יודע, תוכל להשיג את כל מה שאתה רוצה, ואפילו יותר - אם תשתמש בתת המודע שלך בצורה נכונה.\"\n\n\" אולי תפסיקי לבלבל לי במוח עם תת המודע שלך,\" ענה לי בקצת כעס. \"תת מודע זה לא באר משאלות. בשביל לקבל את מה שאני רוצה, צריך לעבוד קשה, צריך הרבה שנים, וגם אז, רק בעלי המזל ישיגו חלק ממה שהם רוצים. אי אפשר שגם אהיה עשיר, גם בריא, גם רגוע וגם הקול הפנימי שלי ישתנה לטובה וגם הסרטים שיש לי בראש יהיו נורמליים. יש גבול לכל דבר. אנחנו לא בסרט מדע בידיוני. אנחנו בני אדם. נולדנו עם דפקטים רבים. מה לעשות, החיים קשים. יש דברים שלא נולדנו בשבילם. חוץ מזה, זה מה שאני ומי שאני, אי אפשר לשנות אותי. זה חומר כימי שנמצא במוח. זה מדעי. תת מודע או לא תת מודע - כל כך הרבה מטפלים ופסיכולוגים ופסיכיאטרים גדולים ניסו לעזור לי ולא הצליחו - מה גורם לך לחשוב שתת המודע יצליח?\"\n\nבשלב זה החלטתי שלא לענות. הבחור מלא באמונות מגבילות. אנצל את הבמה שניתנה לי ואמנה כל אמונה מגבילה, אחת לאחת:\n\n1.\"תת מודע זה לא באר משאלות\" - בואו נגיד שמי שיודע לתכנת אותו נכון - בשבילו תת המודע יהיה באר משאלות.\n\n2. \"בשביל לקבל את מה שאני רוצה, צריך לעבוד קשה, צריך הרבה שנים\" - כבר לא. זה שייך לעבר. היום אפשר להשיג רוגע, ביטחון, הערכה עצמית, אמונה עצמית, לפתור טראומות ופוביות, לפתור פחדים, ולשנות כל הלך רוח שרוצים בזמן קצר, ו...כן. דרך תת המודע. כל אחד יכול.\n\n3. \"רק בעלי המזל ישיגו..\" - היום ידוע שמזל מייצרים. כאשר עושים את הדברים הנכונים, המזל מגיע. אנשים רבים חשבו שאין להם מזל. אך, כאשר עברו תהליכי שינוי, לפתע המזל התחיל להאיר להם פנים. מעניין....\n\n4. \"אי אפשר שגם אהיה עשיר, גם בריא, גם רגוע, גם הקול הפנימי שלי ישתנה לטובה, וגם הסרטים שיש לי בראש יהיו נורמליים.\" - יש לי חדשות בשבילך: כל אלה אפשריים. ו...כן: בעזרת תת המודע.\n\n5. \"נולדנו עם דפקטים רבים\" - אנחנו נולדים דף חלק. הדף הזה מתלכלך במהלך החיים כתוצאה מכל מיני ארועים וחוויות שאנחנו עוברים. החוויות האלה מתאחסנות בתת המודע - בדיוק כמו קבצים במחשב - וזה נשאר שם. והחדשות הטובות הן שאפשר לשנות את זה בקלות יותר דרך תת המודע.\n\n6. \"החיים קשים\" (\"העולם קשה\") - רק למי שחושב כך. החיים הם אותם חיים. העולם הוא אותו עולם לכולם. זה האנשים שמפרשים את החיים ואת העולם באופנים שונים. זה כמו פרק זמן, נגיד: שעה. לאחד שעה יכולה להיות זמן ארוך מאוד, ולאחר היא יכולה להיות קצרה מדי.\n\n7. \"זה חומר כימי שנמצא במוח. זה מדעי.\" - זה אכן מדעי, זה אכן חומר כימי ואכן נמצא במוח. מה שאתה עדיין לא יודע הוא שהחומר הכימי שנמצא במוח נוצר כתוצאה מן המחשבות שלך. מחשבות שליליות יוצרות חומרים כימיים במוח שהם כמו רעל, והם גורמים גם למחלות. מחשבות חיוביות יוצרות במוח חומרים כימיים שהם מרפא למוח, ויוצרים תחושה טובה של היי (כמו אחרי ספורט, אחרי סקס וכו'). ו...כן. זה גם מדעי.\n\n8. \"אי אפשר לשנות אותי\" - תחשוב שוב... כי היום כל אחד יכול להשתנות - אם הוא רוצה... כמובן בעזרת כוחו עוצמתו של תת המודע.\n\nלסיכום:\n\nלתת המודע יש עוצמות אדירות. (במאמר \"מהי שיטת NLP?\" מניתי הרבה אפשרויות) הסיבה שאנשים רבים לא מצליחים לשנות דפוסי חשיבה ודפוסי התנהגות במשך שנים, היא שהם עושים את זה במודע. אפשר לדמות את תת המודע למכונית, ואת המודע לנהג. לא משנה כמה הנהג יגיד לאוטו \"תפנה שמאלה\", האוטו לא יפנה שמאלה אם הנהג מחזיק את ההגה ישר. ברגע שאנשים יבינו שאם הם יעשו את השינוי בתת המודע, השינוי יהיה קל, מהיר ומהנה.\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nednamaim@gmail.com\n\nלחץ כאן כדי לקרוא סידרה של מאמרים על תפקידיו של תת המודע\n\nתוכלו לקרוא מאמר נוסף על תת המודע באתר דעתון, שנכתב על ידי עדנה מימון. כותרת המאמר: כמה עובדות על NLP ותת המודע"}, {"slug": "מאמרים-איך-לשפר-את-ההערכה-העצמית", "title": "איך לשפר את ההערכה העצמית", "category": "ביטחון עצמי", "date": "", "excerpt": "בני האדם נולדים עם הערכה עצמית. אך, למרבה הפליאה, במהלך חייהם הם מורידים מערכם, וזה גורם להם לפעול מתוך חוסר או נחיתות.כאשר בן אדם לא מעריך את עצמו, הוא מתנהג בהתאם לתחושת החוסר או הנחיתות, וזה יכול ל", "content": "תחילה נבין למה אנשים מורידים מהערך העצמי שלהם.\n\nאנשים מושפעים מאוד מחוויות שהם עוברים, ממראות שהם רואים, ומדיבורים ומקולות שהם שומעים.\n\nכאשר בן אדם, משחר ילדותו, שומע מילים חיוביות, זה עושה לו טוב והוא מרגיש טוב עם עצמו. זה מחזק אותו. מנגד, כאשר בן אדם שומע מילים שליליות, מילים של ביקורת, מילים של: \"למה עשית.....?\" או \"למה לא עשית......?\" או \"למה אתה כל הזמן עושה כך וכך?\" זה גורם לו למסקנה ולתחושה שהוא לא בסדר.\n\nומכיוון שסיטואציות כאלה די חוזרות על עצמן, המסקנה והתחושה השלילית רק מתחזקות ומתעצמות. לאחר כמה שנים, זה מושרש כל כך חזק, שקשה לאותו בן אדם לחשוב שהוא לא מה שהוא חושב על עצמו. ב: NLP קוראים לזה תוכנה. זה הופך לתוכנה במוח, וקשה מאוד לשכנע בן אדם כזה שהוא כן בסדר.\n\nגם אם יגידו לו: \"אתה בסדר כמו שאתה\", רוב הסיכויים שהוא לא יאמין לזה, מכיוון שהתוכנה כבר הותקנה, וכדי לשנות תוכנה כזאת, צריך לדעת איך עושים את זה.\n\nאם כן, כיצד משפרים הערכה עצמית?\n\nהדרך הקלה והמהירה ביותר לשפר את ההערכה העצמית היא לעבור תהליך אימון אישי אצל מנחה NLP מוסמך ולשלב טכניקות קו הזמן.\n\nיחד עם זאת, לא כל אחד מוכן לעשות צעד כזה, לכן אני משתפת אותכם ב 5 שלבים לשיפור ההערכה העצמית שלכם ושל הקרובים לכם:\n\n1. הפסיקו עם הביקורת העצמית!!!!\n\nמי שמבקר את עצמו, שלא יתפלא שההערכה העצמית שלו נפגעת. לא משנה מה עשיתם ואיך עשיתם, לא משנה אם קילקלתם משהו, או עשיתם משהו לא מושלם, תבינו שאתם עדיין בסדר ואתם שווים. ותבינו: אתם שווים בכל מצב, ללא קשר למעשה שלכם!\n\n2. הפסיקו לתת ביקורת לאחרים!!!!\n\nגם אם אתם עושים זאת מתוך רצון טוב, מתוך כוונה טובה, אפילו מתוך רצון לעזור לאחרים ש\"בפעם הבאה הם ידעו מה לעשות ואיך לעשות\" - אל תעשו את זה. זה מתקבל כביקורת. גם ביקורת בונה מתקבלת כביקורת. לכן, הכלל יהיה כזה: אם ביקשו מכם לתת ביקורת, תבקרו, אבל בעדינות. אם לא ביקשו, אנא מכם, אל תבקרו. כי כאשר אתם מבקרים אחרים, התוכנה של ביקורת יכולה לחזור אליכם או להתחזק. בשביל מה לכם?\n\n3. תחמיאו לעצמכם בסתר, כשאף אחד לא רואה, תחמיאו לעצמכם הרבה. אפילו תכתבו את זה על דף. כתיבה על דף מקצרת את התהליך. היא מעצימה אותו.ו וזה לא אומר שאתם משוויצים., כי אף אחד לא יודע על זה. המלצתי: תעופו על עצמכם:)\n\n4. על כל פעולה שלא צלחה, תחשבו איזה דבר טוב בכל זאת יצא מזה. פעם מישהו אמר לי שאפילו כשיש תקר בגלגל, נשאר אויר בחלק העליון. וזה אומר שכדאי לראות את החצי המלא של הכוס, כי את החצי הריק כבר יש. אני הרבה פעמים ממליצה לעשות לימונדה מהלימון, ואז זה מביא לרווחה כלשהי, כי הלימון כבר קיים, לא ככה?\n\n5. תעשו מחברת הצלחות. תכתבו את הצלחותיכם כל יום במשך חצי שנה. דבר זה יגרום לתת המודע שלכם להתיחס לדברים באופן חיובי, וזה גם יחזק את ההערכה העצמית שלכם.\n\nואסיים במשהו שחברה שלי אור סיפרה לי . אור ובני משפחתה היו בחתונה לפני כחודש. כשחזרו, גילו שהבית שלהם היה מוצף במים. מסתבר שהיה פיצוץ באחד הצינורות. אור מיד סגרה את שעון המים והיא ובני ביתה התחילו בגריפת המים. לאחר שסיימו, הם כולם היו בהיי גבוה.\n\nנשמע הזוי? מה פתאום בהיי גבוה אם חזרו מחתונה וגילו בית מוצף במים?\n\nובכן, לפני שהתחילו לגרוף מים הם החליפו את בגדי החתונה לבגדי ים, נשארו יחפים והתחילו להשפריץ מים אחד על השני בכיף, ולצחוק ולהשתולל בשמחה. הם נהנו מאוד מהביחד. כפי שאור העידה: \"זמן רב לא בילינו כל כך יפה. אפילו בחתונה לא נהננו כמו בזמן גריפת המים\". ובנוסף לזה, הם מצאו כמה פריטים ש\"הלכו לאיבוד לפני זמן רב\", הם ניצלו את ההזדמנות לניקוי יסודי משותף, הם זרקו חפצים מיותרים, הם הצטלמו ל\"סלפי\" ושיתפו חברים בפייסבוק, הם שמו מוזיקה שאהבו ורקדו על המים ועוד ועוד.\n\nתגידו לי: לא עדיף ככה?\n\nוכשבן אדם מגיע לרמה גבוהה של ראיית החיובי בכל סיטואציה, של חשיבה חיובית אוטומטית, וכשהוא מפסיק לחלוטין את הביקורת, הוא מגיע למעין שלווה פנימית כזאת, למין שלמות עצמית שרק הוא יכול להבין אותה, וזה כמובן מחזק את ההערכה העצמית שלו ואת הדימוי העצמי שלו.\n\nעדנה מיימון\n\nמורה מוסמכת ל NLP, מנחה סדנאות לניהול כעסים, לשיפור הביטחון העצמי וההערכה העצמית, ושיפור הזוגיות. וגם באופן אישי/פרטני\n\nאיך לשפר את ההערכה העצמית, כיצד לשפר את ההערכה העצמית, שיפור ההערכה העצמית, חיזוק ההערכה העצמית"}, {"slug": "מאמרים-איך-לשפר-ביטחון-עצמי", "title": "איך לשפר ביטחון עצמי", "category": "ביטחון עצמי", "date": "", "excerpt": "אתה רוצה להתקדם, רוצה לעשות, רוצה חיים טובים, רוצה להגשים את עצמך, רוצה להיות עם חברים, לצחוק, להתבדח, להשתולל, להשתטות, להשתעשע, לעשות מה שבא לך, להגיד את מה שיש לך להגיד, להביע את עצמך ואת דעתך, כי ...", "content": "אתה רוצה להתקדם, רוצה לעשות, רוצה חיים טובים, רוצה להגשים את עצמך, רוצה להיות עם חברים, לצחוק, להתבדח, להשתולל, להשתטות, להשתעשע, לעשות מה שבא לך, להגיד את מה שיש לך להגיד, להביע את עצמך ואת דעתך, כי יש לך דעה משלך, להתחיל עם בחורה, כי גם לך מגיע..... אך משהו עוצר אותך מלעשות זאת!\n\n\"מה זה הדבר הזה?\" אתה שואל את עצמך. \"למה זה קורה לי?\" \"למה אני לא יכול להיות כמו האחרים?\" \"למה אני נשאר מאחור, מוותר לעצמי, מתכווץ, נמנע, מתרץ תירוצים כאילו לא בא לי, כאילו לא מעניין אותי, כאילו לא בשבילי?\"\n\n\"למה?\"\n\n\"מה המיוחד בי?\" \"מאיפה בא לי הדפקט הזה?\" \"למה אני כזה כישלון?\" \"למה אני נשאר מאחור?\" \"למה אין לי ביטחון עצמי?\"\n\nאלה הן חלק ממחשבות של חוויית חוסר ביטחון. הקול הפנימי הביקורתי, אשר כל פעם מחדש מרתיע אותנו מלעשות, או ליזום, או להגיד, או לקדם או לבלוט וכו'. הקול הפנימי, אשר מתריע בנו וקורא לנו להמנע, כי זה עלול להכשל, כי מה אם זה לא יצליח, מה אם זו טעות, מה אם יצחקו עלי, מה אם יגידו לי לא, מה אם אני אהפוך לבדיחה, מה אם יביישו אותי ברבים, וכו'.\n\nקול זוועתי.\n\nכתוצאה מכך, מגיע התיסכול וחוסר האונים, ולאחר מכן, הרמת ידיים, כניעות וקבלת גזר הדין, אשר מגיעה בצורה של: \"זה האופי שלי.\" או: \"ככה נולדתי.\" או: \"זה תורשתי. זה משפחתי. זה בגנים. גם אבא/אמא שלי עם אותו אופי.\"\n\nלא נעים. לא מקדם. לא תורם לאנושות. לא משפר את ההרגשה.\n\nובכן, החדשות הטובות הן שאפשר לשנות הכל!\n\nאפשר להשיג הכל ולהגיע לכל מה שרוצים. התנאים הם: רצון ללמוד, אמונה שזה אפשרי לנו, והרבה נחישות.\n\nברגע שאנחנו מבינים שהכל אפשרי, ובוחרים באמונה הזאת, אכן הכל יהיה אפשרי.\n\nאז מה בכל זאת מונע מכל כך הרבה אנשים לבחור בזה?\n\nהעבר!\n\nכן. העבר. העבר כבר עבר ממזמן, אך בתת המודע נשארו שאריות ממנו. השאריות האלה באות בצורה של אוטומים כגון אלה שהוזכרו בפתיח של מאמר זה. והשאריות האלה יוצרות תחושה פיקטיבית שכביכול אנחנו לא יכולים לעשות משהו, או אנחנו לא מספיק שווים כדי לעשות משהו. אך המציאות איננה כזאת, כי כולנו יכולים, וכולנו מסוגלים.\n\nבעברנו חווינו כישלונות, חווינו תסכולים, חווינו פחדים, חווינו חוסר אונים, חווינו בושה, חווינו אשמה ועוד תחושות לא נעימות. חלקן אפילו לא באמת קרו, אלא אנחנו פירשנו אותן ככאלה.\n\nגם אם בחרנו בפרשנות לא אפקטיבית, עדיין הפרשנות נתקעה בתת המודע, וכל פעם שחוזרים לסיטואציה באותו סגנון, עולה הפרשנות הישנה.\n\nאפשרויות חדשות המייצרות ביטחון עצמי\n\nעל מנת לשנות את האוטומטים הישנים, הקיימים בתת המודע, עלינו להגיד לעצמנו שמחשבה ספציפית זו אינה אפקטיבית יותר. היא שירתה אותנו בעבר, אך כיום היא רק תוקעת אותנו, ומונעת מאיתנו להתקדם. ובמקומה נבחר מחשבה/אמונה חדשה.\n\nלדוגמא: אם פעם חשבנו שבלי תואר, אי אפשר להתקדם בחיים, היום ברור שאפשר להתקדם באופן משמעותי ללא תואר. אנשים רבים עשו מיליונים בלי תואר.\n\nאם פעם חשבנו שאנחנו לא שווים מספיק, שאחרים שווים יותר, ולכן הקטננו את עצמנו, עכשיו נאמץ אמונה חדשה שאנחנו שווים לכולם, כי כל בני האדם שווים, ולכן נגדיל את עצמנו. וזה אומר שתמיד נקפיד על שפת גוף פתוחה, זקופה, משוחררת, שרירים רפויים, ידיים זזות יותר (ולא יד בסנטר, או בפה, או בזקן, או בשיער), עיניים פקוחות עם מבט קדימה (ולא למטה או לצדדים). נחייך הרבה, נהיה יותר אנרגטיים.\n\nאם פעם חשבנו שאנחנו לא טיפוסים יוזמים, או חברותיים, אז דוקא נשתתף יותר בארועים, ודוקא ניזום יותר. בהתחלה זה ירגיש מעושה ומזוייף. זה ירגיש \"לא אני\", אך ככל שנקפיד לעשות זאת שוב, בכל פעם כזאת היכולת החברתית שלנו תשתפר.\n\nאם פעם חשבנו שצריך להיות עשיר בשביל להצליח, הפעם נשנה אמונה זו, ונחליט שאין צורך בעושר כדי להצליח. מספיק שיש אמביציה, תחושת ייעוד, מכוונות למטרה, שפת גוף אפקטיבית, קצב מוגבר, נוכל להתגבר ולצמוח מכל אתגר.\n\nזה המקום לומר, שאם רק תקראו את המאמר ולא תעשו לפחות צעד אחד חדש לעבר מטרתכם - שום דבר חדש וטוב לא יקרה. לכן, חובה לעשות את הצעד הראשון, כי הצעד הראשון הוא כמו כדור שלג. ברגע שהוא מתחיל להתגלגל במדרון, הוא ממשיך להתגלגל, ואפילו ללא מאמץ כלל וכלל. ותאמינו לי שכדור השלג מחייך בעודו מתגלגל...:) .\n\nוזה מזכיר לי שכל פעם שאני אומרת לעצמי: \"הפעם אני אעשה רק חלק מהכלים\", אני אף פעם לא עומדת בהבטחה זו. כי כשמתחילים, אנחנו בתוך הקצב והאנרגיה המתאימה, וזה נותן לנו חשק להמשיך ולעשות עוד, מסכימים איתי?\n\nגם אם קיים פחד מכישלון, בכל זאת תעשו!!!\n\nגם אם קיים פחד מכישלון, בכל זאת תעשו!!!\n\nגם אם קיים פחד מכישלון, בכל זאת תעשו!!!\n\nמקסימום זה יצליח!\n\nגם אם קיים פחד שאולי זה לא הדבר הנכון לעשותו, בכל זאת תעשו, כי יותר גרוע לא לעשות בכלל מאשר לעשות ולגלות שזה לא הדבר הנכון. מכיוון שכאשר אתם מגלים מהו הדבר הלא נכון, אתם כבר יכולים לדעת מהו הדבר הנכון, ואז הכל זורם והדרך פתוחה לכל כך הרבה דברים טובים ומרגשים. וזה נקרא ביטחון עצמי. הגיוני, לא?\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, סדנאות ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535"}, {"slug": "מאמרים-טכניקת-nlp", "title": "טכניקת NLP", "category": "NLP", "date": "", "excerpt": "לפני שאסביר את טכניקת NLP הפשוטה, אני רוצה לספר לכם שאת רוב הטכניקות של תחום הNLP רצוי מאוד ללמוד פיזית (אני ממליצה בכיתה עם עוד תלמידים), מכיוון שNLP לומדים מחוויה. החוויה מחדירה את הטכניקות לתת המוד", "content": "לפני שאסביר את טכניקת NLP הפשוטה, אני רוצה לספר לכם שאת רוב הטכניקות של תחום הNLP רצוי מאוד ללמוד פיזית (אני ממליצה בכיתה עם עוד תלמידים), מכיוון שNLP לומדים מחוויה. החוויה מחדירה את הטכניקות לתת המודע יותר בקלות.\n\nמי שהתנסה בזה מבין למה אני מתכוונת.\n\nאני בכוונה בחרתי טכניקת NLP פשוטה מאוד, כדי שאוכל להסביר אותה בקלות יותר.\n\nועוד הקדמה קצרה לפני ההסבר: השינויים בNLP נעשים בתת המודע. הודות לכך, השינויים הם מהירים ומחזיקים לאורך זמן.\n\nותנאי אחד חשוב לכל טכניקות NLP: לעשות אותן באופן מדוייק! לא תדייקו - לא תקבלו תוצאה.\n\nתת המודע שלנו הוא כמו מחשב. הוא מלא בתוכנות. כל תוכנה מדוייקת להפליא, והיא חוזרת על עצמה בכל פעם שלוחצים על אותו קובץ (כפתור).\n\nלמשל: תקיעות / דחיינות (דחיית עשיית משימות), פחדים, חרדות, פוביה, כעסים, חוסר ביטחון עצמי וכו'.\n\nלמי שיש את התוכנה הזאת, היא מופעלת במדוייק בכל פעם שהבן אדם חושב על הפעולה שהוא צריך לעשות, אך נמנע מלעשותה....\n\nועכשיו לטכניקה:\n\nקורה לכם שאתם משתמשים בצמדי המילים:\n\nכש.......... , אז.........\n\nאם......... , אז.........\n\nקודם...... , אז.........\n\nאחרי ש......... , אז.........\n\nחלק גדול מכם מתחברים ללפחות אחד או שניים מצמדי מילים אלה.\n\nצורת הדיבור הזאת היא \"תוכנה\". היא חוזרת על עצמה בכל פעם שבן אדם מסויים חושב על מה שיש לו לעשות, וזה גורם לו להלך רוח לא אפקטיבי.\n\nלמשל:\n\n\"קודם שאסיים את הלימודים, אחר כך אתחיל לעשות ספורט\".\n\n\"כשיהיה לי תואר, אז אחפש עבודה\".\n\n\"קודם שהילדים יגדלו, אז אתחיל לדאוג לעצמי\".\n\n\"כשאמצא זוגיות, אז אהיה מאושר\" / \"כשאמצא אהבה אהיה מאושר\".\n\n\"אחרי שאקבל תואר, אז אהיה גאה בעצמי\".\n\n\"קודם שיהיה לי ידע מושלם, אז אתחיל לעבוד בזה\".\n\n\"אם היה לי מספיק כסף, הייתי מאושר\".\n\nלכאורה, משפטים תמימים. מה שמסתתר מאחורי משפטים אלה היא העובדה שהם חוזרים על \"תוכנה\" מדוייקת. \"תוכנה\" זו היא הגורם לחוסר עשיה.\n\nהחיסרון ב\"תוכנה\" זו הוא: או שאף פעם לא משיגים את מה שרוצים, או שמשיגים, אבל ההנאה מההישג לא אורכת זמן רב, כי מטיבעה של \"תוכנה\" הוא שהיא חוזרת על עצמה שוב ושוב. ואז חוזרים שוב על התנאים שצוינו למעלה (כמו בעל חיים שרודף אחר הזנב שלו).\n\nלדוגמא: התוכנה: \"קודם שאסיים לימודים, אחר כך אעשה ספורט\", רוב הסיכויים שאדם בעל תוכנה כזאת לא יתחיל לעשות ספורט גם כשיסיים לימודים. הוא כבר ימצא תירוץ \"משכנע\" מאוד למה לא.\n\nיכול גם להיות שהוא יתחיל לעשות ספורט, אך יפסיק לאחר זמן מה, כי בתת המודע שלו ה\"תוכנה\" ממשיכה לרוץ.\n\nדוגמא נוספת: \"כשאמצא זוגיות, אז אהיה מאושר\". אדם כזה יכול בהחלט למצוא זוגיות ולהיות מאושר. יחד עם זאת, מכיוון שה\"תוכנה\" ממשיכה לרוץ בתת המודע, לאחר תקופה מסויימת של אושר, אותו אדם יחזור להלך רוח הלא אפקטיבי שהיה לו לפני הזוגיות. זאת אומרת, הוא יקח את הזוגיות כדבר מובן מאליו, וימשיך לחפש את האושר.....\n\nאם כן, מה עושים? איך פותרים את ה\"תוכנה\" הלא אפקטיבית הזאת?\n\nקיימות שתי אפשרויות:\n\n1. לעשות בלי להתנות תנאים.\n\nלמשל: במקום: \"קודם שהילדים יגדלו, אז אתחיל לדאוג לעצמי\", לשנות ל: \"אני אדאג לעצמי כבר עכשיו. הילדים לא קשורים לזה. הילדים הם רק תירוץ\".\n\n2. להרגיש את ההלך רוח בלי להתנות תנאים.\n\nמה זאת אומרת?\n\nלמשל: \"אחרי שאקבל תואר, אהיה גאה בעצמי\".\n\nלא ברור למה התואר הוא תנאי כדי שתהיה גאה בעצמך. מה הקשר בין גאוה עצמית לקבלת תואר? הרי גאוה עצמית היא הלך רוח, והלך רוח אפשר לייצר באופן מיידי, ללא תנאים מוקדמים!\n\nחבל מאוד שאנשים רבים מונעים מעצמם להיות גאים בעצמם, ומתנים תנאים לתחושות. זה מיותר ולא אפקטיבי.\n\nגישת הNLP אומרת: חבל על כל יום שעובר בלי שתהיה גאה בעצמך, או בלי שתאהב את עצמך, או בלי שתעריך את עצמך, או בלי שתהיה מאושר וכו'. ממש חבל. זה פוגע באיכות החיים. לכן, מה דעתך קודם כל להיות גאה בעצמך, ובעודך גאה בעצמך תוכל להנות יותר מלימודי התואר, ואולי גם לקבל ציונים טובים יותר, מכיוון שהלכי רוח אפקטיביים עוזרים להיות יותר ממוקדים ויותר חדים, ומשפרים את הזיכרון, לא ככה?\n\nעדנה מימון, מורה מוסמכת ללימודי NLP, מנחה סדנאות לשליטה בכעסים, לביטחון עצמי, לשיפור הזוגיות ומאמנת אישית לטיפול מהיר ויעיל בחרדות, פחדים ופוביות. מנהלת את \"מכללת אמביציות\"."}, {"slug": "מאמרים-מהי-השיטה-הכי-טובה-לעשות-שינוי-בקלות", "title": "מהי השיטה הכי טובה לעשות שינוי בקלות", "category": "שינוי", "date": "", "excerpt": "פחד משינוי הוא אחד הפחדים הגדולים ביותר של בני אדם. אנשים מתרגמים את השינוי כמשהו גדול ומפחיד, משהו שאולי לא יוכלו להצליח בו עד הסוף, פחד שלא יוכלו להתמיד עם המצב החדש, פחד שלא יהיו מספיק חזקים כדי לע", "content": "כמעט כל בן אדם מרגיש את התחושה הזאת: רוצה לעשות משהו, אבל לא עושה. ואז ממציא סיבות למה הוא לא עושה את זה: \"לא עכשיו. זה לא הזמן\", כשארגיש יותר בטוח\", \"אני לא אוהב שינויים\", \"כרגע אני מעדיף את המצב שבו אני נמצא\", \"לא ממהר, אין מה למהר\", \"למה, מישהו רודף אחרי?\", \"יש זמן\", \"אולי אני לא מספיק רוצה\", \"אולי אין לי כוח רצון\", \"אם היה לי מישהו שיעשה את העבודה בשבילי, אז הייתי הולך על זה\", \"אם היה מישהו שהיה עוזר לי, מחזיק לי את היד ומלווה אותי צעד צעד\", \"אני לא יודע איך\", \"אני לא רוצה שינוי\", \"אני לא רואה את עצמי עושה דברים כאלה, זה לא בשבילי\", \"כשיהיה לי מספיק כסף\".... ועוד כהנה וכהנה תירוצים להשאר תקוע במקום....\n\nמה שמייחד את כל התירוצים האלה הוא שאף אחד מהם איננו הסיבה האמיתית.\n\nהסיבה האמיתית היא: פחד.\n\nפחד משינוי הוא אחד הפחדים הגדולים ביותר של בני אדם. אנשים מתרגמים את השינוי כמשהו גדול ומפחיד, משהו שאולי לא יוכלו להצליח בו עד הסוף, פחד שלא יוכלו להתמיד עם המצב החדש, פחד שלא יהיו מספיק חזקים כדי לעמוד בשינויים, פחד שיהיה קשה, פחד שלא יהיה מושלם, פחד שיהיה מהיר מדי ולא יוכלו להכיל את השינוי הגדול, פחד ממה אחרים יגידו אם זה לא יצליח, פחד שיצטרכו להתאמץ ולעבוד קשה, פחד שיאבדו חברים ועוד פחדים מפחדים שונים.\n\nלסיכום: הסיבה ל: אי עשיית שינוי היא פחד.\n\nלפני שאמליץ איך לעשות שינוי בקלות, אמנה כמה דוגמאות לשינוי:\n\nהפסקת עישון\n\nהורדה במשקל\n\nעשיית ספורט\n\nמציאת עבודה חדשה\n\nעזיבת עבודה נוכחית שלא נותנת סיפוק\n\nמעבר משכיר לעצמאי\n\nמציאת זוגיות\n\nהריון\n\nמעבר למקום מגורים אחר\n\nעמידה מול קהל\n\nלימוד מקצוע חדש\n\nלהחליט מה המקצוע שרוצים להתמקד בו\n\nנסיעה חשובה\n\nלעבור טיפול לניקוי רגשות ושינוי התנהגויות\n\nועוד....\n\nובכן, איך אפשר לעשות שינוי בקלות?\n\nתחילה, אתן דוגמא מחברת \"טים סקיי\": חברה זו אחראית לזכיה במקום הראשון בתחרות היוקרתית: \"טור דה פרנס\".\n\nומהו הסוד שלהם?\n\nהם קבעו לעצמם כלל, שקראו לו: \"שיפורים מזעריים\".\n\nזאת אומרת, כל פעם שיפור קטנטן. וזה בא לידי ביטוי בכל תחום שקשור לתחרות: אם זה: איזו תזונה לאמץ, אם זה: איזו איכות אופניים להעדיף, אם זה: איך להתנהל בעבודת צוות, אם זה: באילו בדים לבחור לבגדים שילבשו, אם זה: באיזו איכות דוושות לבחור, אם זה: באילו הרגלי שינה לבחור, ואפילו בלימודי שפה של המתחרה הכי חזק.\n\nוכך בכל תחום ותחום, הם התקדמו כל פעם ממש מעט.\n\nובזכות זה הם ניצחו בתחרות!\n\nמסקנה:\n\nכל שינוי שאתם רוצים, תעשו אותו במנות קטנות (ואפילו קטנטנות). וכך, כל פעם שתעשו משהו, תרגישו שזה אפשרי וזה אפילו כיף.\n\nלדוגמא: אתם רוצים להפסיק לעשן, אבל חוששים שלא תעמדו בזה? המלצתי:\n\n1. תשאלו את עצמכם למה אתם רוצים להפסיק לעשן\n\n2. תכתבו את הסיבה על דף.\n\n3. תספרו את מספר הסיגרות שאתם מעשנים בכל יום, במשך חודש.\n\n4. אחרי חודש, תורידו סיגריה אחת (במשך חודש).\n\n5. אחרי חודש, תורידו סיגריה נוספת, וכך הלאה....\n\nמה שיקרה הוא, שכאשר עושים מעקב, תת המודע נותן יותר בהירות, והבהירות נותנת יותר אפשרויות וזה נותן יותר ביטחון, יותר אמונה שזה אפשרי, ויותר כוח להמשיך. והשינוי ייווצר כמעט בלי שתרגישו.\n\nאני מאחלת לכם בהצלחה עם השינויים הקטנים שתעשו, ולאחר זמן מה תהפכו אותם לשינוי אחד גדול:)\n\nעדנה מימון\n\nמורה מוסמכת לNLP, מאסטר בNLP, מאסטר בתרפיית קו הזמן, מאסטר קואצ', מאסטר בהיפנותרפיה. מנחה סדנאות לשליטה בכעסים, שיפור הביטחון העצמי, ושיפור הזוגיות. מאמנת אישית לטיפול בפחדים, חרדות ופוביות."}, {"slug": "מה-ההבדל-בין-פסיכולוגיה-ל-nlp", "title": "מה ההבדל בין פסיכולוגיה ל-NLP", "category": "NLP", "date": "", "excerpt": "אנשים רבים שואלים אותי: מה שאת עושה זה פסיכולוגיה? אני עונה: אני אכן עוסקת בפסיכולוגית הנפש, אך בשיטה אחרת: בשיטת NLP.ואז שואלים אותי: אז מה ההבדל?וזה הביא אותי לכתוב את המאמר הזה: עוד על ההבדל בין פס", "content": "אנשים רבים שואלים אותי: מה שאת עושה זה פסיכולוגיה?\n\nאני עונה: אני אכן עוסקת בפסיכולוגית הנפש, אך בשיטה אחרת: בשיטת NLP.\n\nואז שואלים אותי: אז מה ההבדל?\n\nוזה הביא אותי לכתוב את המאמר הזה:\n\nהיום לא צריך להיות פסיכולוג כדי לעזור לאנשים ליצור שינוי מהותי בחייהם, ובעיקר בתחושותיהם התקועות. בזכות שיטת NLP אנשים רבים עברו תהליכי שינוי מדהימים, תוך זמן קצר באופן יחסי.\n\nאנשים עם טראומות, חרדות, כעסים, התפרצויות, תיסכולים, פוביות, חוסר ביטחון עצמי, פחד מנטישה, לחץ, עצב, דיכאון, קינאה, אובססיביות וכו', הצליחו לשנות תחושות אלה, להתגבר על הקשיים ולהתחיל חיים חדשים. כל זה בזכות שיטת NLP הגאונית.\n\nונחזור לשאלה העיקרית: מהו ההבדל הכי מהותי בין פסיכולוגיה ל-NLP:\n\nקיימים ארבעה הבדלים עיקריים בין פסיכולוגיה ל-NLP:\n\nההבדל הראשון\n\nההבדל הראשון הוא שבטיפול פסיכולוגי, הלקוח הוא \"מטופל\". דהיינו, מישהו אחר מטפל בו (במקרה זה: הפסיכולוג). זאת אומרת, הפסיכולוג הוא האחראי לא הלקוח. וכך, הלקוח הוא פסיבי, כאשר הפסיכולוג הוא האקטיבי.\n\nלעומת זאת, ב-NLP הלקוח איננו \"מטופל\", אלא הוא \"מונחה\". זאת אומרת, הוא מקבל הדרכה כיצד להשתמש במוח שלו נכון, באופן עצמאי, כדי שלא יצטרך אותנו יותר. הוא לומד להשתמש במשאבים שיש לו.\n\nב-NLP הנחת היסוד היא שאין אנשים מקולקלים, לכן אין מה לתקן ואין מה לטפל. בן אדם שיש לו קושי, הוא לימד את עצמו להתנהג באופן מסוים, באופן שלא אפקטיבי לו. ולכן, הוא יכול ללמוד לשנות התנהגות זאת, ולאמץ לעצמו התנהגות אחרת, שהיא אפקטיבית בשבילו ובשביל סביבתו. הלקוח עובר תהליך מתוך חוזק ולא מתוך חולשה. הלקוח אקטיבי, ולא פסיבי. הוא לוקח אחריות על התהליך. למשל, בן אדם שמעשן, הוא לימד את עצמו לעשן. לכן, הוא יכול ללמד את עצמו לעשות משהו אחר במקום זה (בעזרת כלים מסוימים שהוא מקבל מהמנחה שלו).\n\nגם בן אדם שיש לו פוביה ממעליות, הוא לימד את עצמו לפחד ממעליות. הוא עשה את זה בתת המודע. היו לו סיבות טובות ללמד את עצמו לפחד ממעליות. אולם, ככל שהוא חזר על זה יותר פעמים, כך זה נצרב יותר בתת המודע שלו, והפך לכביכול \"חלק ממנו\". למעשה הפחד הוא לא באמת חלק ממנו. וזה אומר שאפשר להיפטר ממנו. ל NLP יש כלים עוצמתיים כדי להעלים את הפוביה הזאת, או כל פוביה אחרת. זה לא משנה איזו. למשל: פוביה מג'וקים, פוביה ממחטים, פוביה מכלבים, פוביה מנחשים ועוד ועוד...\n\nגם בן אדם שיש לו חרדות, הוא לימד את עצמו לייצר את החרדות (בתת המודע שלו). למשל: חרדת נטישה, חרדה ממבחנים, חרדה מעמידה מול קהל, חרדה מנהיגה, חרדת קיום, חרדה מסקס וכו'. בחרדות, הבן אדם חושב על מה עלול להשתבש, וזה מגדיל עוד יותר את החרדה. כיום, בזכות שיטת NLP הדברים האלה פתירים.\n\nההבדל השני\n\nההבדל השני הוא שבמהלך טיפול פסיכולגי, הלקוח חווה שוב את הטראומה, או החרדה, או כל קושי אחר. למעשה, הוא עובר טראומה נוספת באותו רגע. זאת, בהנחה שכדי להתגבר על טראומה, יש לחזור אליה, לפרט אותה ולהסביר מה קרה, כדי שהפסיכולוג יידע לסווג אותה. שיידע איזה סוג של טראומה זאת, וכך יידע מה לעשות.\n\nלעומת זאת, ב-NLP, אין צורך לחוות את הטראומה שוב. אין צורך לדעת מה קרה שם בדיוק. אפשר להעלים את הטראומה גם בלי לחוות אותה שוב ובלי לפרט מה קרה. זאת, בין היתר, הגדולה של ה-NLP והייחודיות של שיטת NLP.\n\nב-NLP הטכניקות הן ידידותיות ללקוח, מקלות עליו ומחברות אותו למשאבים שלו.\n\nההבדל השלישי\n\nהבדל נוסף ומשמעותי בין הפסיכולוגיה ל-NLP הוא: אורך התהליך. הרבה מן הלקוחות שלי, שכבר היו אצל פסיכולוגים, סיפרו שהם כבר 7 שנים בטיפול פסיכולוגי.\n\nחשוב לציין כי בשיטת NLP התהליכים קצרים מאוד. כמובן שזה שונה מבן אדם אחד לשני. אין מספר קבוע של מפגשים. יחד עם זאת, ההתקדמות מהירה יותר ואפקטיבית מאוד.\n\nההבדל הרביעי\n\nבפסיכולוגיה משתמשים בעיקר בחלק המודע של המוח. אומנם קיים שימוש בתת המודע, אך לא בטכניקות שינוי בתת המודע. לעומת זאת, בNLP משתמשים בתת המודע עם טכניקות לשינוי מהיר יחסית (מכיוון שהאוטומטים שלנו, דפוסי ההתנהגות וההרגלים שלנו נשלטים על ידי תת המודע).\n\nאז מה הבעיה?\n\nהבעיה היא במקובעות של בני האדם. אנשים הורגלו שכדי לטפל בבעיה, כמו חרדות, טראומות, פוביות, חוסר ביטחון, כעסים, דיכאון וכו', זה לוקח המון זמן. וכאשר באים ואומרים להם שיש שיטה שנקראת NLP, והיא מטפלת בבעיה תוך זמן הרבה יותר קצר, אנשים נוטים להתיחס לזה בספקנות, בפקפוק ובחוסר אמונה שזה אכן כך.\n\nולכן, ברגע שתבינו ותפנימו שאכן קיימת שיטה שמטפלת בבעיה בתוך זמן הרבה יותר קצר באופן יחסי, תוכלו להיות פתוחים לשיטה ולהנות מפירותיה, כמו עוד מיליוני אנשים בעולם.\n\nהערה חשובה:\n\nמאמר זה אינו בא להפחית מחשיבותה של הפסיכולוגיה. אדרבא, ככל שיש יותר שיטות, זה אומר שיש יותר סיכויים לשינוי. ולכן, יש מקום גם לפסיכולוגיה וגם לשיטות חדשניות וקצרות יותר. כל אחד יבחר במה שמתאים לו.\n\nהמלצתי:\n\nתבקשו פגישת היכרות חינם. בפגישה תוכלו לשאול את כל השאלות שלכם, ולקבל תשובות ולהבין יותר את השיטה, וכך תוכלו לבחור במה שמתאים לכם.\n\nעדנה מימון - טריינר, מאסטר ומורה לNLP, מאסטר קואצ', מאסטר היפנותרפיסטית, מנחה סדנאות ומאמנת אישית לניהול כעסים בזוגיות ומחוץ לזוגיות. מטפלת גם בשיטת תרפיית קו הזמן לניקוי רגשות שליליים, העלמת פחדים וחרדות דרך תת המודע, מנהלת את: \"מכללת אמביציות\"\n\n050-7378535"}, {"slug": "מה-הם-הכישורים-של-מטפל-זוגי-טוב", "title": "מה הם הכישורים של מטפל זוגי טוב", "category": "זוגיות", "date": "", "excerpt": "על המטפלת הזוגית לדעת לנקות רגשות שליליים מן העבר של הלקוח. הרגשות השליליים מן העבר הם האוטומטים – הם השולטים בנו – הם אלה שחזקים מאיתנו.", "content": "למה זה חשוב?\n\nזוגות רבים מגיעים למטפל/ת זוגי/ת, מקשיבים היטב למטפל/ת הזוגי/ת, אך לא מצליחים לבצע את המשימות שהוטלו עליהם.\n\nהתוצאה של זה: חזרה לדפוסים הישנים.\n\nלעומתם, יש זוגות שכן מצליחים ליישם את מה שהמטפל/ת המליץ/צה, אך זה מחזיק זמן קצר, ואז שוב חוזרים לאוטומטים הישנים.\n\nשתי התוצאות האלה גורמות לזוגות רבים להסיק מסקנה שגויה שאין סיכוי והכי טוב להתגרש.\n\nאם כן, תשאלו אותי:\n\nמדוע המסקנה שגויה? הרי הם ניסו את מה שהומלץ, אך לא הצליחו לקיים בפועל. היה להם רצון, ואפילו עשו מעשה אך כנראה שיש דברים שהם יותר חזקים מאיתנו.\n\nמשפט חזק....\n\nיחד עם זאת, משאיר סימן שאלה גדול. אולי אפילו איזו משאלה:\n\n\"אילו היתה מגיעה איזו פייה והיתה מעלימה לנו את הדברים שהם חזקים מאיתנו, היינו מונעים את הגירושין. היינו מקבלים בחזרה את המשפחה שלנו\"\n\nאולי כדאי קודם לשאול: מה זה \"דברים שהם יותר חזקים מאיתנו\"?\n\n\"דברים שהם יותר חזקים מאיתנו\" הם האוטומטים שלנו. האוטומטים שלנו נשלטים על ידי תת המודע ולא על ידי המודע. מסיבה זו, אנשים לא מצליחים ליצור שינוי, או מצליחים לזמן מה ואח\"כ האוטומטים חוזרים.\n\nולכן, כדי שהשינוי יהיה יציב ואמיתי, יש לשנותו בתת המודע.\n\nאיך עושים זאת?\n\nמה הם הכישורים של מטפל זוגי/מטפלת זוגית?\n\nקיימות מספר שיטות: הידועות ביותר הן NLP, תרפיית קו הזמן והיפנוזה.\n\nמכיוון שהיפנוזה אסורה בארץ (שזה ממש חבל כי היפנוזה יכולה ליצור שינויים מדהימים), נשארנו עם שתי שיטות גאוניות: NLP ותרפיית קו הזמן. שתי שיטות אלה עובדות עם תת המודע ויוצרות שינויים אמיתיים. כך השינוי נשאר לתמיד.\n\nואיך כל זה קשור לכותרת המאמר?\n\nכאשר זוגות לא מסתדרים ביניהם, זה תוצאה של אוטומטים שקשורים לעבר שלהם, כגון: כעסים, תסכולים, מרירות, חרדות, פחדים (מכל סוג כולל פחד נטישה וטראומות למיניהן), חוסר ביטחון ועוד. כל אחד מבני הזוג מביא איתו את העבר שלו אל תוך הזוגיות ומשליך אותו על השני. בנוסף לכך, כל אחד מביא איתו ערכים שונים או אפילו ערכים דומים (כאשר שם הערך הוא אותו שם, אך התוכן שונה לחלוטין). וכך, אף אחד לא מוכן לוותר על הערך שלו, כי על ערכים לא מוותרים ויהי מה.\n\nשוב: איך כל זה קשור לכותרת המאמר? או במילים אחרות: כיצד לבחור מטפלת זוגית?\n\nעל המטפלת הזוגית לדעת לנקות רגשות שליליים מן העבר של הלקוח. הרגשות השליליים מן העבר הם האוטומטים הם השולטים בנו הם אלה שחזקים מאיתנו.\n\nלאחר הניקוי, יוצרים אוטומטים חדשים חיוביים. האוטומטים החדשים נשארים לתמיד.\n\nאיך מנקים רגשות שליליים מן העבר? שתי שיטות: שיטת NLPותרפיית קו הזמן. בשילוב שתי שיטות אלה ניתן לעבוד עם תת המודע ולייצר אוטומטים חדשים בדיוק כמו שאתם רוצים.\n\nבשבוע שעבר אחת הלקוחות שלי הסבירה לי את השינוי שעבר עליה במילים אלה: \"זה כמו שמחברים למוח USB ומוציאים משם את התוכנות עם הוירוסים ובמקומם שמים תוכנות חדשות ומשודרגות. איזו הקלה\".\n\nואני הוספתי: \"יש עכשיו בפנים אנטי וירוס\".\n\nטיפ לשיפור הזוגיות\n\nלפני שאתם מעירים הערה לבן/בת זוג, תשאלו את עצמכם:\n\nבשביל מה להעיר?\n\nמה ייצא לי מזה?\n\nהאם ייצא מזה משהו טוב? (כמעט בטוח שלא...). מה שיצא מזה זה עוד בן אדם שמרגיש פחות טוב. ולכן, תחליטו שאתם לא מעירים את ההערה שתכננתם ותתגאו בעצמכם על כך:)\n\nעדנה מימון/ טריינר ומאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, לטיפול ברגשות שליליים וטיפול בטראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: להציל את הזוגיות. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות.\n\n050-7378535\n\nמי שקרא מאמר זה התעניין גם ב:\n\nהסיבות לשחיקה בזוגיות ,\n\nב: מה משפיע על תקשורת בזוגיות ,\n\nשיפור הזוגיות - עשו זאת בעצמכם\n\nוגם ב: מיומנה של מטפלת זוגית"}, {"slug": "מה-משפיע-על-תקשורת-בזוגיות", "title": "מה משפיע על תקשורת בזוגיות", "category": "זוגיות", "date": "", "excerpt": "אנשים רבים לא מבינים מדוע אחרים כועסים עליהם. הם גם לא מבינים מדוע אחרים עשו להם את מה שעשו להם. איך אחרים יכולים להתנהג אליהם בצורה כזאת, באופן כזה? הרי אנחנו היינו בסדר. היתה לנו כוונה טובה. לדעתנו ", "content": "לפני שתתחילו את השינוי, נא קיראו את הכלל הבא:\n\nכל קושי בתקשורת במערכות יחסים מקורו בתקשורת שלנו עם עצמנו - עדנה מימון\n\nלכל אדם יש את הזכות להיות מאושר, לחיות עם ביטחון, חיים שלווים, רגועים, שמחים, מפרגנים, מכבדים ובריאים.\n\nאתם תבחרו להיות מה שאתם רוצים.\n\nזכרו: השינוי מתחיל כבר עם המחשבה לעשותו, עם הפתיחות לשינוי.\n\nועכשיו למאמר:\n\nמה משפיע על התקשורת בזוגיות?\n\nמאת: עדנה מימון\n\nאנשים רבים לא מבינים מדוע אחרים כועסים עליהם. הם גם לא מבינים מדוע אחרים עשו להם את מה שעשו להם. איך אחרים יכולים להתנהג אליהם בצורה כזאת, באופן כזה? הרי אנחנו היינו בסדר. היתה לנו כוונה טובה. לדעתנו אנחנו הצודקים. זה לא הוגן שיתיחסו אלינו בצורה כזאת. אנחנו גם יכולים להסביר בדיוק ובצורה הגיונית מאוד למה אנחנו צודקים, ולמה השני לא בסדר ולא צודק.\n\nכאן המקום להזכיר את המשפט שלי: כל קושי בתקשורת בינאישית מקורו בקושי בתקשורת תוך אישית.\n\nלמה הכוונה?\n\nניקח לדוגמה בן אדם שמחפש עבודה, אך לא מוצא. דבר זה גורם לו לתסכול רב. זה יכול לפגוע בהערכה העצמית שלו, בביטחון העצמי, באמונה העצמית ועוד. בן אדם כזה עלול להוציא את התסכולים שלו על בת הזוג/בן הזוג, על הילדים, על חברים וכו'. כאשר אותו בן אדם יבין שאם הוא יטפל בתסכול שלו, לא רק שהתקשורת שלו עם הסביבה שלו תשתפר, אלא יהיו לו יותר סיכויים למצוא עבודה. בן אדם מתוסכל קשה לו יותר למצוא עבודה מאשר בן אדם לא מתוסכל.\n\nדוגמה נוספת: אדם הנמצא בפחד מתמיד שבן זוגו/בת זוגו יעזבו אותו. אדם זה חונק את הזוגיות. לעתים קרובות הוא כועס על בן הזוג/בת הזוג, על הילדים, על הלקוחות וכו'. אף אדם לא אמור לחיות בפחד מתמיד שמא הוא יינטש על ידי בן/בת הזוג. חיים כאלה הם חיים של סבל ופחד מיותרים. לכן, אם מטפלים בפחד, מערכות היחסים של אדם זה ישתפרו ויהיו מצוינות.\n\nניקח למשל אדם שחושב שבן הזוג שלו לא עושה מספיק בבית, או לא מתחשב בו, או לא עושה את מה שהוא מבקש, או לא מכבד אותו וכו'. מקור הבעיה היא במבקש ולא בזה שלא עושה. לכן, במידה שיש לכם תלונות על בן הזוג/בת הזוג, שלא עושים מספיק או לא מקשיבים לכם, תחילה עליכם לטפל בחוסר ההקשבה שלכם עם עצמכם.\n\nבני זוג/בנות זוג רבים מתנהגים כמו שהם מתנהגים כי זה מה שהם ספגו בבית או בסביבה הקרובה להם שבמהלך רוב חייהם. מה שבן אדם סופג רוב חייו מסביבתו הקרובה, נכנס לתת המודע שלו כתוכנה (בדיוק כמו תוכנה במחשב). הוא לא מכיר משהו אחר. בשבילו, זו ההתנהגות הנורמלית. לכן, במקום להיות בטוחים שאנחנו הצודקים, כדאי לבדוק אם ה\"צדק\" הזה שלנו הוא אפקטיבי ומקדם את מערכות היחסים שלנו. במידה שזה לא מקדם אותנו, מומלץ לשאול את עצמנו: מה אנחנו יכולים לעשות על מנת ליצור שינוי במערכות היחסים שלנו?\n\nאנשים רבים סובלים מחוסר ביטחון עצמי, מחרדות, מלחצים ועוד, ומצפים מבן/בת הזוג להבין אותם ולהתאים את התנהגותו לקושי שלהם. לדוגמה: בת זוג חרדתית, אשר נכנסת לפניקה מסיטואציות מסוימות. היא מצפה שבן הזוג שלה יתמוך בה בזמן שהיא נכנסת לפניקה. ברגעים כאלה, אם בן הזוג לא תומך בה, היא נפגעת מאוד, ומאשימה אותו שהוא לא רגיש, או לא אוהב, או לא מכבד וכו'. בת זוג כזאת צריכה להבין שאי אפשר לנהל חיים תקינים איתה לאורך זמן. זה לא כיף לחיות עם בן אדם כל כך תלותי, שכל הזמן צריך תמיכה, וצריך שיתחשבו בו. זה יכול לעייף מאוד ולשחוק את מערכת היחסים. כמובן שזה קורה גם בקרב גברים, שהם חרדתיים, ויוצרים מצב של תלות בבת הזוג.\n\nלחילופין, יש מצבים שבהם מתאים מאוד לבן הזוג שבת הזוג שלו תהיה תלותית בו. זה גורם לו להרגיש בעל ערך, יותר חזק וכו'. הבעיה מתחילה כאשר בת הזוג מתפתחת, מתחילה להרגיש חזקה ועצמאית יותר. מצב זה יכול לגרום לפאניקה אצל בן הזוג. הוא יכול להאשים אותה שהיא לא הבן אדם שהתחתן איתה, שהיא השתנתה לרעה וכו'. במקרים כאלה, מומלץ שבן הזוג יהיה מודע לחששותיו ויחזק את עצמו ואת הביטחון העצמי שלו.\n\nנשאלת השאלה: מדוע שבן/בת הזוג יתאימו את עצמם לקשיים בתקשורת התוך אישית של בן/בת הזוג שלהם? איפה כתוב שכך צריכה להיות זוגיות?\n\nצ'ארלס דארווין אמר: \"השורדים הם לא אלה החזקים ביותר, או האינטליגנטים ביותר, אלא, אלה המסתגלים לשינוי הכי מהר.\" זאת אומרת, להפסיק עם האוטומטים שהתרגלתם אליהם, ושלא אפקטיביים לכם. במקומם תאמצו לכם אוטומטים חדשים ואפקטיביים. תיצרו אוטומטים שמניעים שינוי בתקשורת שלכם.\n\nמהם הדברים שעלולים לגרום לבעיות בתקשורת במערכות יחסים?\n\nחוסר ביטחון עצמי\n\nבעיות בזהות העצמית\n\nהערכה עצמית נמוכה\n\nאדם שנפגע בקלות או נעלב בקלות\n\nכעסים\n\nלחץ\n\nקנאה לבן הזוג/לבת הזוג\n\nפחדים (למשל: פחד מנטישה, פחד מלהיות לבד, פחד מלאבד שליטה וכו')\n\nחרדות\n\nטראומות מן העבר שלא טופלו\n\nתסכולים (למשל אבטלה, חוסר ביטוי עצמי, חוסר סיפוק מהעבודה, יאוש, העדר מטרה בחיים, לא מקשיבים לנו וכו')\n\nקשיים אישיים למיניהם (למשל, קשב וריכוז, אובססיות למיניהן ועוד)\n\nאמונות מגבילות / אמונות טפלות\n\nדפוסי חשיבה קיצוניים (או שחור או לבן, או הכל או לא כלום וכו')\n\nנקיינות יתר (הכל צריך להיות נקי ומסודר)\n\nפרפקציוניזם\n\nטוטליות (ברגש)\n\nצורך בשליטה / צורך בלחנך\n\nהתחושה שהצדק איתי, ולכן האחר צריך להתאים את עצמו אלי (אין הבנה לרגש ולאמונות של השני).\n\nתרבות שונה (שבאה לידי ביטוי באמונות שונות. במקרה כזה כל אחד חושב שהצדק עמו)\n\nאגו (שמתבטא בחוסר חוסן נפשי, כעסים, קללות, לפעמים מכות, חוסר יכולת להודות שטעינו, תחושות השפלה או נחיתות, צורך בשליטה, חוסר סיפוק וכו')\n\n(הסדנה לשיפור הזוגיות \"התדר הזוגי\" כוללת טיפול בכעסים ושיפור הבטחון העצמי)\n\nמסקנה + טיפים\n\nבמידה שהקושי שלכם קשור לאחד הדברים הרשומים לעי\"ל, תעשו מעשה ותשנו את התנהגויותיכם. תחליטו שאתם לוקחים אחריות על החיים שלכם, על ההתנהגויות שלכם ועל התחושות שלכם. אנשים שלוקחים אחריות על ההתנהגויות שלהם ועל התחושות שלהם, הופכים להיות מאושרים, שלווים ועם חוסן נפשי. בקישור כאן למטה תוכלו לקבל 30 טיפים מנצחים לחוסן נפשי. אלה טיפים חזקים מאוד לעבודה עצמית, אשר ישפיעו לטובה על הזוגיות שלכם ועל כל תחומי החיים שלכם.\n\nהשאירו פרטיכם בטופס ונחזור אליכם\n\n********סודיות מובטחת*********\n\nלמאמר 30 דרכים למניעת סטרס מאמר זה נותן טיפים עוצמתיים לחוסן נפשי. אנשים בעלי חוסן נפשי, לא זקוקים לכעסים בתור אפשרות תגובה\n\nל פרטים על הסדנה הייחודית לשיפור הזוגיות: \"התדר הזוגי\"\n\nל: סדנה לשליטה בכעסים ושיפור הזוגיות\n\nlower"}, {"slug": "מהי-אמונה-מגבילה", "title": "מהי אמונה מגבילה", "category": "NLP", "date": "", "excerpt": "באלו אמונות אחרות כדאי להחליף את האמונות המגבילות?אנשים רבים שואלים אותי את השאלה: ", "content": "המציאות שלנו היא תוצאה של האמונות שלנו\n\nובאלו אמונות אחרות כדאי להחליף את האמונות המגבילות שלנו?\n\nאנשים רבים שואלים אותי את השאלה: \"איך אני יודע אם יש לי אמונה מגבילה?\"\n\nובכן, החלטתי לעשות רשימה קצרה של כמה אמונות מגבילות נפוצות מאוד.\n\nתחילה, אסביר מהי אמונה מגבילה. אמונה מגבילה היא כל אמונה שתוקעת אותנו. כל אמונה שמונעת מאתנו להתקדם לעבר מטרתנו, כולל אמונות טפלות.\n\nיש לזכור כי אמונה מטבעה היא סובייקטיבית. האמונות שלנו נוצרו עוד בילדותנו, ובמהלך חיינו, כאשר קלטנו אינפורמציה דרך החושים (ראיה, שמיעה, תחישה, ריח, טעם). במהלך הקליטה, החומר הנקלט עבר עיבוד, אשר יצר שינוי בתוצאה. התוצאה המתקבלת כוללת עיוותים, השמטות והכללות.\n\nלמעשה, אמונה מגבילה דומה להכנסת מצרכים מסוימים לתוך מיקסר. לאחר שמפעילים את המיקסר במהירות, מקבלים תוצאה אחרת לגמרי. כך גם באמונות מגבילות. אנחנו מעוותים אינפורמציה, מכלילים אינפורמציה ומשמיטים את מה שנוח לנו להשמיט.\n\nלמעשה, כל אמונה כוללת שני חלקים: החלק החושב והחלק המוכיח. החלק החושב חושב מחשבה, והחלק המוכיח, מוכיח שהיא נכונה, על ידי השמטת אינפורמציה המפריכה את האמונה, והתמקדות באינפורמציה התומכת באמונה.\n\nלדוגמה: אדם שמאמין שהוא לא איש מכירות. מה הוא עושה? הוא מנסה למכור, אך לא מצליח. שוב מנסה למכור, ושוב לא מצליח. לאחר מספר קטן של ניסיונות, הוא מחליט שהיו לו מספיק \"הוכחות\" לכך שהוא איננו איש מכירות. הוא רק שוכח שאת האמונה הזאת הוא מכר בהצלחה רבה לעצמו ולסביבה הקרובה שלו.\n\nאמונה מגבילה יכולה להיות גם במסגרת איסורים למיניהם.\n\nלדוגמה:\n\nאסור לאכול לפני השינה\n\nאסור לשתות אחרי אכילת פירות\n\nאסור לישון ליד חלון / קיר\n\nאסור שתהיה מראה שבורה בבית\n\nאסור להשאיר אוכל בצלחת\n\nאסור לדבר בזמן הארוחה\n\nאסור לאכול בעמידה\n\nאסור לחתן וכלה להיפגש ביום החתונה\n\nאסור לדלג מעל אדם אחר\n\nאמונה מגבילה יכולה להיות הכללה לגבי מגדר מסוים.\n\nלדוגמה:\n\nילדים הם עם אכזר\n\nנשים לא יודעות לנהוג\n\nנשים הן עם נחות\n\nלנשים אין חשיבה ריאלית\n\nגברים לא יודעים לעשות כמה דברים באותו זמן\n\nהיום אין לנוער ערכים\n\nכל הבחורים הטובים תפוסים (כל הבחורות הטובות נשואות)\n\nלהיות גרוש זה בושה\n\nכל המוכרים רמאים\n\nכל הבלונדיניות טיפשות (מעניין ששכחו את הבלונדינים...)\n\nרשימה נוספת של אמונות מגבילות:\n\nאני לא יכול\n\nזה קשה\n\nזה בלתי אפשרי\n\nאני כנראה לא רוצה מספיק\n\nאין לי כוח רצון\n\nלהיות אסרטיבי פירושו לצעוק על אנשים / לתקוף אנשים\n\nלהיות אסרטיבי פירושו לדרוך על אחרים\n\nרק אם צועקים משיגים את מה שרוצים\n\nאנשים עשירים מרימים את האף\n\nאם מתעשרים נהיים מושחתים\n\nאני לא איש שיווק\n\nאני לא טוב בשיווק\n\nהצרות באות בצרורות\n\nאם אין לך בגדי מותגים, אתה לא נחשב\n\nקשה להיות מאושר\n\nהחיים הם לא קיטנה\n\nשינוי דורש הרבה זמן\n\nשינוי זה מפחיד\n\nקשה למצוא בן/בת זוג טוב/ה\n\nמחלות הן תורשתיות\n\nכסף זה דבר מלוכלך\n\nכסף הולך לכסף\n\nכסף לא גדל על עצים\n\nחתול שחור הוא סימן למזל רע\n\nאם אני אכשל, יצחקו עלי\n\nאם זה לא מושלם, אז זה לא כדאי\n\nאו הכל או לא כלום\n\nאם אגיד על עצמי דברים טובים, אני משקר לעצמי\n\nכל מי שמסביבי רוצה לפגוע בי\n\nזה קרה לי בגללך\n\nזה המקום לציין: אם נפגעתם, תבדקו את עצמכם, ולא את זה שנפגעתם ממנו. אם כעסתם, תבדקו את עצמכם, ולא את זה שבגללו כעסתם. כנ\"ל אם הרגשתם מושפלים או מקופחים.\n\nהבנת הכלל הזה תחסוך לכם הרבה אמונות מגבילות.\n\nלשמחתנו הרבה, שיטת ה-NLP כוללת בין היתר, טכניקה לשינוי אמונה. בזכות טכניקה זו, תוך זמן קצר ניתן לשנות אמונה מגבילה, ולאמץ כל אמונה שרוצים. לדוגמה: לאדם מסוים יש אמונה שהוא לא מתאים להיות עצמאי. האמונה החדשה שהוא רוצה: \"אני מתאים להיות עצמאי\". כמובן, שתחילה, יש לוודא שהאדם אכן מעוניין לשנות את אמונתו. וגם אם יתחרט, ניתן להחזיר לו את האמונה הישנה.\n\nמומלץ לאמץ לעצמנו אמונות מקדמות כגון:\n\nכולנו יכולים,\n\nהכל אפשרי,\n\nהחיים יפים\n\nשינוי זה טוב\n\nהחיים קלים\n\nיש דבר כזה אושר אמיתי\n\nגם אם זה לא מצליח בהתחלה, זה יצליח בהמשך (If at first you don't succeed, try, try again)\n\nשינוי ניתן לעשות גם בצעדים קטנים. נפוליאון היל אמר: \"אם אינך יכול לעשות דברים גדולים, תעשה דברים קטנים בצורה גדולה\".\n\nאני לוקח/ת אחריות על רגשותי\n\nאני לוקח/ת אחריות על חיי\n\nאני לוקח/ת אחריות על מעשי\n\nאני לוקח/ת אחריות על החלטותי\n\nמכל דבר אנו לומדים משהו (\"אין כישלון, יש משוב (למידה)\" - זוהי אחת מהנחות היסוד של ה-NLP).\n\nלעבוד זה כיף\n\nהעבודה שלי היא ההובי שלי\n\nאין גיל להגשמה עצמית\n\nאף פעם לא מאוחר מדי\n\nכל זמן הוא זמן מתאים\n\nניתן להצליח בכל תחום\n\nכל אחד יכול להיות עשיר / גם אני יכול להיות עשיר\n\nאתם מוזמנים להוסיף עוד אמונות מקדמות עבור עצמכם.\n\nבהצלחה:-)\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nednamaim@gmail.com"}, {"slug": "מהי-הצלחה", "title": "מהי הצלחה?", "category": "הצלחה", "date": "", "excerpt": "כששומעים את המילים קבוצת אימון להצלחה, עולה השאלה מהי הצלחה? כיצד בכלל ניתן לקבוע הצלחה? האם יש לה גבולות? האם זה קשור לכסף? למעמד חברתי? ליופי? למידות גוף? אולי לעיסוק?ואם נניח שהצלחה קשורה לכסף, אזי", "content": "כששומעים את המילים קבוצת אימון להצלחה, עולה השאלה מהי הצלחה? כיצד בכלל ניתן למדוד הצלחה? האם יש לה גבולות? האם זה קשור לכסף? למעמד חברתי? ליופי? למידות גוף? אולי לעיסוק?\n\nואם נניח שהצלחה קשורה לכסף, אזי נשאלת השאלה, כמה כסף נחשב להצלחה? חמישים אלף? מאה אלף? מיליון? שני מיליון? מיליארד? ואם נניח שהצלחה קשורה למעמד חברתי, אזי שוב עולה השאלה מהיכן הוא מתחיל? בעלות על מכונית יקרה? אולי וילה? אולי עצם היותי שייכת לחברה מסויימת? אולי בכלל עיסוק בתחום מסוים יתן לי תחושה של הצלחה? מה עם צבע עיניים או שיער? מידות גוף כבר אמרנו?\n\nכמה חבל שאין קריטריון מסויים המראה את הנתונים המדויקים להצלחה!\n\nאך, הסירו דאגה מליבכם. הסיבה לכך היא שהצלחה כלל אינה נמדדת על סמך הקריטריונים שהוזכרו לעי\"ל.\n\nמכאן, שהצלחה איננה יכולה להתבסס על נתונים אובייקטיביים, אלא דוקא על נתונים סובייקטיביים, דהיינו, תחושותנו האישיות.\n\nכל אחד מאתנו מפרש הצלחה באופן שונה. עולל בן שנה מרגיש הצלחה אם הוא מצליח ללכת בלי ליפול. נער בן 15 מרגיש הצלחה אם הוא קם בבוקר ולא מוצא פצעונים חדשים על הפנים. נער אחר ירגיש הצלחה אם הוא יעבור את הבחינה במתמטיקה. איש מכירות ירגיש הצלחה אם יצליח למכור כמות מסוימת של המוצר אותו הוא מוכר. מעשן סיגריות שיפחית חמישים אחוז ממספר הסיגריות שהוא מעשן ירגיש הצלחה. לעומתו, מעשן אחר ירגיש הצלחה רק אם יפסיק לעשן לחלוטין .\n\nעל מנת להבין לגמרי את המושג הצלחה, ראשית עלינו לדעת מה לא יכול להחשב להצלחה.\n\nאדם הרוכש מכונית מסוימת רק בגלל שלשכן שלו יש מכונית כזאת - זו אינה הצלחה! אדם הפותח עסק מסוים רק בגלל שלמישהו שהוא מכיר יש עסק כזה, וזה מצליח - זו אינה הצלחה! אדם הפוצח בקריירה מסויימת רק בגלל שזה in , או בגלל שזה ישמח את הוריו, או בגלל שזה יתן לו כרטיס כניסה לחברה מסוימת - זו אינה הצלחה! אדם שמשווה את תוצאותיו ביחס לאחרים - זו אינה הצלחה.\n\nמכאן, הצלחה היא תחושה אינטימית. הצלחה מרגישים מתוך הקרביים. הצלחה מרגישים מתוך הלב. אם אתה קם בבוקר עם תחושה של כיף (ולא מתוך תחושת יאוש וכניעה למציאות), אזי אתה מצליח. אם אתה עוסק בתחום שנותן לך סיפוק עצום, אזי אתה מצליח. אם התקשורת הבינאישית שלך חיובית, אפקטיבית ומקבלת - אתה מצליח. אם אתה חי באיזון רגשי, אתה מצליח.\n\nלסיכום, אם אתה עסוק בעשייה הקשורה למשימה שהצבת לעצמך מתוך מצפונך הפנימי, ולא בגלל ציפיות של אחרים, ולא בגלל מה שאחרים יגידו - אתה מצליח. אם אתה עושה את משימתך מתוך דרייב פנימי, ולא מתוך כורח - אתה אכן עונה להגדרה הצלחה. אם הערך העצמי שלך נשאר גבוה, ללא קשר לכמות הכסף שיש לך, או לכמה הספקת, או לכמה השגת, אתה עונה להגדרה הצלחה. אם אתה נהנה מהדרך, מחייך הרבה - זו הצלחה. אם אתה מפרש סיטואציות בצורה חיובית - זו הצלחה.\n\nאדם מצליח מרגיש שהוא מצליח עם כל חושיו. אדם מצליח אינו שואל את עצמו האם אני מצליח. הוא יודע זאת וחש זאת. וזו תחושה נהדרת.\n\nבקבוצת אימון להצלחה נפגשים פעם בשבוע ומקבלים כלים על מנת להגיע להצלחה האמיתית.\n\nמאמר זה פורסם גם במעריב nrg\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535"}, {"slug": "מיומנה-של-מטפלת-זוגית", "title": "מיומנה של מטפלת זוגית", "category": "זוגיות", "date": "", "excerpt": "שיחה טיפוסית בינו לבינה (קטגוריה: יחסים > זוגיות)", "content": "שיחה טיפוסית בינו לבינה\n\nדנה: \"אמא שלך מעדיפה את אחותך הגדולה על פניך\".\n\nקובי: \"אני יודע\".\n\nדנה: \"היא מחייכת מאוזן לאוזן כל פעם שאחותך הגדולה מבקרת אותה, אבל כשאתה מבקר אותה, היא רק אומרת שלום\".\n\nקובי: \"אני יודע\".\n\nדנה: \"היא גם מנשקת יותר את הילדים של אחותך מאשר את הילדים שלך\".\n\nקובי: \"אני יודע\".\n\nדנה: \"היא גם קונה מתנות יותר יקרות לילדים של אחותך מאשר לילדים שלך\".\n\nקובי: \"אני יודע\".\n\nדנה: \"היא באה יותר למסיבות יום הולדת של הילדים של אחותך מאשר לילדים שלך\".\n\nקובי: \"אני יודע\"\n\nדנה: \"היא עוזרת לעשות כלים בבית של אחותך, אבל בבית שלך היא לא עושה כלום\".\n\nקובי: \"אני יודע\".\n\nדנה: \"היא גם צוחקת הרבה כשהיא בבית של אחותך, אבל כשהיא בבית שלך, היא לא צוחקת בכלל\".\n\nקובי: \"אני יודע\"\n\nדנה: \"היא גם מעדיפה את יוני (בעלה של אחותו), על פני אשתך\" (מתכוונת לעצמה כמובן).\n\nקובי: \"אני יודע\"\n\nדנה: \"כל פעם שאמא שלך ויוני נפגשים היא מחייכת מאוזן לאוזן, היא ממש פורחת. וכשהיא פוגשת אותך ואותי, היא כאילו מחייכת וכאילו שמחה, אבל רואים עליה שזה לא אותו דבר. איך היא לא מתביישת לעשות לך את זה? איזו אמא... אני במקומך לא הייתי שותקת. היא צריכה לדעת שאתה שם לב לעוול שהיא עושה לך\".\n\nקובי: (בצעקות): די כבר! אולי מספיק? כמה שאת מתאמצת כדי להוכיח שהיא רעה ושהיא כזאת, ושהיא כזאת ושהיא כזאת. מה זו הרשימה הזאת? בטח עבדת קשה כדי להכין אותה ולהוכיח שאת צודקת! כמה זמן השקעת בה, הא? את מתעסקת רק בה ורק בשלילי. זה מה שאת רואה! כולך שלילית. אין לך אפילו משהו אחד חיובי להגיד עליה? זה שהיא באה למסיבות של הילדים שלנו, זה שהיא קונה מתנות, זה שהיא מחייכת ושואלת לשלומנו, זה שהיא מציעה לנו הצעות שעוזרות, זה שכל פעם שאת עוקצת אותה היא לא עונה לך, זה שפעמיים בשבוע היא מתקשרת ושואלת לשלומנו ולשלום הילדים, זה שהיא פותרת את הסכסוכים ביני לבינך, וזה שכל חודש היא משלמת את שכר הדירה שלנו ואת האוכל ועוד הרבה דברים את זה שכחת? היא לא מבזבזת שקל אחד על אחותי הגדולה. וגם כל פעם שאני צועק עליה היא מדברת אלי יפה. ואני צועק עליה הרבה. את יודעת למה? כי את כל הזמן מספרת לי כמה שהיא כזאת וכזאת. אז אני שותק לך ומוציא הכל עליה! ועוד דבר: כל מה שאמרתי לך \"אני יודע\" זו אינפורמציה שקיבלתי ממך. אני עצמי לא חוויתי את זה אף פעם! אני פשוט האמנתי לך ולעיוותי החשיבה שלך.\n\nדנה: (בצעקות): זו התגובה שלך? זה מה שיש לך להגיד אחרי כל מה שאמרתי? איפה ההתיחסות למה שאמרתי? ואתה יודע מה? היא גם סכסכנית! בגללה אתה עכשיו רב איתי!\n\nמסקנה\n\nאם יש לכם אמונה כלשהי לגבי בן אדם מסוים, אתם תצליחו \"להוכיח\" שאתם צודקים. זה לא אומר שאתם באמת צודקים, אלא שהשמטתם את החלקים שמוכיחים את טעויותיכם. כך פועל מוחנו. זהו תת המודע שמגן עלינו.\n\nבמקרה זה, בתור מטפלת זוגית, הייתי מבקשת מדנה לבדוק איך היא מתייחסת לחמותה, ולעומתה, איך יוני (גיסה) מתייחס אל חמותו.\n\nהתשובה ברורה.\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nלרשימת סדנאות"}, {"slug": "שינוי-זה-טוב-או-לא-טוב", "title": "שינוי - זה טוב או לא טוב?", "category": "שינוי", "date": "", "excerpt": "אנשים רבים מתנגדים התנגדות נמרצת לשינוי. אתן לדוגמה את חברתי - נקרא לה בשם הבדוי מיקה.מיקה היא בחורה עם רצונות רבים. יש לה חלומות להיות עשירה, לעסוק בתחום שמעניין אותה וגם לפתור כמה רגשות שליליים ששול", "content": "אנשים רבים מתנגדים התנגדות נמרצת לשינוי. ניקח לדוגמה את חברתי - נקרא לה בשם הבדוי מיקה.\n\nמיקה היא בחורה עם רצונות רבים. יש לה חלומות להיות עשירה, לעסוק בתחום שמעניין אותה וגם לפתור כמה רגשות שליליים ששולטים בה ופוגעים בה ובסביבתה (משפחה, חברים וכו') וחוזרים על עצמם שוב ושוב כבר שנים רבות.\n\nמיקה כבר בת 50, אך לא השיגה אפילו מטרה אחת מכל מטרותיה. היא ממשיכה לעבוד באותה עבודה אפורה, החוזרת על עצמה בשעמום ותסכול רב. היא מחפשת זוגיות פרק ב' (מזה שנים רבות), אך עדיין לא מצאה את האחד.\n\nבשפת מאמנים אישיים היא נקראת תקועה. זאת אומרת: היא רוצה - אבל לא עושה שום דבר בנדון.\n\nכשהצעתי לה לקחת מאמן אישי או מאמנת אישית ולעבור תהליך לשינוי, היא הגיבה בכעס ובפגיעות. היא נפגעה עד עמקי נשמתה. \"איך את מעיזה אפילו לחשוב שאני צריכה להשתנות? אני אוהבת את מי שאני. אני אוהבת את המראה שלי, את סגנון הלבוש שלי, את התחביבים שלי, את המאכלים האהובים עלי וכו'. אני לא מוכנה להיות מישהי אחרת. ומי שלא מוכן לקבל אותי כמו שאני - שיתרחק ממני.\n\nואכן, הרבה כבר התרחקו ממנה. כולל אותי. גם אני התרחקתי ממנה, אך אחת לכמה זמן נפגשנו שוב וקבענו החלטות חדשות. ושוב האוטומטים השליליים שלה חזרו על עצמם, ושוב התרחקנו. דבר זה חזר על עצמו כמה פעמים. ממש כמו אצל זוגות שנפרדים וחוזרים.\n\nאם כן, מה לעשות? איך להתמודד עם פחד משינוי?\n\nתחילה כדאי שנבין למה הכוונה במילה: \"שינוי\".\n\nכאשר ממליצים לבן אדם לעבור שינוי, אין הכוונה שהוא יהיה בן אדם אחר. הוא תמיד ישאר הוא - גם אם יעבור תהליכי שינוי.\n\nאנחנו תמיד אנחנו - ומוטב שזה ימשיך להיות כך.\n\nכמו שדר' סוס אמר: \"היום אתה זה אתה. אין עוד אדם בעולם שהוא יותר אתה מאתה\".\n\nכאשר אנחנו מדברים על שינוי, אנחנו מדברים על התפתחות, על למידה - ולא על לשנות את מי שאנחנו. כאשר אנחנו מדברים על שינוי, או סדנה להתמודדות עם שינוי, אנחנו מתכוונים לשינוי התנהגויות שתוקעות אותנו, שינוי התנהגויות שלא אפקטיביות לנו, שינוי הרגלים שמונעים מאיתנו להתקדם, שינוי אוטומטים שפוגעים בתקשורת שלנו עם עצמנו ועם אחרים. כאשר אנחנו מדברים על להשתנות, אנחנו מדברים על שינוי תחושות שליליות ובמקומן לחוות תחושות חיוביות, מקדמות ומעצימות.\n\nכאשר אנחנו מדברים על להשתנות, אנחנו לא מתכוונים לשנות תחביבים. אנחנו לא מתכוונים לשנות את המראה או את סגנון הלבוש. אנחנו לא מתכוונים שתהיו מישהו אחר. אדרבא. תהיו רק מי שאתם. אנשים רבים מדי עסוקים מדי בלהיות מישהו אחר, עד כדי כך שהם שוכחים להיות מי שהם באמת. אוסקר ויילד כתב על זה משפט חשוב: \"תהיה עצמך. כל האחרים כבר תפוסים\".\n\nבני אדם משתנים כל הזמן. אנחנו לומדים דברים חדשים. מגלים שאמונות מסוימות שהאמנו בהן בעבר - כיום הן כבר לא רלוונטיות. למשל: פעם זרקנו את בקבוקי הפלסטיק. לא התיחסנו לכדור הארץ. היום יש לנו אמונה חדשה: צריך למחזר את בקבוקי הפלסטיק למען שמירה על כדור הארץ.\n\nונחזור למיקה חברתי: היא החליטה לעשות שינויים לבדה, ללא עזרה חיצונית, אלא בקצב שלה. שיהיה לה בהצלחה. אני כבר מדמיינת את הפגישה איתה בעוד 20 שנה. אני אשאל אותה: \"נו, איך השינויים שעשית בכוחות עצמך?\" היא תגיד לי: \"בסדר. לאט לאט\". אני אשאל: \"נו, החלפת עבודה?\" היא תענה: \"לא התחשק לי\".\n\nהיא ביזבזה כבר 50 שנה מחייה, למה שלא תבזבז עוד 20 שנה?\n\nלידיעתכם: בזכות שיטת NLP וטכניקות קו הזמן, שינוי יכול להיות מהיר וממלא את הנשמה\n\nבתחושות נפלאות.\n\nאנשים שעברו שינוי בזכות שיטה זו הרגישו שנולדו מחדש ואמרו לי: \"אילו ידעתי שזה מה שאני ארגיש אחרי השינוי, מזמן הייתי עובר את התהליך הזה. חבל על כל השנים שפיספסתי, על כל החוויות המרגשות שדילגתי עליהן, על רויות האמיתיות שהתעלמתי מהן ועל זה שכל השנים האלה לא הייתי באמת אני. רק עכשיו אני חי את עצמי ואת מי שאני באמת\".\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי.\n\nמנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות.\n\n050-7378535\n\nednamaim@gmail.com"}, {"slug": "שיפור-הזוגיות-עשו-זאת-בעצמכם", "title": "שיפור הזוגיות - עשו זאת בעצמכם", "category": "זוגיות", "date": "", "excerpt": "זוגות רבים מתקשים בתקשורת ביניהם. הם לא יודעים מה לעשות. הם חווים חוסר אונים גדול. לקרוא עוד על איך לשפר את הזוגיות בעצמכם", "content": "הדרכה על טיפול זוגי עצמי\n\nזוגות רבים מתקשים מאוד בתקשורת ביניהם, אך לא יודעים מה לעשות. במקרים רבים הם חווים חוסר אונים גדול. הם מלאי כעסים על הפרטנר/ית ומשרים אווירה מאוד לא נעימה בבית. מטרת המאמר היא לשפר את הזוגיות שלכם בעצמכם. תהיו אתם המטפלים הזוגיים שלכם. תעשו את זה שלב אחר שלב. חשוב מאוד שתהיו לגמרי כנים עם עצמכם. הנה תהליך שיפור הזוגיות ב-7 שלבים:\n\n1. תודו בתחושות האמיתיות. זה בסדר להודות שיש קושי, כי רק אחרי שמודים בכך, מבינים שצריך לעשות משהו. זוגות רבים לא מודים בכך, וממשיכים לחיות עם תסכולים רבים. לכן, משפט שבו שמים את הקלפים על השלחן חשוב כדי להגיע לצעד הבא.\n\n2. זוגות רבים נתקעים ב:1. החוכמה היא להמשיך ל:2. זאת אומרת: להחליט לעשות משהו בנדון. בדיוק כמו שאם הגלגל של האוטו מפונצ'ר, אתם הולכים למוסך, כמו שאם הטלפון הסלולרי מתקלקל, אתם לא מחכים אפילו יום אחד כדי לטפל בזה, בדיוק כמו שאם הילד חולה, אתם נותנים לו את הטיפול הטוב ביותר - כך גם בזוגיות. תחליטו שאתם עושים משהו כדי לשנות את המצב הקיים.\n\n3. השלב הזה כולל שאלות שתשאלו את עצמכם: מה אני רוצה מהזוגיות הזאת? מה חשוב לי בזוגיות הזאת? איך אני רואה את עצמי עוד 5 שנים, עוד 10 שנים, עוד 20 שנה וכו'?\n\n4. כאן תשאלו את עצמכם: במי זה תלוי? במה זה תלוי? האם זה תלוי בפרטנר/ית או בי או בשנינו?\n\n5. בשלב זה תשאלו את עצמכם אם בתשובתכם לשלב 4 תליתם את הפתרון בפארטנר שלכם. תהיו כנים לגמרי. במידה שהתשובה שלכם היתה שזה תלוי בפרטנר/ית, מומלץ שתשנו את זה כבר עכשיו. אנחנו לא אחראים על שינוי מישהו אחר, אלא על שינוי עצמנו. אנחנו נשאל את עצמנו: מה אני יכול/ה לעשות כדי לשפר את הרגשתי? האם יכול להיות שהתמקדתי הרבה בשלילי ובכלל לא התיחסתי לחיובי? האם יכול להיות שנתתי משקל רב למה שאין מאשר למה שיש?\n\n6. שאלות נוספות שתשאלו את עצמכם: האם השתמשתי עד כה בשפה שלילית? האם אני מגזים/ה בתלונות? האם אני טיפוס של או שחור או לבן? האם אני טיפוס של קצוות? מה עשיתי שתרמתי לזוגיות להגיע עד הלום? אולי התלוננתי יותר מדי? אולי השלכתי על השני את פחדי (פחד מנטישה, פחד מדחיה, פחד מאובדן וכו')? אולי כפיתי על הפרטנר/ית את אמונותי (שחשבתי ש\"דברים צריכים להיות ככה ולא אחרת ואם זה נעשה אחרת, אז אני לא אשתוק\")? אולי לא פיניתי מקום בתוכי בשביל עוד בן אדם? אולי חשבתי שזוגיות זה רק מה שאני מאמין בו ושהפרטנר צריך ליישר איתי קו? אולי חפרתי יותר מדי לפרטנר/ית? אולי התנהגתי כמו קרציה?\n\n7. במידה שעניתם על השאלות בכנות, קיימת האפשרות שהבנתם שיש מה לשנות אצלכם. לכן, תחליטו שמהיום אתם משנים כיוון. מהיום אתם לוקחים אחריות על הזוגיות. מהיום אתם מתיחסים לזוגיות בדיוק כמו שאתם מתיחסים לילד שלכם כשהוא חולה. אתם לא מתלוננים. אתם מעניקים. אתם מבינים אותו. חשוב לכם שיבריא וירגיש טוב. חשוב לכם שיחייך. חשוב לכם שיהיה מאושר. אתם לא אומרים לילד: \"תעשה אותי מאושר/ת\", אלא אתם דואגים שהוא יהיה מאושר.\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים,פוביות. שינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לשיפור ביטחון עצמי, סדנאות לניהול ושליטה בכעסים , שיפור הזוגיות, קורס NLP - למי שרוצה לדעת את הסודות הכי כמוסים של איך לשפר הכל בקלות\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע", "title": "תפקידיו של תת המודע - חלק 1", "category": "תת מודע", "date": "", "excerpt": "מאמר זה הוא הראשון מתוך סדרה של מאמרים בהמשך למאמר: כוחו ועוצמתו של תת המודעתחילה, הסבר קצר כדי למנוע אי הבנות: תת המודע הוא חלק מאיתנו. הוא אנחנו. זה לא איזו ישות חיצונית ומפחידה. תת המודע הוא אנרגיה", "content": "מאמר זה הוא הראשון מתוך סדרה של מאמרים בהמשך למאמר: כוחו ועוצמתו של תת המודע\n\nתחילה, הסבר קצר כדי למנוע אי הבנות: תת המודע הוא חלק מאיתנו. הוא אנחנו. זה לא איזו ישות חיצונית ומפחידה. תת המודע הוא אנרגיה בעלת עוצמה רבה.\n\nאחד התפקידים החשובים של תת המודע הוא להיות אחראי על האוטומטים שלנו.\n\nלדוגמה, אם למדתי לנהוג באוטו. רצוי מאוד, שלא אצטרך ללמוד לנהוג באוטו כל פעם מחדש.\n\nלכן, לאחר כמה פעמים, הנהיגה הופכת להרגל. זה מתבטא בכך שאני מפסיקה לחשוב (במודע) על כל השלבים ההכרחיים לנהיגה.\n\nלמעשה, אני עושה הכל באוטומט.\n\nכלומר, בשלב מסוים, פעולת הנהיגה עברה מן המודע אל תת המודע.\n\nתחשבו על כל הדברים הטובים (האפקטיביים) שאתם עושים באוטומט. לדוגמה: הקלדה עיוורת, רכיבה על אופניים, שחייה, קריאה, כתיבה וכו'.\n\nעכשיו, תחשבו על כל הדברים הלא אפקטיביים שאתם עושים באוטומט. לדוגמה: קללות, פחדים, חרדות, סטרס, כעסים, חוסר ביטחון, או כל דפוסי התנהגות שמעכבים אתכם.\n\nלמעשה, גם את ההתנהגויות האלה אתם לימדתם את עצמכם. בהתחלה, לא הייתם כל כך \"טובים\" בזה. לאחר כמה פעמים, זה הפך לאוטומט. זה אומר שזה עבר מן המודע אל תת המודע.\n\nלתת המודע יש זיכרון מעולה. כל פעם שתצטרכו אותו, הוא יתן לכם את ההתנהגות הזאת באופן אוטומטי.\n\nמסיבה זאת, אנשים רבים רוצים לשנות אוטומטים מסוימים, אך לא מצליחים. הם לא מצליחים מכיוון שהם משתמשים במודע בשביל לשנות. וכפי שכבר ידוע, המודע אינו אחראי להתנהגות האוטומטית, אלא תת המודע.\n\nמכאן, השינוי האמיתי יצטרך להיעשות מתוך תת המודע.\n\nניפגש במאמר הבא: תפקידיו של תת המודע - מס' 2\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע-2", "title": "תפקידיו של תת המודע - חלק 2", "category": "תת מודע", "date": "", "excerpt": "בדיוק כמו שבמחשב יש זיכרון והוא מאוחסן בתוך צ'יפים, כך גם למוח שלנו יש זיכרון והוא מאוחסן בתוך תת המודע. תפקיד מס' 2 של תת המודע הוא לאחסן זיכרון.", "content": "תת המודע הוא כמו מחשב\n\nבדיוק כמו שבמחשב יש זיכרון והוא מאוחסן בתוך צ'יפים, כך גם למוח שלנו יש זיכרון והוא מאוחסן בתוך תת המודע.\n\nתפקיד מס' 2 של תת המודע הוא לאחסן זיכרון.\n\nקיימים שני סוגי זיכרון: לפי זמן (ליניארי) ולא לפי זמן.\n\nבכל רגע נתון אנחנו חשופים להמון מידע:\n\n11 מיליון ביטים של מידע.\n\nהרוב נשמט. מתוכו נשארים רק 134 ביטים של מידע. כל מה שנשמט עובר לתת המודע.\n\nהמידע שלא נשמט הוא המידע שרלוונטי לנו באותו רגע, בהתאם למיקוד שלנו.\n\nלדוגמה: אם באותה תקופה אני רוצה לקנות בית - אני אתמקד בזה ואמצא הרבה בתים. באותו זמן מידע אחר נשמט מן המודע ועובר לתת המודע. באותו אופן, מי שמתמקד בפחדים - זה מה שיקבל, ומי שמתמקד במחשבות חיוביות - זה מה שיקבל.\n\nדוגמה נוספת: ילד בוכה כי קיבל מכה וכואב לו. כל עוד הוא חושב על זה - זה יכאב לו. ברגע שמסיטים לו את המחשבה למשהו אחר - הוא ישכח מהכאב.\n\nדמיינו שני בני אדם מדברים אליכם בו זמנית. מדי פעם אתם תפספסו מילים כלשהן, או משפטים. מלים אלה מגיעות לתת המודע.\n\nבקיצור: תת המודע זוכר הכל. זה המודע שזוכר באופן מוגבל.\n\nניפגש במאמר הבא: תפקידיו של תת המודע - חלק 3\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע-3", "title": "תפקידיו של תת המודע - חלק 3", "category": "תת מודע", "date": "", "excerpt": "תפקיד מס' 3 של תת המודע הוא: להדחיק זכרונות של רגשות שליליים לא פתורים.", "content": "הקשר בין תת המודע לזכרונות ורגשות\n\nתפקיד מס' 3 של תת המודע הוא: להדחיק זכרונות של רגשות שליליים לא פתורים. למשל טראומה מילדות: אצל הרבה אנשים היא נמחקת. הם לא זוכרים אותה. היא נכנסת לתת המודע. אצל אחרים היא נכנסת לאיזושהי מגירה בתת המודע, אך לא נמחקת. אותו אדם אינו חושב על הטראומה ביום יום, אך אם ישאלו אותו על סיטואציה מן העבר שבה הוא עבר טראומה, הסיטואציה הזו תעלה לו בזכרון.\n\nחשוב לציין, כי למרות ההדחקה, אותו אדם מתנהג באופן מסוים (למשל: חרדות, חוסר ביטחון, פחדים למיניהם וכו') בהשפעת אותה סיטואציה. ולכן, אחרי שהוא מטפל באותה טראומה, התנהגותו משתנה באופן אוטומטי.\n\nיש עוד סוג של אנשים: אלה שהטראומה מלווה אותם כל חייהם. ואז הם כל כך רגילים אליה, שבתת המודע שלהם הם לא מוכנים לוותר עליה. היא הופכת למעין: \"חברה\". אלה אנשים שהולכים ממטפל למטפל, אך מסרבים (בתת המודע) לפתור אותה. הם מקבלים הרבה תשומת לב ורחמים על הטראומה. לכן הם לא מוכנים להיפטר ממנה.\n\nזה המקום להביע את דעתי האישית: הטיפול הכי טוב בטראומה הוא בשיטת תרפיית קו הזמן משולב עם NLP. היתרון בשיטות אלה הוא שהאדם לא צריך לחוות שוב את הטראומה כדי להעלים אותה (לעומת הפסיכולוגיה, שבה האדם חווה שוב את הטראומה וזה מגדיל אותה ויוצר טראומה נוספת. כל זה מיותר לחלוטין.).\n\nהעולם שלנו מתקדם בקצב אדיר. לפני כמה שנים מי היה חושב על אייפון? לפני שהטלפון הסלולרי הומצא, מי חשב על זה? או על אינטרנט וכו'. כך גם בתחום הנפש. יש התפתחות מדהימה, אפילו גאונית. ולכן, כשיש שיטה שבה אפשר לטפל בטראומה מבלי לחוות אותה שוב, היא בוודאי עדיפה על שיטה שבה חווים אותה שוב. יש כאלה שזה לא נתפס להם. זה בגלל הרגלי חשיבה ישנים. כמובן שמודעות לדפוסי חשיבה ישנים תעזור להיות פתוחים לשנות אותם.\n\nהמלצתי: אם יש לכם זכרונות שליליים מן העבר: טפלו בהם. למרות שהם נראים לכם לא רלוונטיים - תת המודע מתנהג בהתאם למה שעבר עליכם בעבר. הוא זוכר!\n\nניפגש במאמר הבא: תפקידיו של תת המודע - חלק 4\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע-4", "title": "תפקידיו של תת המודע - חלק 4", "category": "תת מודע", "date": "", "excerpt": "תפקיד נוסף של תת המודע הוא לנהל את הגוף.", "content": "תת המודע וגופנו\n\nתפקיד נוסף של תת המודע הוא לנהל את הגוף.\n\nלתת המודע יש חותם (blueprint) של גוף שנמצא במצב בריא לחלוטין, עוד מתחילת חיינו. החותם הזה מוטבע היטב בתת המודע והופך לאוטומט. כמו למשל, רמת החיסון של הגוף, תקינות הקיבה, תקינות איברי הרביה, תקינות כלי הנשימה וכו'. וכך, אם, למשל, יש למישהו פצע קל, שמים פלסטר והפצע מחלים לאחר כמה שעות או ימים (גם בלי פלסטר....). זאת, מכיוון שלתת המודע יש את האוטומט של ניהול הגוף ודאגה לרווחתו ובריאותו.\n\nאנשים רבים אינם מודעים לכך, אך גופנו מתחדש כל הזמן.\n\nלמשל:\n\n98% מהאטומים של הגוף מתחדשים כל שנה\n\nכל 3 חודשים מתחדשות הרקמות הרכות\n\nכל חמישה ימים מתחדשות דפנות הקיבה (הרירית).\n\nכל חודש בממוצע מתחדש העור.\n\nהכבד מתחדש כל 6 שבועות.\n\nלגבי השיער והציפורניים כולנו כבר יודעים שהם מתחדשים.\n\nואם אני שומעת אתכם היטב כרגע, אתם שואלים עכשיו: אם כך, איך זה שלאנשים מסוימים יש מחלות שהם לא נרפאים מהן? ואיך זה שהעור מזדקן? ואיך זה שילדים נולדים עם בעיות גופניות? ואיך זה שיש אנשים עם רמת חיסון נמוכה? ואיך זה ששיער ראשם של אנשים מסוימים אינו מתחדש?\n\nשאלות מצוינות. אפרט על כך במאמר הבא: תפקידיו של תת המודע: חלק 5\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע-5", "title": "תפקידיו של תת המודע - חלק 5", "category": "תת מודע", "date": "", "excerpt": "תפקיד נוסף של תת המודע הוא לשמור על גופנו. אם כן, תשאלו, כיצד זה שכל כך הרבה אנשים חולים?", "content": "תת המודע וחידוש הגוף\n\nתפקיד נוסף של תת המודע הוא לשמור על גופנו. אם כן, תשאלו, כיצד זה שכל כך הרבה אנשים חולים?\n\nלפני שאענה על שאלה זו, אני מזכירה לכם שאברי גופנו מתחדשים כל הזמן (ראה תפקידיו של תת המודע - תפקיד מס' 4). שוב נשאלת השאלה: אם הם מתחדשים כל הזמן, כיצד זה שמחלות מסוימות נשארות לתקופה מסוימת, וחלקן הרות אסון?\n\nהתשובה היא שיש לתת המודע עוד תפקידים, והוא מתאים את עצמו אליהם. הוא מתנהל בסינכרוניזציה מלאה לתפקידים האחרים.\n\nלדוגמה:\n\nאם למשל, למישהו יש פחד שיקרה לו משהו, או מאמין שעלול לקרות לו משהו רע, והוא חושב על זה הרבה, זה עלול להתגשם, מכיוון שבין היתר תת המודע הוא צייתן.\n\nהוא מציית למחשבות שלנו לגבי עצמנו. זאת אומרת, הוא כל הזמן מקשיב למחשבותינו.\n\nמסיבה זאת, יש הורים שכאשר ילדם הקטן חולה מאוד, הם מביעים משאלה שהמחלה תעבור אליהם במקום הילד. זוהי טעות חמורה, מכיוון שהורה כזה עלול לקבל את המחלה מכיוון שחזר על משאלה זו הרבה פעמים ודימיין את עצמו עם המחלה. הוא כל כך רצה את זה, שתת המודע (שהקשיב כל הזמן למחשבותיו) נתן לו את זה. ומה הבעיה עם זה? שהמחלה נוצרה אצל הילד מסיבה מסוימת (קשיים מחשבתיים למיניהם). והיא לא תעזוב אותו אם הוא עדיין במצב המחשבתי ההוא. וכך נוצר מצב שבו גם הילד וגם ההורה חולים במחלה.\n\nעל מנת לאפשר לילד להבריא, יש לשנות את המציאות שלו, את סגנון החיים שלו, את היחס אליו.\n\nיש מצבים שבהם כמה אנשים מאותה משפחה חולים באותה מחלה. בטעות יש נטיה לחשוב שזה תורשתי. מי שמבין כיצד תת המודע עובד יודע שזה כלל וכלל אינו כך. הסיבה לכך שיש משפחות עם אותה מחלה מתחלקת ל-3:\n\n1. באותה משפחה קיימת התנהלות מסוימת, מחשבות דומות, דיבורים דומים - דיבורים שמתאימים לאותה מחלה.\n\n2. תת המודע מתנהל על פי אמונותינו (אמונות הקיימות בתת המודע - ולא רק במודע). מי שיש לו אמונה שזה תורשתי, ושהוא גם עלול לחלות במחלה הספציפית - הוא אכן יחלה במחלה (תת המודע מקשיב לאמונות שלנו). היו לי כמה לקוחות שהאמינו שהם עומדים לקבל התקף לב, מכיוון שלאחד ההורים שלהם יש עבר כזה. הם הרגישו שהלב לא עומד במעמסה ושההתקף הוא רק עניין של זמן קצר מאוד. כמובן, שלאחר תהליך אישי רציני, הם הבינו שזה לא כך, הם שינו את אמונותיהם בנוגע לנושא התורשה, ואכן הם המשיכו לחיות חיי בריאות ואושר עד עצם היום הזה. מה שמעניין הוא, שאותם אנשים החליטו להתרחק מההורים, מכיוון שסגנון החשיבה של ההורים לא התאים להם. הם שמרו איתם על קשר טלפוני וביקורים לעתים רחוקות (מכיוון שהוריהם לא היו מוכנים לוותר על סגנון הדיבור הישן שלהם).\n\nהיתה לי לקוחה שלאמה היו כאבי ברך כרוניים. אמרו לה שזה תורשתי. ואכן, גם היא קיבלה את אותם כאבים, באותה הברך. לאחר תהליך מעמיק, היא שינתה את אמונותיה לגבי מצבה, ואכן הכאב נעלם.\n\n3. מכיוון שבאופן טבעי הילדים, או חלק מהם, מתחברים לאחד ההורים (בתת המודע שלהם. הם לא מודעים לכך), נוצר מצב שבו הם מעתיקים מאותו הורה התנהגויות ומחשבות מסוימות. אני מדגישה: כל התהליך הזה מתהווה בתת המודע של הילד, ומוטבע לכל חייו (אלא אם כן הוא עובר תהליכי שינוי בתת המודע). כמובן, שבטעות אנשים קוראים לזה תורשתי.\n\nדוגמאות מהחיים:\n\n1. משפחה (ישראלית) שבה אבי המשפחה חלה בסרטן. לאחר מכן שלושת ילדיו חלו בזה גם כן. לאחר מכן האמא גם חלתה במחלה. נשאלת השאלה: מה הקשר בין האמא לאבא? מקרי? אז בואו נעבור לדוגמה הבאה:\n\n2. משפחה אמריקאית שהאבא ושלושה מילדיו (מתוך ארבעה) חלו בסרטן. הילד הרביעי לא חי איתם מילדות. כמובן שהילד הרביעי לא חלה במחלה.\n\n3. משפחה אמריקאית, שהיו להם 3 ילדים וילד אחד מאומץ. גם במשפחה זו האבא חלה במחלה, וגם ארבעת ילדיו (כולל הילד המאומץ).\n\n4. בחור אמריקאי שחלה בסרטן ואמרו לו שנשאר לו מעט זמן לחיות, מכיון שהסרטן התפשט כמעט לכל גופו. במקרה, הבחור ראה בעיתון מודעה על תרופה חדשה ויעילה, אך יקרה מאוד. הבחור כל כך רצה לחיות שהצליח להשיג את סכום הכסף עבור התרופה. לאחר זמן קצר, הסרטן נעלם לגמרי מגופו (הוא עבר כמה בדיקות מכיוון שהיה קשה מאוד להאמין לתופעה). כל הבדיקות הראו שהסרטן נעלם. לאחר זמן מה הוא קיבל מכתב מחברת התרופות (שלא שמעה על המקרה שלו) וכתבה לו: \"לצערנו הרב גילינו שהתרופה אינה עוזרת. אנו מתנצלים על כך\". לאחר שבועיים הסרטן חזר לגופו והוא מת.\n\nקיימים מקרים רבים וחמורים מאוד. אני לא רוצה להזכיר אותם כאן. אם היו מקרים בודדים כאלה, עוד אפשר היה להטיל ספק בדבר. אבל כאשר קיים תיעוד של מקרים רבים מאוד, כבר ברור לחלוטין: אופי מחשבתי מאומץ על ידי הילדים (או חלקם), וזה כולל מחלות.\n\nוזו ההזדמנות להזהיר אנשים שכותבים שירים על מוות, או אוהבים להקשיב לשירים על מוות: תעשו טובה לעצמכם (ולילדים שלכם ולקרוביכם): תכתבו רק שירים שמחים ואופטימיים. תקשיבו רק לשירים שמחים ואופטימיים.\n\nכאן אעבור לדוגמה נוספת ואגלה קצת על עצמי:\n\nאני עברתי טרנספומציה רצינית במצב בריאותי. בעבר מצבי הבריאותי היה רע מאוד. עברתי אפילו כמה ניתוחים רציניים. והיתה הרגשה שהסוף מתקרב. ברגע שהבנתי שמחלות נוצרות כתוצאה ממחשבות שליליות, עבדתי על עצמי בקצב מסחרר. ואני יכולה להגיד בבטחון מלא: מאז ועד היום אני בריאה לחלוטין:)\n\nואמשיך להיות:):):)\n\nניפגש במאמר הבא: תפקידיו של תת המודע - חלק 6\n\nאני מאחלת לכולכם בריאות שלמה!!!\n\nעדנה מימון / טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: להציל את הזוגיות. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע-6", "title": "תפקידו של תת המודע - חלק 6", "category": "תת מודע", "date": "", "excerpt": "תת המודע נחשב לממלכת הרגשות. זאת אומרת, הוא אחראי על כל הרגשות שלנו - חיוביים ושליליים.", "content": "תת המודע ורגשות\n\nתת המודע נחשב לממלכת הרגשות. זאת אומרת, הוא אחראי על כל הרגשות שלנו - חיוביים ושליליים.\n\nהיות שכבר אמרנו שכדי להגן עלינו הוא מדחיק זכרונות של רגשות לא פתורים, הוא גם מאפשר גישה לרגשות מודחקים לחזור לזכרון כדי לפתור אותם ולהעלימם (את זה עושים באימון אישי בשיטת NLP וטכניקות קו הזמן).\n\nיחד עם זאת, יש לזכור כי לעתים תת המודע יעדיף להשאיר את הרגשות המודחקים למטרת הגנה. זה קורה כאשר לבן אדם יש עבר קשה מאוד, שאם הוא ייזכר בזכרונות מסוימים, זה עלול להשפיע עליו קשות. לכן, מתוך הגנה, תת המודע עשוי לבחור להשאיר את מה שהדחיק באותו מצב.\n\nהדבר שונה ממצב למצב ומאדם לאדם.\n\nלעתים, כאשר פותרים רגש שלילי כלשהו, עלול לצוף רגש שלילי אחר, שהיה מודחק עמוק בזיכרון. היתרון של זה הוא האפשרות לנקות גם את הרגש הזה.\n\nלכן, מומלץ מאוד לטפל ברגשות שליליים. כל רגש שלילי יוצר התנהגות אוטומטית. זאת אומרת: התנהגות שלא בשליטתנו (כל מה שבשליטת תת המודע אינו בשליטת המודע).\n\nניקוי רגשות שליליים יוצר תחושת רוגע, שלוה, שמחה וחוסן נפשי.\n\nהדבר חשוב כפליים למי שיש ילדים, מכיוון שלילדים יש נטיה להעתיק את תחושותיהם והתנהגויותיהם של הוריהם (כולל בעיות בריאותיות למיניהן - בעיקר כרוניות).\n\nניפגש במאמר הבא: תפקידיו של תת המודע - חלק 7\n\nעדנה מימון / טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: להציל את הזוגיות. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות.\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע-7", "title": "תפקידיו של תת המודע - חלק 7", "category": "תת מודע", "date": "", "excerpt": "דבר נוסף וחשוב שכדאי לדעת על תת המודע הוא שתת המודע הוא מוסרי מאוד.זאת אומרת, הוא תמיד יתן לכם את האמת.", "content": "תת המודע והאמת\n\nדבר נוסף וחשוב שכדאי לדעת על תת המודע הוא שתת המודע הוא מוסרי מאוד.\n\nזאת אומרת, הוא תמיד יתן לכם את האמת.\n\nלדוגמה: אם הרגשתם כעסים כלפי מישהו (למשל בזוגיות), ולאחר מכן אמרתם לעצמכם: \"טוב, אני סולח לו\" - אבל בתוככם פנימה לא באמת התכוונתם לזה - תוכלו לבדוק זאת על ידי שתעצמו עיניים ותשאלו את עצמכם: \"האם אני באמת סולח לו?\"\n\nהתשובה האמיתית תעלה מיידית. זו התשובה מתת המודע.\n\nיחד עם זאת, זה המקום להזהיר: אם תשאלו שאלות לגבי העתיד, כגון: \"האם אני אמצא זוגיות?\" התשובה שתקבלו היא התשובה שלכם בלבד. זאת אומרת: זו איננה האמת האובייקטיבית. זו האמת שלכם בלבד, מתוך הניסיון שלכם, מתוך האמונות שלכם לגבי מציאת זוגיות, מתוך הרצון האמיתי שלכם וכו'.\n\nבמציאת זוגיות, למשל, חשוב מאוד להביא בחשבון קונפליקטים פנימיים. לדוגמה: יכול להיות שאדם מעוניין בזוגיות, אך הוא גם מעוניין בחופש. במידה שהוא מאמין שזוגיות פוגעת בחופש, הוא עלול למצוא את עצמו ללא זוגיות. אנשים שלא מוצאים זוגיות, מומלץ שיעברו תהליך אימון אישי כדי לנקות קונפליקטים ואמונות מגבילות.\n\nונחזור לנושא תת המודע והמוסריות:\n\nניקח לדוגמה אדם שגונב. מכיוון שבתת המודע שלו הוא יודע שאסור לגנוב (מסיבה זו הוא עושה את פעולת הגניבה בהסתר) הוא ממציא לעצמו תירוצים רציונליים ומאוד משכנעים שהגניבה הספציפית היא מותרת. דוגמה נפוצה לכך היא רובין הוד. רובין הוד גנב מעשירים וחילק לעניים. הוא אפילו נתפס כגיבור, מכיוון שלמרות הגניבה, הוא לא לקח את זה לעצמו, אלא חילק לעניים. יחד עם זאת, חשוב מאוד לציין שגניבה היא גניבה. במקרה של רובין הוד, אם הוא ישאל את תת המודע שלו האם הוא גנב (אחד שגונב), יכול להיות שתת המודע שלו יגיד לו \"לא\" (במידה שהוא לגמרי מאמין במעשהו כמעשה חיובי), ויכול להיות שתת המודע שלו יגיד לו \"כן\" (במידה שיש לו ספק הכי קטן בחיוביות מעשהו). בכל מקרה הוא יקבל את התשובה האמיתית שלו.\n\nנסו על עצמכם:\n\nתחשבו על שיחה כלשהי שהיתה לכם עם מישהו, ובשיחה זו התרגזתם או נפגעתם ולכן חשבתם שאותו בן אדם חוצפן, או חסר אחריות, או טיפש וכו'.\n\nעכשיו שבו בנוח בסביבה שקטה, תעצמו עיניים ותשאלו את תת המודע שלכם: האם האדם הזה באמת כזה, או שאמרתם את מה שאמרתם מתוך חוסר נכונות להתמודד עם מה שששמעתם?\n\nהתשובה שתעלה לכם היא התשובה האמיתית שלכם.\n\nניפגש במאמר הבא: תפקידיו של תת המודע - חלק 8\n\nעדנה מימון / טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: להציל את הזוגיות. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות.\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע-8", "title": "תפקידיו של תת המודע - חלק 8", "category": "תת מודע", "date": "", "excerpt": "אחד המאפיינים הבולטים של תת המודע מזכיר מאוד את איפיוניו של ידידו הטוב ביותר של האדם: הכלב. כן. הכלב.\nבדיוק כמו שהכלב נאמן לבעליו ומשרת אותו במסירות רבה, כך גם תת המודע.", "content": "תת המודע והדיבור הפנימי\n\nאחד המאפיינים הבולטים של תת המודע מזכיר מאוד את איפיוניו של ידידו הטוב ביותר של האדם: הכלב. כן. הכלב.\n\nבדיוק כמו שהכלב נאמן לבעליו ומשרת אותו במסירות רבה, כך גם תת המודע.\n\nתת המודע מקשיב כל הזמן לדיבור הפנימי שלנו.\n\nבן אדם שאומר על עצמו שהוא לא שווה - תת המודע יוכיח לו שהוא לא שווה. באותה מידה, אם בן אדם חושב שהוא שווה - תת המודע יוכיח לו שהוא שווה. זאת אומרת: כל מה שאנחנו מאמינם בו באמת ובתמים - תת המודע יתן לנו הוכחות שזה נכון. וכל מה שאנחנו לא מאמינים בו - גם כן תת המודע יתן לנו הוכחות שצדקנו.\n\nכמו כן, בן אדם שמאמין שהוא יודע הכל, ואף אחד לא ילמד אותו משהו חדש, זה מה שיקרה. הוא לא ילמד. אנשים שיש להם נטיה לקרוא משהו ולהגיד: \"את זה ידעתי כבר. לא חידשו לי\", כדאי שישנו את הגישה הזאת. ובמקום זה להגיד: \"חלק מזה ידעתי, ובכל זאת הספר חידש לי כמה דברים\".\n\nבזוגיות קורה הרבה שאחד מבני הזוג אומר על השני: \"הוא כזה\", או: \"הוא חושב כך וכך\", וכשאני שואלת את הבן/בת זוג אם הוא/היא באמת חושב/ת כך, הוא אומר: \"לא. אני לא חושב/ת כך\".\n\nקורה לכם שאתם אומרים: \"אבל זה באמת ככה\", או: \"אני בכלל לא חשבתי שזה נכון, אבל במציאות ראיתי הוכחות שזה נכון\" או: \"קודם זה קרה, ורק אח\"כ האמנתי שזה כך\" וכו'...,\n\nהרבה פעמים אנחנו לא מודעים לאמונות שיש לנו בתת המודע. לעתים, מספיק שזה קורה פעם אחת, אנחנו כבר יוצרים אמונה לגבי אותה סיטואציה.\n\nלדוגמה, גבר שחושב ש\"נשים לא יכולות להיות חברות אמיתיות, כי הן מקנאות אחת בשניה. זה בטבע שלהן\".\n\nאני מניחה שחלק מקוראי המאמר מאמינים באמונה זו, והם אף \"יוכיחו\" לי שזה אכן נכון. ברצון רב ובקלות הם יתנו לי דוגמאות רבות ש\"מוכיחות\" שהאמונה נכונה.\n\nאם כן, תשאלו: מה הבעיה עם זה? הוא הוכיח שזה נכון, אז זה נכון. הוא לא משקר.\n\nתשובתי היא: נכון שהוא לא משקר. יחד עם זאת, ההתמקדות שלו היתה במקרים שמתאימים לאמונה שלו, ולכן, תת המודע - בהיותו נאמן לבעליו - הגן עליו ו\"הוכיח\" לו שהוא צדק. וכך, אותו גבר משמיט כל הוכחה שמנוגדת לאמונתו. זאת אומרת, גם אם לנגד עיניו הוא יראה נשים עם אחווה וחברות אמיתית, הוא יגיד לעצמו שזה רק מבחוץ, והאמת עוד תצא לאור ביום מן הימים....\n\nמנגד, במידה שאותו גבר ישנה את אמונתו הנוכחית ותהיה לו אמונה חדשה כמו: \"לנשים יש אחוות נשים והן מגוננות אחת על השניה\", לפתע יקבל הוכחות (בעזרתו האדיבה של תת המודע הנאמן והמסור) שמוכיחות שהוא צדק.\n\nתשאלו אותי: אז מי צודק? הרי מתוארות פה שתי אמונות מנוגדות, ובכל אחת מהאמונות תת המודע מגן על בעליו ומוכיח לו שהוא צדק?\n\nהתשובה היא: אין צודק או לא צודק. הרי תת המודע בכל מקרה יוכיח לבעליו שהוא צודק.\n\nאז מה עושים? מפחיד....\n\nהתשובה פשוטה:\n\nתשאלו את עצמכם באיזו אמונה עדיף לכם להאמין? איזו אמונה תיטיב עימכם? איזו אמונה תעשה לכם חיים יותר טובים? איזו אמונה תשפיע לטובה על מערכות היחסים שלכם? איזו אמונה תיתן לכם יותר שקט פנימי? איזו אמונה תגרום לכם לחייך יותר? איזו אמונה תיצור לכם את המציאות שאתם רוצים? איזו אמונה תחנך את ילדיכם יותר טוב? האם הייתם רוצים שלבתכם יהיה אבא (או אמא) שמאמין באמונה הראשונה? או השניה?\n\nזכרו: המציאות שלכם היא תוצאה של האמונות שלכם.\n\nלמען ההגינות, ניתן דוגמה של נשים בנוגע לגברים: יש נשים שמאמינות שכל הגברים בוגדים. כמובן שאמונה זו אינה נכונה. זו אמונה מגבילה. יחד עם זאת, אם תשאלו אישה שמאמינה בזה, היא תוכיח לכם בקלות רבה שזה נכון. עובדה: כל הגברים שהיו בחייה בגדו בה. אותה אישה יצרה לעצמה את המציאות הזאת כתוצאה מהאמונה שיש לה.\n\nכדאי שאותה אישה תשאל את עצמה: האם היא מאמינה שהבן שלה יבגוד באישתו? האם היא העבירה אמונה זו לבת שלה?\n\nולפני סיום, בואו נעשה בדיקה קטנה:\n\nתענו בבקשה על השאלה הבאה: האם נשים יודעות לנהוג טוב?\n\nניפגש במאמר הבא: תפקידיו של תת המודע - חלק 9\n\nעדנה מימון / טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: להציל את הזוגיות. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות.\n\n050-7378535"}, {"slug": "תפקידיו-של-תת-המודע-9", "title": "תפקידיו של תת המודע - חלק 9", "category": "תת מודע", "date": "", "excerpt": "אשר יודעים איך תת המודע פועל, ניתן ליצור שינויים מדהימים גם בתחושות וגם בהתנהגויות.תפקידים נוספים של תת המודע:", "content": "תת המודע ואנרגיה\n\nכאשר יודעים איך תת המודע פועל, ניתן ליצור שינויים מדהימים גם בתחושות וגם בהתנהגויות.\n\nתפקידים נוספים של תת המודע:\n\nתת המודע מייצר אנרגיה, מאחסן אנרגיה, מחלק אותה בין כל חלקי הגוף והנפש, ומשדר אותה אל מחוץ לגוף.\n\nכל הרגשות שלנו מלווים באנרגיה. המילים שלנו מלוות באנרגיה. למשל, תחשבו על סיטואציה שבה כעסתם. תהיו ערים לתחושה ולאנרגיה שהמילה יצרה אצלכם. עכשיו תחשבו על סיטואציה שבה אהבתם. התחושה והאנרגיה שונות.\n\nהאנרגיה משודרת כלפי חוץ גם ללא דיבור בקול. זאת אומרת: לעתים אנו מדברים לעצמנו, אך לא מבטאים את המילים בקול. זה מלווה באנרגיה (הכוללת את שפת הגוף). אנרגיה זו משודרת הלאה לאחרים, ולכן אחרים יכולים לנחש שהאדם שמולם חושב מחשבה שלילית או חיובית. לניחוש הזה קוראים אינטואיציה.\n\nחשוב לציין שכאשר אנשים חושבים מחשבות שליליות, הם משתמשים בהרבה אנרגיה שלילית (כמובן שזה על חשבון החיובית), ולכן האנרגיה הזאת הופכת להיות הרסנית. ההרס מתבטא גם בחיים קשים, בתקיעות וגם בבריאות לקויה (כאבים בעמוד השדרה, שפעת, גב תפוס או כל איבר אחר תפוס, לחץ דם, מחלות וכו').\n\nמבחינת תת המודע, אין זה משנה לגבי מי יש לכם מחשבה שלילית. מספיק שהיא קיימת. וגם אין זה משנה אם היא מוצדקת או לא. מספיק שהיא קיימת.\n\nזאת אומרת: גם אם מישהו עשה לכם משהו רע, לא כדאי לנטור לו טינה, כי זה עלול להשפיע עליכם לרעה. מומלץ מאוד לסלוח לו/לה למענכם!!!!\n\nבזוגיות: אם אתם מתלוננים הרבה כלפי בן/בת הזוג שהוא לא מתחשב/ת, כדאי שתבדקו את עצמכם. תבדקו היכן אתם עצמכם לא מתחשבים.\n\nאם מישהו מדבר אליכם לא יפה, תשאלו את עצמכם איך יצרתם את המציאות הזאת? היכן העלמתם עין? תשנו את המציאות לטובה.\n\nתקשיבו יותר לתחושות הבטן שלכם. במידה שתחושות הבטן שלכם הטעו אתכם - תהיו יותר עירניים לעצמכם ולסביבה. תחדדו את החושים שלכם.\n\nאם יש לכם קשיים בחיים, תשאלו את עצמכם: אלו מחשבות שליליות רצות לכם בראש? ותחליפו אותן במחשבות חיוביות. כך תוכלו לקדם את עצמכם בחיים (כולל מערכות יחסים וכולל קריירה).\n\nאם אתם חושבים במונחים של \"צדק\" או \"אשמה\", כדאי שתוותרו עליהם למען קידום ושיפור מערכות היחסים שלכם ובעיקר בטיפול בזוגיות שלכם.\n\nתעשו את זה בשבילכם ובשביל הבריאות שלכם.\n\nכי הכל בא עם אנרגיה. והאנרגיה משפיעה על הכל. נשאלת השאלה: איזו אנרגיה אתם מעדיפים?\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: להציל את הזוגיות. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות.\n\n050-7378535\n\nמי שעוד לא קרא את המאמר: כוחו ועוצמתו של תת המודע - מומלץ מאוד שיקרא עכשיו"}, {"slug": "תקשורת-בינאישית-או-תקצורת", "title": "תקשורת בינאישית", "category": "תקשורת", "date": "", "excerpt": "מטרת מאמר זה היא לתת לכם הקוראים דוגמאות על הקלות הבלתי נסבלת שבה לפעמים אנחנו פוגעים באחרים. עוד על תקשורת בינאישית", "content": "מטרת המאמר הזה היא לתת לכם הקוראים דוגמאות על הקלות הבלתי נסבלת שבה לפעמים אנחנו פוגעים באחרים, בסובבים אותנו ו/או יוצרים מריבות על לא עוול בכפם של האחרים. כל זאת ללא מודעותנו וללא מחשבה קצת מעבר לדפוסי החשיבה הרגילים שלנו.\n\nקורה הרבה שאנחנו חושבים משהו שלילי על מישהו, כאשר אנחנו בטוחים שאנו צודקים. אך אם נתעמק במחשבה באמת נגלה שגם אנחנו יכולים לטעות. ולכן, לא כדאי להתחפר כל כך בעמדות שלנו (כאשר הן שליליות).\n\nהנה כמה דוגמאות הממחישות את זה. המקרים הם אמיתיים.\n\nבחורף האחרון, בדרכי חזרה מהשתלמות בארה\"ב היתה לי טיסת קונקשן בגרמניה. כשנחתנו בגרמניה התברר שאין טיסות יוצאות מפאת מזג האויר הקשה. חיכינו בתור 7 שעות!!!! כדי לקבל כרטיסים חדשים. לאחר 4 שעות של עמידה על הרגליים, סוף סוף השגתי כסא וישבתי. האנחה שנשמעה מגרוני היתה משמעותית מאוד.\n\nבדיוק אז שמעתי מישהי מאחורי אומרת את המשפט הבא (באנגלית כמובן): \"היום לאנשים אין ערכים. הם לא מכבדים את המבוגרים מהם. הם חושבים רק על עצמם\".\n\nהיתה לי תחושה שהיא מתכוונת לעובדה שישבתי על הכסא במקום לתת אותו לחברתה שעמדה לידה. הסתובבתי לאחור, הסתכלתי על שתיהן ואמרתי לה: \"אם התכוונת אלי, אני לא רואה מישהו בסביבה פה שהוא יותר מבוגר ממני. שתיכן צעירות ממני בכמה שנים טובות\".\n\nלפתע שתיהן פרצו בצחוק רועם כאילו לומר: \"יש דברים ברורים שרק טיפשים לא רואים אותם\". למזלי, אני מאמנת אישית ומנחה סדנאות לשליטה בכעסים וגם לחיזוק הביטחון העצמי. כך שדבריה לא הכעיסו אתי ולא גרמו לי לחוסר ביטחון. למעשה, אני דיברתי בבדיחות הדעת. ביקשתי משתיהן להוציא תעודות זהות. אני הוצאתי את התעודה שלי והשוונו.\n\nמתברר שחברתה ה\"מבוגרת\" היתה צעירה ממני ב-9 שנים!\n\nמצד אחד זה מחמיא לי שאני נראית פחות מגילי האמיתי. מצד שני יש גם מקרים כאלה. וזה לא נעים.\n\nמקרים שבהם אנשים בטוחים בדעותיהם וכועסים על אחרים, קורים הרבה בכביש. הנה דוגמה: לפני כחצי שנה נסעתי בתוך העיר כאשר ילד כבן 11 רצה לחצות את הכביש במעבר חציה. אני עצרתי כדי לאפשר לו לחצות. מאחורי נסע בחור שהתעצבן על שעצרתי (הוא לא ראה את הילד, וכנראה לא ידע שיש שם מעבר חציה). הוא עשה לעברי תנועה של כעס וניסה לעקוף אותי במהירות. כשראה את הילד הוא בלם ברגע האחרון. הילד נבהל מאוד. למרבה המזל הוא ניצל.\n\nעל מקרה נוסף שמעתי מפי חברתי. היא נסעה באוטובוס וישבה במושב האחורי. ראשה היה עמוס במחשבות מלחיצות. כל הנסיעה היא היתה מרוכזת בטרדותיה הרבות.\n\nכאשר התכוננה לרדת מהאוטובוס הסתכל עליה בחור שישב לידה ואמר בזילזול: \"היום כל הבחורות סנוביות. אפילו על שאלה פשוטה לא נאה להן לענות\". מסתבר שהוא שאל אותה שאלה (כמה פעמים) והיא אפילו לא שמעה אותו בגלל הרעשים הפנימיים שלה.\n\nב-NLP קיימת הנחת יסוד שאומרת: \"המפה איננה השטח. היא רק מפה, ייצוג סימבולי של השטח\".\n\nויש להוסיף לזאת כי: אין בעולם שתי מפות שהן שוות.\n\nזאת אומרת: בראשו של כל אחד מבני האדם בעולם יש מפת עולם שהיא יחודית לו, ואין שניה לה. לכל אחד יש את צורת החשיבה היחודית שלו , את דפוסי החשיבה היחודיים שלו, את האמונות שלו, הערכים שלו, ניסיון העבר שלו וכו'. וכל אחד מגיב מתוך מפת העולם שלו שיש לו בראש ולא מתוך השטח (המציאות).\n\nמה המסקנה?\n\nגם אם אתם בטוחים במשהו, שבעטיו אתם כועסים, תחשבו שוב! כדאי לבדוק את הנושא עד תום.\n\nאולי בכל זאת אתם לא מעורים בכל הפרטים. וכשתרכיבו את כל חלקי הפאזל, התמונה שתתגלה יכולה להיות שונה ממה שחשבתם בהתחלה.\n\nוכך תוכלו למנוע תקצורת ולחיות מתוך תקשורת מקרבת. כי תקשורת בינאישית מקרבת יכולה לשנות לחלוטין את המציאות של כל אחד.\n\nעדנה מימון\n\nטריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, מאמנת אישית להעלמת רגשות שליליים והעלמת טראומות, פחדים, חרדות, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות, סדנאות לביטחון עצמי, מורה מוסמכת ל NLP\n\n050-7378535\n\nרוצים ללמוד NLP Practitioner בראשון לציון?\n\nרוצים לדעת איך לייצר מציאות כמו שאתם רוצים?\n\nלחצו כאן לפרטים\n\nלקריאה מהבלוג, על הקשר בין קשיי קשב וריכוז לכעסים"}, {"slug": "למי-כדאי-לקחת-אימון-אישי-או-סדנה", "title": "למי כדאי לקחת אימון אישי או סדנה", "category": "אימון אישי", "date": "", "excerpt": "למה כדאי לכל אחד מאיתנו לעבור חוויה של אימון אישי או סדנה — ולמה זה לא סימן שמשהו 'לא בסדר'.", "content": "אנשים רבים חושבים שאם הם יגידו שהם רוצים אימון אישי או סדנה, אזי הם מודים שמשהו אצלם לא בסדר, שכביכול הם \"מקולקלים\", או \"פסיכים\", או \"מטורפים\", או \"לא נורמליים\", ועוד אמונות שגובלות בבורות רבה. מסיבה זו, הם לא פונים לקבל עזרה. ואם הם לא פונים לקבל עזרה, משמע הם \"בסדר\", הם \"נורמליים\". אנשים אלה הם אנשים לא מאושרים. הם חיים בפחדים.\n\nלעתים קרובות אני שומעת את המשפט: \"אימון אישי? סדנה? מה הבעיה? אני אתן לך\".\n\nאני מניחה כי אתם מחייכים כרגע, מכיוון שכבר שמעתם את המשפט הזה.\n\nובכן, הבה נעשה סדר בדברים:\n\nאילו שאלו אותי, הייתי אומרת כי מומלץ שכל אחד מאיתנו יעבור חוויה ששמה אימון אישי או סדנה.\n\nדמיינו לעצמכם עולם שבו כל אינדיבידואל עבר תהליך אימון אישי רציני. מה היינו מקבלים?\n\nהיינו מקבלים עולם, אשר בו אנשים יותר רגועים, יותר סבלניים אחד כלפי השני, יותר מצליחים, יותר מאושרים, בעלי תקשורת בין אישית מוצלחת מאוד, בעלי זוגיות עמידה ומאושרת, בעלי יכולת לגדל ילדים בריאים ומאושרים. הפשע היה נעלם. המלחמות היו הופכות להיסטוריה רחוקה. אנשים היו קוראים את ספרי ההיסטוריה ולא היו מאמינים שפעם אנשים הרגו זה את זה. בקיצור, אנשים היו בריאים יותר אילו קיבלו אימון אישי או סדנה. אני עצמי מהווה דוגמה מצויינת לכך, ואני גאה מאוד על כך.\n\nאומנם, אימון אישי או סדנה מכוונים להשגת מטרות, אך קיימת מטרת-על אחת, המשותפת לכולנו, והיא להיות מאושרים אהובים ורגועים.\n\nאדם לא מאושר הוא אדם סובל. אדם סובל מקרין זאת על סביבתו. סביבתו יכולה להיות משפחתו הקרובה, חבריו, עבודתו, או כל מקום אחר, אשר אליו הוא מגיע . אותו אדם, יקרין את תחושת הסבל לילדיו ולכל הסובבים אותו. מסיבה זו, גם ילדיו ימשיכו את מעגל הסבל.\n\nשמעתי על אנשים, אשר מעידים על עצמם: \"אני מאושר\", אבל אני רואה עליהם שהדבר\n\nאינו כך. הם משקרים לעצמם.\n\nאדם המעשן, שותה ומחליף בחורות כמו גרביים, לא יכול להיות מאושר - גם אם הוא מצהיר שהוא מאושר. כבר שמעתי על אנשים כאלה, אך הם מתו בגיל צעיר. הם מתו מריקנות. הם מתו ממחסור באושר. הם מתו כי התביישו להודות אפילו בפני עצמם כי הם לא מאושרים. הם מתו מבושה.\n\nשוחחתי עם נשים, אשר סיפרו לי כי הן מאושרות, אך באותה נשימה התגאו על כך כי הן קונות כמויות אדירות של בגדים, ושזה מביא להן אושר רב. הן לא ידעו כי, קניות מטורפות מצביעות על אי שביעות רצון מן החיים, על רעב לאהבה ועל הערכה עצמית נמוכה.\n\nנשים אחרות סיפרו שהן מאושרות, אך באותה הזדמנות סיפרו שיותר מדי פעמים הן נפגעו מאוד מאנשים מסויימים. הן לא ידעו כי פגיעות יתר מצביעה על חסמים כבדים.\n\nומה לגבי אנשים, המשקיעים את מיטב כספם בשיפוץ הבית, אך בפנים הם כועסים כמעט על כל העולם? האם לא היה עדיף להשקיע חלק מהכסף על אימון או סדנה לשליטה בכעסים? או בשיפור הזוגיות? או בשיפור הביטחון העצמי והדימוי העצמי? הרי קירות לא יכולים להביא אושר!\n\nישנם אנשים המשקיעים כסף רב בטיולים יקרים, אך תמיד חוזרים מהטיול מלאים בכעסים על בן/בת הזוג, על הילדים או על חברים שהשתתפו בטיול. כאן, שוב עולה השאלה: האם לא היה עדיף לקחת אימון אישי במקום אחד הטיולים, כדי ללמוד הקשבה אמיתית ותקשורת בין אישית?\n\nגם אנשים בעלי רגש של נקמה יעשו טוב לעצמם אם יקחו אימון אישי. הנקמה היא דבר הרסני מאוד. היא הורסת קודם כל את האדם הרוצה לנקום. היא גם הורסת את סביבתו הקרובה. מישהו כבר אמר כי אדם כועס משול לאדם המוזג רעל, אך שותה אותו בעצמו.\n\nאם שמעתם את עצמכם אומרים את המשפט: \"הראתי לו (הראתי לה) מה זה\", או \"מגיע לו (מגיע לה)\", או \"כולם רמאים...\", \"כולם חושבים על כסף\", פנקו את עצמכם באימון אישי או סדנה על מנת להבין ממה זה נובע, ומה זה גורם לכם.\n\nאנשים המקללים או צועקים בפקקים, בתור לקופת חולים, בתור בסופר, או בכל מקום אחר, ירוויחו מאימון אישי.\n\nאנשים המרגישים שאחרים טובים יותר מהם, יפים יותר מהם ומוכשרים יותר מהם, או שחשוב להם מה יגידו אחרים, או שחוששים מתגובותיהם של אחרים, יגלו עולם חדש ויפה בעזרת אימון אישי.\n\nאנשים שקשה להם למצוא כיוון בחיים. אנשים שלא מוצאים עניין בחיים, שרוצים לעזוב עבודה, או להיות עצמאיים, אך חוששים. פעמים רבות, אנשים המוצאים תמיד הסברים \"משכנעים\" למה לא כדאי להתחיל משהו חדש, אלה אנשים עם מטרות נמוכות מדי, אנשים אשר אינם מעיזים לחשוב רחוק, או תקועים מחשבתית. אימון אישי או סדנה יכולים לעשות להם פלאים.\n\nאנשים שהסטטוס חשוב להם מאוד (כמו מכונית יקרה, עבודה במקום \"נחשב\", מגורים באזור יוקרתי, בגדים יוקרתיים וכו'), אך עדיין לא חשים את האושר.\n\nאנשים המרגישים לחוצים, המרגישים שאין להם יכולת לעשות כלום (למרות שיש הרבה מה לעשות). אנשים המנקים בית באופן מוגזם, אנשים המקפידים על סדר באופן מוגזם (המרגישים שמראה הבית יותר חשוב מהשגת אושר), אנשים החושבים הרבה על חיידקים.\n\nאנשים בעלי משקל יתר, או אנשים הנלחמים במשקל בקביעות.\n\nבאימון אישי קצר, אנשים פרפקציוניסטים יוכלו לגלות על עצמם דברים שלא חשבו עליהם קודם.\n\nאנשים שחשוב להם לרצות את האחרים. אנשים המקבלים כל מה שאחרים אומרים להם על מנת לקבל שקט. זהו שקט שקרי. זהו שקט תעשייתי. מנגד, גם אנשים שמתנגדים כמעט לכל דבר ירגישו טוב יותר עם עצמם ורגועים יותר, לאחר אימון אישי.\n\nאנשים המחמיאים לעצמם בחברה ללא הרף, ירוויחו מאימון אישי קצר או מסדנה.\n\nהקשבה אמפטית חסרה להמון אנשים. הרבה פעמים אני שומעת את המשפט: \"הקשבתי, אבל אני לא מסכים עם דבריו\". הקשבה אין פירושה הסכמה. הקשבה היא הבנה מדוע האדם אמר את מה שאמר, מה מסתתר מאחורי מה שהוא אמר וכו'.\n\nאנשים רבים מתגאים במשפט: \"אצלי זה הכל או לא כלום\"! קיצוניות לכאן או לכאן אינה בריאה ואינה מביאה אושר. גם התנהגות אימפולסיבית מקשה על החיים.\n\nדאגנות יתר הינה חסם רגשי עמוק. בדרך כלל אנשים דאגניים הם גם חסרי ביטחון וגם אינם מצליחים להאציל סמכויות לילדיהם או למי שנמצא תחת מרותם. ילדים להורים כאלה יכולים לאגור תסכולים רבים.\n\nמכירים את המשפט: \"אם הוא לא היה עושה לי את מה שעשה לי, היום הייתי מאושר\"? אנשים רבים מאשימים אחרים בחוסר אושר שלהם, בחוסר השגת מטרותיהם. לעתים קרובות מאשימים את ההורים, לעתים את המדינה, או את הבוס ועוד. אנשים אלה יוכלו לקבל כלים משמעותיים להשגת האושר באימון אישי או בסדנה.\n\nהורים רבים עושים אין ספור טעויות בחינוך ילדיהם. הילדים סוחבים את טעויות הוריהם כל חייהם. הם גדלים לא מאושרים. אותם הורים חושבים כי הדבר טבעי. לא ברור מדוע ילד לא מאושר זה דבר טבעי? הורים רבים טוענים: \"אני נתתי לו הכל, וזה מה שאני מקבל\". זוהי עוד טעות חמורה בחינוך. ילד לא מאושר יגדל להיות הורה לא מאושר וגם יעביר זאת הלאה לילדיו.\n\nהורים מסוימים מתלוננים שהילד שלהם משקר. כדאי שהורים יבינו כי ילד משקר הוא ילד שקשה לו. הוא נאלץ לשקר. מומלץ שהורים לילד כזה יקחו אימון אישי, או סדנה. זאת מכיוון שיש להם השפעה לא מודעת על שקריו של הילד.\n\nהורים המתלוננים שילדם אינו אחראי, מוטב שיבינו שיש להם מה ללמוד. ילד לא אחראי הוא ילד שהלא-מודע (תת מודע) שלו תיכנת אותו להיות כזה. זה ילד שקיבל הרבה ביקורת. להורים יש תפקיד חשוב ביצירת המצב הזה, ועל כן, חובתם ללמוד ליצור שינוי אצל ילד כזה.\n\nהורים מסוימים טוענים שילדם גדול מספיק כדי לקחת אחריות על חייו. הדבר אינו מדויק. אחריות אינה פועל יוצא של גיל, אלא של חוסן נפשי. שוב: גם כאן להורים יש אחריות ליצור שינוי אצל ילדם.\n\nמודעות עצמית להתנהגויותינו יכולה לשפר פלאים את תחושותינו. אך, כמובן, תחילה עלינו להיות מודעים לכך כי האושר שלנו ושל ילדינו יותר חשוב מקנייה זו או אחרת, משיפוץ בית, מטיול כלשהו, או מכל דבר אחר.\n\nחוסר אושר גורם לבעיות בריאותיות. אנשים שעברו שינוי לטובה בחייהם מדווחים על שיפור מדהים במצב בריאותם. בחור שעבר אצלי אימון אישי סיפר שהראיה שלו השתפרה מאוד, ולפתע צווארו אינו נוקשה. כל זאת, ללא שום טיפול אחר.\n\nלסיכום, אין דבר יותר חשוב מלהיות מאושר. אדם מאושר קם בבוקר עם חיוך בלב. אדם מאושר הוא אדם האוהב את עצמו ואת סביבתו. סביבתו חשה זאת ונמשכת אליו כמו מגנט. אדם מאושר רוצה לעבוד. אדם מאושר הוא אדם בריא.\n\nלמאמר: מהי שיטת NLP"}, {"slug": "ראיון-עם-מצליחן", "title": "ראיון עם מצליחן", "category": "הצלחה", "date": "", "excerpt": "ראיון מרתק עם יזם צעיר ומצליח — על אמונה, נחישות, והדרך מנקודת התחלה רגילה אל הצלחה גדולה.", "content": "תאריך ראיון: 2.5.08\n\nכשגיליתי שבעליו של אתר \"ליסטה\" רק בן 24, הרגשתי שאני חייבת לפגוש אותו ולראיין אותו, ולו רק כדי לבדוק אם הצלחתו היתה יכולה להתנבא מראש. ואכן, לא טעיתי!\n\nכשפגשתי אותו ואת חברתו-יד-ימינו ליגל, במסעדה בראשון לציון, היה לי קשה לעכל שבחור עם מראה תמים כשלו יכול להיות האדם שאני מחפשת. סקרנותי גברה עוד יותר, וניגשנו מייד לראיון. הראיון נמשך ארבע שעות וחצי, ונדמה שרק התחלנו...\n\nצבי שחר, הבעלים של אינדקס אתרים \"ליסטה\", חובק הסטוריה של הצלחות, אשר רבים רק חולמים עליהן. נדמה כי תשובותיו לשאלותי נלקחו מספר ייעוץ למצליחנים, אך אצלו זה חלק בלתי נפרד מאופיו הנוח ומחוכמתו הרבה.\n\nצבי נולד וגר בראש העין להורים רגילים, שכירים, מהמעמד הבינוני. החינוך כלל גבולות ברורים, ויחד עם זאת, כבוד לילדים.\n\nציוניו של צבי היו ממוצעים פלוס, אך כדבריו \"אילו ידעתי מה המשמעות של הציונים, הייתי משקיע יותר\". הוריו דאגו לטייל עם ילדיהם כמעט בכל העולם. לכן, טיול של אחרי הצבא לא בא בחשבון.\n\nעד כאן, הכל נשמע שיגרתי. אך, לפתע, משפט מסוים הקפיץ אותי כמוצאת שלל רב: \"תמיד סחבתי איתי מחברת שכתבתי בה רעיונות. בנסיעותי הרבות בצבא חשבתי הרבה, ורשמתי כל מה שעלה לי לראש. העדפתי את זה על פני מוזיקה\".\n\n\"יש!\", חשבתי לעצמי בתחושת ניצחון. \"ברור שיצליח. הרי הוא מתנהג כמו מצליחן - אפילו ללא ידיעתו\".\n\nרעיון ראשון היה לעזוב את הצבא (קבע). החלטה קשה. מצד אחד, יש לו בצבא תפקיד מעניין וחשוב. הוא עובד באופן עצמאי.\n\nמצד שני, מה יהיה באזרחי? שכיר? לא נשמע טוב. הוא ניגש שוב למחברת והכין תוכנית. הוא נתן לעצמו חצי שנה בתור עצמאי. אם לא ילך, יעבוד כשכיר וגם ילמד. הכל תוכנן בקפדנות, בדיוק כמו תוכנית עסקית.\n\nמשנתקבלה ההחלטה, צבי עזב את הצבא וקפץ למים העמוקים של עסק עצמאי. לא היה לו מושג באיזה כיוון ללכת. לא היה לו ידע רב במחשבים (פרט להרכבת משחקים). אך לא אדם כמו צבי יוותר. הוא קנה כמה ספרי מחשבים והקמת אתרים והתחיל ללמוד על ידי ניסוי וטעייה. במסגרת אותם חיפושים לכיוון מקצועי הוא קנה עוד ספרים מתחומים שונים. את גישתו החיובית לאנשים ולכל דבר הוא משייך לספר על NLP שהוא קרא. בנוסף, הוא קרא ספרי קואוצ'ינג, ניסה מודלים תלת מימדיים, קרא על גרפולוגיה, קריאת שפת גוף, קריאת כף יד. הקים אתר מתארח, שבו לא היה צורך בידע קודם בנושא בניית אתרים. האתר נתן טיפים לבנים ובנות בנושא זוגיות.\n\nבשלב זה הוא הבין שהוא רוצה לעסוק בבניית אתרים.\n\nהאתר הראשון שבנה מההתחלה ועד הסוף נקרא lapanim.com . עד היום הוא קיים (גם באנגלית). זהו אתר המאפשר להעלות סרטים, תמונות מצגות וכו' (במקום שיתפסו מקום במחשב הביתי). צבי היה עסוק 24 שעות ביממה (בבוקר צבא קבע ובערב פיתוח ותחזוקת האתר).\n\nכצפוי, צבי פתח את מחברת הרעיונות שלו והבין שאנשים זקוקים לאתר עם לוח מודעות. שוב, הוא הכין תוכנית עסקית ו\"ליסטה\" יצא לדרך. אביו של צבי הגה את השם עבור עסק אחר, אך צבי העדיף אותו לאתר זה.\n\nמהו הערך המוסף של ליסטה?\n\n\"כל האתרים מקבלים קידום, וכל הגולשים מקבלים מידע ועידכונים על אתרים המעניינים אותם. הוא מבוסס על טכנולוגיות מאוד מתקדמות. נכון להיום, הוא במקום 300 בישראל\" (ליסטה הוקם לפני חצי שנה בלבד). אכן, הישג גדול מאוד.\n\nאדם כמו צבי אינו נח על זרי הדפנה. הוא ייסד את אתר maskorot.co.il . אשר תפס פופולריות כבר בראשית ימיו. מטרתו של האתר לתת נתונים על תנאי השכר בישראל.\n\nמהו סדר יומך?\n\n\"קם בין 9:00 ל- 10:00 - קריאת אי מיילים + עידכונים\n\nבין 11:00 ל- 12:00 - פיתוח אישי, עידכון מחברת רעיונות\n\nבין 12:00 ל- 13:30 - למידה, התמקצעות\n\nבין 13:30 ל- 15:00 - מנוחה, טלויזיה, בילוי עם אחי הצעיר\n\nבין 15:00 ל- 19:00 - פיתוח עסקי\n\nבין 19:00 ל- 20:30 - ספורט\n\nבין 20:30 ל- 23:30 - בילוי עם בת הזוג, קורא מגזינים\n\nב- 23:30 הולך לישון\n\nסדר יום שכזה אינו נותן פרנסה ליועץ עסקי, חשבתי לעצמי.\n\nיש לך תחביבים?\n\n\"ודאי. לשחק בפלייסטיישן, לטייל בארץ, לאכול במסעדות ולבלות עם חברים\".\n\nהאם אתה עובד לבד?\n\n\"חברתי ליגל עוזרת לי בניהול התוכן\".\n\nהאם ידעת שתצליח?\n\n\"תמיד ידעתי שאצליח. כשלונות הם חלק מההצלחה\".\n\nמי ההשראה שלך?\n\nבקטע הרוחני אנשי NLP , בקטע העסקי רוברט קיוסאקי\" (מחבר \"אבא עני, אבא עשיר\").\n\nמה הסוד שלך?\n\nהתמדה, אמונה, תרומה (גם לעצמי, אך בעיקר לאחרים)\".\n\nמה המוטו שלך?\n\nIf you write it, it will come\"\"\n\nתוכניות לעתיד?\n\n\"פיתוח יישומי אינטרנט המועילים למשתמשים\".\n\nהשלם בקצרה:\n\nאני אוהב...חיות, את החברה שלי ואת המשפחה.\n\nאני שונא...תבוסתנות\n\nאומרים עלי ש...אני מנהיג\n\nאני קם בבוקר עם תחושה... טובה וציפייה ליום נהדר.\n\nהחיים שלי הם...כמו טיול אחרי צבא\n\nאם תירצו...תתכננו ותשקיעו - זה יגיע.\n\nהצלחה בשבילי היא...הנאה והשגת תחושת מטרה.\n\nבעוד 20 שנה אני אהיה...מיליונר.\n\nולסיום, איזו עצה היית נותן לצעירים?\n\n\"להשקיע, להאמין, להתמיד. לאמץ גישה חיובית. זה הפתרון לכל דילמה ובעיה. כישלון הוא עוד צעד המקרב להצלחה\".\n\nאני מקווה שהצעירים יקבלו השראה מאדם מצליחן כמו צבי שחר."}, {"slug": "הסיבות-לשחיקה-בזוגיות", "title": "הסיבות לשחיקה בזוגיות", "category": "זוגיות", "date": "", "excerpt": "מה גורם לשחיקה בזוגיות, ולמה מריבות ותלונות חוזרות על עצמן — וכיצד אפשר לשנות את הדינמיקה.", "content": "\"על כן, יעזוב-איש, את-אביו, ואת-אימו, ודבק באשתו, והיו לבשר אחד\" (בראשית, פרק ב').\n\nקיימים פירושים רבים לפסוק זה. אך מיותר למנותם. הרעיון של חיים בזוגיות מובן. הוא גם מתגשם בתקופת החיזור, שבמהלכה שני בני הזוג נוטים לוותר זה לזה על אי הבנה, מתוך הנחה שיחס זה הינו זמני, ומתוך תקווה מוטעית שזה ישתנה.\n\nהבעיה מתחילה כשבני הזוג מגלים לתדהמתם כי אותה \"אי הבנה\", למעשה, באה על מנת להשאר...\n\nמה כבר לא נאמר ולא נכתב על היחסים המורכבים מאוד בין גברים לנשים. בנושא בינו לבינה נכתבו אלפי ספרים, כתבי עת וכתבות בעתונים ובמדיה האלקטרונית. הטלויזיה הגדילה לעשות עם תוכניות הריאליטי הרבות והמגוונות. אפילו תוכניות לייט נייט נגעו בנישה זו. חברות שידוכים משגשגות עקב דרישה הולכת וגוברת למציאת בני/בנות זוג מתאימים. מסיבות פנויים/פנויות הן מסוג האירועים היותר פופולריים בימינו.\n\nאך נדמה כי המצב בין זוגות בעינו עומד! דהיינו, מריבות בין בני זוג,\n\nתלונות בלתי פוסקות משני הצדדים על חוסר הבנה של הצרכים והרצונות שלו או שלה. מצבים - שבהעדר טיפול - מובילים לשחיקה. השחיקה מובילה, בסופו של דבר, לגירושין. מספר מקרי הגירושין הולך וגדל עם הזמן. אפילו במגזר החרדי - שבו הנושא נחשב לטאבו - קיימת עליה במספר הגירושין, ולהבדיל - במציאת שידוך עתידי.\n\nאם כן, כיצד זה קורה שמצד אחד נעשים מאמצים בלתי נדלים לחבר בין בני זוג מתאימים, אך מצד שני מספר המתגרשים הולך וגדל?\n\nהאם ייתכן, שבני/בנות זוג עוטים מסכה לפני הנישואים וזמן מה לאחר הנישואים הם מסירים אותה? נקודה זו יכולה להיות נכונה בחלקה בלבד. נכון שהאדם מטבעו יעשה מאמצים רבים למצוא חן בעיני המין הנגדי ולאחר שהוא משיג את מטרתו, עוצמת החיזור הולכת ופוחתת. אצל הרבה זוגות היא אף נעלמת. הפסקת החיזור היא אחד הגורמים לשחיקה בין בני זוג.\n\nאין זאת אומרת, שהיעדר חיזור הוא הגורם היחידי לשחיקה. ישנם גורמים נוספים. הבדלי תרבות, אמונה והשכלה יכולים להשפיע רבות. גם התחזקותה של האישה ומנגד היחלשותו של הגבר מהווים גורם משמעותי לחיכוכים בין בני זוג.\n\nיחד עם זאת, הדבר המשפיע ביותר הוא דוקא ההבדל בחשיבה בין שני המינים! כן. ההבדל בין גברים לנשים הינו חלק מה\"די אן איי\" שלנו. החשיבה של גברים שונה מהחשיבה של נשים, לכן נשים לא מבינות את הגברים וגברים אינם מבינים את הנשים. \"נשים מנוגה וגברים ממאדים\" היא אכן הגדרה נכונה ותמציתית. ההבדל בין שני המינים הינו אוניברסלי, ואינו מבחין בין דתות או תרבויות.\n\nבתקופה המודרנית, שבה האישה מתחזקת יותר ויותר, מעמדו של הגבר נחלש. תופעה זו גורמת לגבר חוסר אונים מסוים מול האישה. הוא בעצם אינו יודע כיצד להתמודד עם אישה חזקה. יחד עם זאת, אינו מעונין להצטייר כ\"חלש\".\n\nמה הוא עושה?\n\nהוא משתמש בדרכים שהוא מכיר על מנת להצטייר כחזק כגון, כפיית רצונו על האישה, אי הסכמה עם האישה, התנגדות לעשיית מטלות בבית, עבודה עד שעות מאוחרות כדי לא להיות בבית, שתיית אלכוהול ועוד.\n\nהמסקנה המתבקשת היא, שהגבר מעדיף לעשות הרבה \"שטויות\", ובלבד לא להצטייר כחלש. דרכים אלו גורמות לריחוק בין בני הזוג. מכאן נובע הצורך בטיפים לחיזוק הגבר.\n\nבהתאם לכך, אם נלמד \"להבין את ראשו/ה\" של בן/ת הזוג, ונפעל על פיו, רק אז נוכל לחיות ביחד בהרמוניה. תקשורת נכונה מהווה אבן דרך להבנת בן/בת הזוג. ההבנה תשמור על האהבה. אין זאת אומרת שלא יהיו מריבות, אך הן ייעשו ברמה שלא תוביל לשחיקה.\n\nבסדנה לחיזוק ושיפור הזוגיות בני/בנות זוג רואים שהם אינם היחידים עם קבעונות מסוימים לגבי בני/בנות זוגם. לפתע מתברר שגם אחרים נאלצים להתמודד עם אותה הבעיה. הכי חשוב, הם רוכשים כלים לבניית זוגיות מוצלחת, ללקיחת אחריות על הזוגיות. ובעיקר, הגברים לומדים לקבל בחזרה את החוסן הגברי שאבד להם כתוצאה מהתחזקותה של האישה.\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nהשאירו פרטים ונחזור אליכם"}, {"slug": "האושר-ומשמעות-החיים", "title": "האושר ומשמעות החיים", "category": "אושר", "date": "", "excerpt": "חיפוש אחר משמעות בדרך אל האושר — על הקשר בין חיים מלאי משמעות לבין אושר אמיתי.", "content": "מהו האושר האמיתי\n\nמאת: שושי כהן\n\nחיפוש אחר משמעות בדרך אל האושר\n\nמעצם היותנו בני חלוף, האושר שלנו לעולם לא יהיה מושלם. תמיד צילו של הלא נודע יעיב על הצורך במציאת משמעות בחיינו - אך יחד עם זאת עצם הידיעה הזו שאנו בני תמותה, מהווה עבורנו טריגר לחיפוש משמעות בחיינו.\n\nהפרדוקס הזה מלווה אותנו בחיי היום יום, כאשר המטרה שלנו היא לנסות ככל האפשר למצוא בתוכנו את האושר.\n\nהאושר ומשמעות החיים הם מושגים שקשורים זה בזה. ככל שאנו נחייה חיים מלאי משמעות אישית, כן האושר שלנו יגדל - וזו מטרתנו, להעצים את יכולתנו לחוות אושר בכל דרך שתביא לנו תועלת.\n\nחיפוש אחר האושר בדרכים שגויות\n\nבעולם הפוסט-מודרני, חיפוש האושר הפך ליותר ויותר מוחצן, כאשר ההנאות החיצוניות מובילות להתמכרויות שונות, ובשלב היותר מתקדם -לתחושת ריקנות וחוסר סיפוק, לירידה בהשגים בכל הרמות ולעלייה בתחלואה הגופנית. מטרת המנחה (בקבוצה או פרטנית) לעזור לאינדיווידואל לחפש את האושר בתוכו פנימה, לעזור לו לפתוח נתיבים לחיפוש משמעות, לעזור לו להגיע למודעות פנימית בדבר הדרכים להגיע לכך ולהכיר בערך עצמו כיחיד ומיוחד בעולם.\n\nראשית הדרך למציאת האושר\n\nחיפוש האושר הוא מושג יום-יומי, הנימצא עימנו תדיר כמו העור שעלינו. כל רגע בחיינו אנו צריכים לשאוף לכך שיהיה בעל משמעות, להשגת איכות חיים ברמה גבוהה מבחינה אישית. בתחילה זו תהיה עבודה עצמית מכוונת למציאת האושר בכל מיני שיטות ודרכים, אך לאחר שנלמד עצמנו את הדרך, הדבר יהיה טיבעי עבורנו כמו האויר שאנו נושמים.\n\nאין כל פסול בכך שאנו נוקטים תחילה שיטות שניראות לנו, על פניו, מעט \"מלאכותיות\" אך הן משמשות אותנו להשגת המטרה. הדבר דומה לנטילת תרופה להחלמת הגוף, לטיפול במכורים למיניהם, לעשיית דיאטה להרזייה כדי להרגיש טוב יותר עם עצמנו, או כל דרך חיובית שתרפד את דרכנו בחיפוש אחר האושר.\n\nההקרבה כביטוי (שגוי) לאושר האולטימטיבי\n\nחיפוש האושר הוא אוניברסלי ולא מבדיל בין עמים ובין דתות. האדם תמיד חיפש ישות אלוהית שתשמש לו כדמות מובילה בחיפוש משמעות והוא ירגיש יותר \"מלא\" מבחינת התכנים שבחייו במידה ויהיו לו אידיאלים שיפעל לאורם.\n\nישנה התנהגות שמשמשת כמוטו בכל הדתות ומהווה נידבך חשוב ביותר בהשגת האושר והיא: הקרבה.\n\nהנתינה לאל לכאורה היא מעשה של ויתור, אך אין זה בדיוק כך. הנתינה פה באה ממקום של אגואיסטיות וממקום של פחד, על מנת לרצות את האל וכדי שנרגיש טוב עם עצמנו. בסקלת הנתינה יש את השלב הגבוה ביותר, שמביא אותנו קרוב ככל האפשר לאושר המזוכך, והוא האלטרואיזם.\n\nהאושר האמיתי\n\nאלטרואיזם, פרושו, נתינה ללא תנאי, מתוך אהבה. ככל שאנו נותנים יותר מעצמנו אנו הופכים לאנשים מסופקים יותר ומלאים יותר באושר פנימי. אדם מגיע למקום של נתינה ממקום של שלווה פנימית והכרה בערך שלו. אדם עם ביטחון בפנימיות שלו ובערך העצמישלו, יכול לתת אהבה לאדם אחר משום שיש לו בשפע. כאשר אדם מאושר ומסופק, הוא מאיר על סביבתו - על משפחתו, חבריו. תפוקתו בעבודה עולה ובריאותו הגופנית משתפרת.\n\nנקיטת פעולות בדרך אל האושר\n\nנאמר כבר ש\"האדם ניברא בצלם\". בכל אדם יש את ה\"אלוהות\", בכל אדם יש את הייחודיות באשר היא. בכל אחד יש כוחות שאינו יודע עליהם, הוא צריך רק להוציאם לפועל ללא חת וללא מורא. הפחד מהווה מכשול בפני האושר. מצבי \"סטרס\" למיניהם ומצבי חרדה מעכבים את ההתפתחות שלנו, לכן עלינו לנקוט בפעולות שונות כדי להגיע למצב תודעה נכון.\n\nשיעזור לנו לקלוט מסרים חיוביים ולחשוב מחשבות חיוביות בדרך להשגת האושר. במהלך חיי היום-יום, על האדם לעצור, לנשום, לחשוב, לדאוג לרווחתו הנפשית והגופנית באופן הכי אגואיסטי. דבר זה הכרחי בכדי שימשיך בשיגרת יומו וימשיך להעניק למשפחתו ולאחרים.\n\nבתוך ים הנתינה שלנו, אל לנו לשכוח את עצמנו כדי שיהיו לנו הכוחות להמשך הדרך, כאשר האופטימיות והראייה החיובית מנחות אותנו.\n\nקשר גורדי בין גוף לנפש\n\nידוע הוא שיש קשר בלתי נפרד בין גוף לנפש, לכן עלינו לטפל בגוף בדרכים שונות להשגת רגיעה נפשית כפי שנאמר \"נפש בריאה בגוף בריא\". ניתן לבצע תרגילי נשימות ומדיטציה, ניתן לבצע תרגילי התעמלות, לרקוד, להזין הגוף בתזונה מאוזנת ולשתות הרבה מים...\n\nההשקעה בגוף צריכה להיות מתמדת וכחלק בלתי נפרד מהשקעה בנפש.\n\nבחיפוש אחר האושר יש לשתף את כל החושים: האזנה למוזיקה, לחוש את אור השמש ולחזות ביופי שמסביבנו, להריח, ללטף, לאהוב ולתת דרור ליצירתיות שבנו. ליצירתיות ולגמישות יש מקום מאוד חשוב בחיפוש אחר האושר והמשמעות בחיים, משום שאנו מתרוממים מעט למעלה וצופים על היקום ממקום גבוה יותר: ממקום של התבוננות רחבה יותר, של הבנה ואמפטיה ושל ויתור - כאשר כל המכלול של התחושות שלנו נובע מאהבה אין סופית שקיימת בכל אחד ואחת מאיתנו.\n\nהאושר הוא כוח\n\nאהבת העצמי-מובילה לאהבת האחר-וזו כל השאיפה שלנו: להגיע לשלמות עצמית, לסיפוק, שלווה ואושר ולתת מהשפע שקיים בתוכנו לזולת. כאשר כל אחד ואחד מאיתנו יהיה מאושר יותר ומסופק יותר, הסביבה החברתית שלנו תהיה פורה יותר, אנו כעם נרגיש פחות סבל ונהיה חזקים יותר ובעלי עוצמה כאשר המשמעות החזקה ביותר היא למעשה עצם קיומנו.\n\nאם כן, האושר האמיתי יוצר כוח רב ומלכד."}, {"slug": "מודעות-עצמית", "title": "מודעות עצמית", "category": "מודעות", "date": "", "excerpt": "על חשיבות המודעות העצמית ליצירת בריאות — והקשר הדו-כיווני בין גוף, נפש ורגשות.", "content": "מחשיבות המודעות העצמית ליצירת בריאות\n\nמאת: שושי כהן\n\nהגישה ההוליסטית\n\nהגישה ההוליסטית גורסת שהכול קשור במודעות שלנו\n\nבעולם המודרני יותר ויותר ר ווחת הדעה המקשרת בין גוף ונפש.\n\nיותר ויותר רופאים ואנשי רוח מגיעים לכלל הסכמה על הקשר הדו-כיווני בין: גוף ונפש, מוח ורגשות, ארציות ורוחניות, חרדה והזדקנות, לחצים ומחלות, חוסר ביטחון וחוליים גופניים, רגשות שליליים ומכאובים.\n\nנפש בריאה בגוף בריא\n\nכיום מקובלת אצל המדענים התפיסה שיש קשר הדוק בין המתרחש בגופנו למודעות שלנו. ככל שנטפח את האני הפנימי שלנו ונהיה מודעים יותר למתרחש בתוכנו נוכל להלחם בתהליכים הגופניים שגורמים ליצירת מחלות ולהזדקנות.\n\nככל שנהייה יותר בעלי ביטחון בעצמנו וביכולות שלנו, ככל שנגשים יותר את החלומות שלנו ונתווה לעצמנו דרך חיים נכונה ומספקת, כן נוכל לגדול בגוף בריא יותר ולהאט תהליכי הזדקנות בגופנו.\n\nנמצא קשר ברור בין מצבי חרדה, לחץ וחוסר ביטחון לתהליכי הזדקנות בגופנו והתפתחות מחלות למיניהן.\n\nחשיבות הרוגע הפנימי\n\nלשלב הרגיעה יש חשיבות גדולה לתגובה הביולוגית שלנו. הגוף משחרר נוירוטרנסמיטורים שגורמים לשלווה ולהרגשה טובה. לעומת זאת תחושות של שינאה, אלימות ורוגז גורמים לשחרור חומרים כימיים במוח המזיקים לגוף. המתח והלחץ בהם אנו חיים מהווים סכנה לקיומנו הפיזי. תפקיד המודעות העצמית שלנו הוא להביא אותנו למקום בו נחיה את חיינו באופן מספק ונסתכל על עצמנו ועל העולם בסקרנות - להגיע ממקום של פתיחות ללמידה מתמדת ולא ממקום של \"אני ואפסי עוד\" .\n\nחשיבות האמונה בעצמנו\n\nשלב הרגיעה חשוב ביותר לאנשים אובססיביים וחסרי ביטחון. הביטחון הפנימי העמוק בעצמנו מסיר מאיתנו חסימות ריגשיות המעכבות את ההתפתחות שלנו ומכאן אנו יוצאים החוצה עם תובנות נכונות לגבי עצמנו, סביבתנו, גופנו והחיים בכלל.\n\nחשיבות הפעילות הגופנית\n\nיחד עם זאת, חשוב לשלב פעילות גופנית מתונה בחיי היום יום - אז משחרר המוח אדרנלין הגורם לנו לתחושה של מרץ וחיות, ובאותו הקשר - לתחושה של ביטחון עצמי בגופנו, ביכולות שלנו ובעוצמה האישית שלנו.\n\nלסיום\n\nהמודעות העצמית הינה פאזה חשובה מאוד בתהליך התובנות הפנימיות שאנו עוברים.\n\nאם נדבק בשלבים שמניתי לעי\"ל, מובטח שנגיע לשינוי המיוחל."}, {"slug": "איך-להיות-מאושר-הסוד", "title": "איך להיות מאושר - הסוד", "category": "אושר", "date": "", "excerpt": "הסוד להיות מאושר: למה אנחנו תמיד דוחים את האושר ל'כש...' — ואיך לבחור באושר עכשיו.", "content": "כמה אנשים אתם מכירים שאומרים את המשפטים הבאים?\n\n\"אני אהיה מאושר כשאמצא עבודה\".\n\n\"אני אהיה מאושר כשילדי יתחתנו\".\n\n\"אני אהיה מאושר כשאסיים את לימודי\".\n\n\"אני אהיה מאושר כשיהיה לי הרבה כסף, (או כשאזכה בלוטו וכו')\".\n\n\"אני אהיה מאושר כשיהיה לי בית\".\n\n\"אני אהיה מאושר כשאצליח בעסק\".\n\n\"אני אהיה מאושר כשהבן / בת יחזור ארצה\".\n\n\"אני אהיה מאושר כשאעבור לגור בבית קרקע\".\n\n\"אני אהיה מאושר כשארד במשקל\".\n\n\"אני אהיה מאושר כשיהיה לי בת זוג/ בן זוג\".\n\n\"אני אהיה מאושר כשהבן/בת שלי יהיה בריא\".\n\n\"אני אהיה מאושר כשילדי יקשיבו לי\".\n\nוהרשימה עוד ארוכה...\n\nכן. אני יודעת ששמעתם לפחות חלק ממשפטים אלה, או אפילו אתם בעצמכם אמרתם אותם. ההפתעה היא, כי אותם אנשים, אשר בסופו של דבר הגשימו את ה\"תנאי לאושרם\", אכן זכו להיות מאושרים לזמן קצר. לאחר תקופה זו, הם חזרו לאותו מצב נפשי, שהיה חלק בלתי נפרד מהם, עוד לפני שהשיגו את מבוקשם. ועתה, הם מתחילים עם תנאי נוסף לאושר...\n\nמסקנה:\n\nאושר אמיתי אינו תלוי בהשגת דבר זה או אחר. אושר אמיתי הוא תחושה, אשר חווים בכל רגע נתון, ללא קשר למה שקורה מסביבנו. הווה אומר: עלינו ליהנות מן הרגע.\n\nעל האדם ליהנות מכל רגע נתון בחייו. עליו לראות את היופי, את החיובי, את הייחודי ואת היתרון של כל דבר, בכל רגע נתון.\n\nאושרנו תלוי אך ורק בזווית הראיה שלנו. אושרנו תלוי במה שאנחנו בוחרים לראות, בכיוון שבו אנחנו בוחרים ללכת ובאינטרפריטציה לארועים בחיינו.\n\nבמילים אחרות, כאשר אנו בוחרים במחשבה שלילית, היא אכן תתגשם. ואז, כאשר המחשבה השלילית מתגשמת, אנו עוד מוסיפים לקינוח: \"ידעתי שזה מה שיקרה\". ואז, כביכול, אנחנו מקבלים \"הוכחה\" כי אנו צודקים. עובדה: יש לנו \"הוכחות\" לכך.\n\nבאותה מידה, כאשר אנו בוחרים במחשבה חיובית, אנו מקבלים הוכחות חיוביות לצדקתנו.\n\nמסקנה:\n\nאם נחשוב חיובי, אם נזמן לעצמנו שפע, אושר, רוגע וכו', זה מה שנקבל. ז\"א, אם נתמקד בחיובי - נקבל חיובי.\n\nאושרנו אינו תלוי בדברים חיצוניים. אושרנו אינו תלוי באדם זה או אחר, או במה שהוא עושה, או לא עושה. אושרנו אינו תלוי בבריאותו של יקירנו. ברגע שיקירנו חולה, אין זאת אומרת שעלינו להכנס למרה שחורה, או להתמוטט. מן הסתם, אם נתמוטט, הדבר לא יביא לבריאותו של יקירנו, אלא רק יוסיף עוד אדם לא בריא לסביבה לא בריאה.\n\nמאידך, אם נקרין חיוניות ואושר בסביבתו של אדם חולה, יש סיכוי שהוא יידבק בחיוניות ובאושר שהקרנו, ויתן לו כוחות להחלים.\n\nלמרות כל הנאמר לעי\"ל, ישנם אנשים מאושרים, החוששים כי הם עלולים לאבד את האושר. חשש זה אינו עולה בקנה אחד עם הגדרת האושר האמיתי. לאושר אין צורה, גודל או משקל. לכן, אי אפשר לאבד אותו. אנשים החוששים לאבד את האושר, הם אנשים שאושרם תלוי בדבר חיצוני. כפי שכבר נאמר, אושר אינו תלוי בדבר זה או אחר.\n\nישנו פתגם האומר: \"אושר אינו שיש לך כל מה שאתה אוהב, אלא שאתה אוהב כל מה שיש לך\". זאת אומרת, תהנה מכל רגע בחייך, ללא פרשנויות שליליות.\n\nמי שבוחר להיות מאושר בכל רגע נתון, יהיה מאושר גם אם, חלילה, קורה ארוע לא נעים בחייו.\n\nאנשים רבים מתיחסים לאושר כאל שאיפה הקשה להשגה. אושר אינו תלוי בזמן מסוים. אושר אינו תלוי בעשייה עתידית. אושר חווים כאן ועכשיו, ובכל רגע נתון.\n\nהפחד משינוי הוא מיותר. הוא גם ככה לא אמיתי. הוא קיים רק בדימיון.\n\nתחליטו עכשיו שאתם מאושרים, ותהיו מאושרים.\n\nעדנה מימון\n\nטריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, מאמנת אישית להעלמת רגשות שליליים והעלמת טראומות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: זוגיות לעניין. מנחה סדנאות לניהול ושליטה בכעסים ושיפור הזוגיות, מורה מוסמכת ל NLP\n\n050-7378535"}, {"slug": "רוצה-אבל-לא-יוצא", "title": "רוצה אבל לא יוצא", "category": "מוטיבציה", "date": "", "excerpt": "רוצים לעשות משהו אבל לא עושים? הסיבה העיקרית היא אזור הנוחות — והנה איך יוצאים ממנו.", "content": "מכירים את זה שאתם רוצים לעשות משהו, אבל לא עושים?\n\nכמה פעמים רציתם לעשות משהו, אבל לא עשיתם אותו?\n\nכמה פעמים אמרתם לעצמכם: \"אילו רק הייתי\", או \"אילו רק היה לי\", \"אילו רק...\", \"\"אני רק מחכה ל...\", ולא עשיתם כלום בנדון?\n\nכמה פעמים רציתם להתחיל בדיאטה? לעשות ספורט? הליכה? למצוא עבודה? להיות בזוגיות? ללמוד? לפתוח עסק עצמאי? להגשים חלום? וכו'.\n\nקיימות סיבות רבות לכך. אך, במקום לעשות רשימה של הסיבות, אתן לכם את הסיבה העיקרית:\n\nאזור הנוחות!\n\nכן!!!\n\nבדיוק כמו תינוק הנמצא ברחם אמו, טוב לו שם ונוח לו. הוא אינו צריך להתאמץ, כי הוא מקבל הכל מאמו.\n\nכמה שאזור הנוחות נוח!\n\nיש המשך לסיפור אזור הנוחות של התינוק: בסוף הוא יוצא מאזור הנוחות שלו. הוא מחליט שנמאס לו להיות בתוך העולם הנוח שלו, ואז הוא מחליט שהגיע הזמן לעשות שינוי.\n\nוכשהוא עושה את השינוי, הוא מגלה עולם חדש ומרתק. זהו עולם מלא ברצונות. אלה רצונות טובים ובריאים. הוא רוצה להשיג תוצאות. והוא לא ינוח, ולא ישקוט, עד שישיג אותן. זאת אומרת: כשיש לו מטרה, הוא יעשה הכל על מנת להשיגה.\n\nויש לו הרבה מטרות. הוא מתלהב מהרעיון של החדשנות. הוא מחליט לעשות הכל, להתאמץ מאוד, על מנת להשיג את מטרותיו.\n\nכמו להתהפך, לשבת, לעמוד, להגיע לצעצוע, לאכול לבד, ללכת, לבדוק, לבחון, לדעת, להכיר, לטעום, לחוש, לשמוע, לראות דברים חדשים וכו``. את כל אלה הוא מתעקש לעשות לבד, למרות שהם מהווים שינוי משמעותי. שינוי מהפכני, למרות שזה לא קל. ולמרות שהדבר דורש מאמץ רב מאוד. בעצם, למרות שהדבר דורש יציאה מאזור הנוחות שלו!!!!!\n\nונחזור אליכם:\n\nאם תינוק מתאמץ כל כך הרבה על מנת להשיג את מטרותיו, האם אתם לא אמורים לפחות להתחיל בקטן את השינוי?\n\nהאם אתם מעוניינים סוף סוף לצאת מהרחם? עד מתי תשארו בנוחות שלכם?\n\nתארו לכם שתינוק (כלשהו) היה מחליט שזה מפחיד ללמוד ללכת, ואז הוא היה אומר:\n\n\"נוח לי ככה\", או \"לא היום\", או \"לא השנה\", או \"כשארצה ללכת, אז אלך\", או \"אני יכול ללכת, אני פשוט לא רוצה\", או \"לא מתאים לי\", או \"זה מפחיד ללכת\", או \"מה יקרה אם אפול ואקבל מכה?\", או \"אני נהנה מזה. זו אחת ההנאות שלי בחיים\" וכו`\n\nהאם ידעתם שהנוחות הורגת יצירתיות? הורגת גמישות מחשבתית? הורגת אינטואיציה? פוגעת בזיכרון? ועוד.\n\nאילו הייתם הורים לילד כזה, הייתם מודאגים מאוד.\n\nמה קורה כשהילד הזה הוא אתם?\n\nבדיוק כמו שהתינוק אינו אומר לעצמו: \"אני פוחד להכשל, לכן אני לא אעשה שום דבר\", כך גם אתם.\n\nתחליטו שעכשיו אתם עושים שינוי. זה לא חייב להיות שינוי גדול (כמו אצל התינוק....). מספיק שינוי קטן אחד... קטנטן... פיצי...\n\nלאחר כמה ימים תוסיפו עוד שינוי קטן.\n\nתעשו כמה שינויים קטנים. בסופו של דבר, הם יהפכו לשינויים גדולים.\n\nאז מהו השינוי שאתה רוצה לעשות עכשיו?\n\nאיזו פעולה קטנטנה תעשה עכשיו על מנת לקדם את עצמך?\n\nאתה יודע שהכל אפשרי, נכון?\n\nבהצלחה!\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה מוסמכת לNLP מטעם ממציא ה NLP.\n\n050-7378535"}, {"slug": "דרכים-למנוע-סטרס", "title": "30 דרכים למנוע סטרס - חלק א'", "category": "סטרס", "date": "", "excerpt": "איך להתמודד עם פחדים, סטרס, חרדות וחוסר ביטחון — 10 הדרכים הראשונות למניעת סטרס, חלק א'.", "content": "איך להתמודד עם פחדים, סטרס, חרדות וחוסר ביטחון\n\nמצבי סטרס (stress), הכוללים לחץ, מתח דאגות חרדות, פחדים, דחק ועוד, פוגעים במהלך תקין של החיים. לעתים הדבר גורר אחריו קבלת החלטות שגויות, המגדילות ומגבירות את המתח. במקרה כזה, נוצרת תגובת שרשרת, אשר מביאה לבעיה נוספת. במלים אחרות, מתח גורר מתח רב יותר.\n\nלדוגמה, אדם שלא הספיק לסיים מטלה מסוימת בזמן, נכנס לסטרס. אם אותו אדם ישחזר את הזמן שעבר עד לאותו רגע, הוא ישים לב שדווקא הסטרס יצר אצלו חסימה בחשיבה. וכתוצאה מחסימה זו, הוא דחה את השלמת המטלה. דחייה זו רק הגבירה את הסטרס. בינתיים נוספו עוד מטלות, והלחץ גובר....\n\nיש לזכור כי הורים הנמצאים בסטרס מעבירים זאת לילדיהם. הם בעצם מלמדים את ילדיהם לא להתמודד. הם מלמדים את ילדיהם להכנע, ולא לקחת אחריות על החיים.\n\nהורים רבים חושבים בטעות שאם יראו לילדם שהם דואגים לו, זה יתפרש כאהבה. טעות זו היא הרסנית, מכיוון שהילד לומד לדאוג, וכשיהיו לו ילדים משלו, הוא יעביר זאת לילדיו מבלי להיות מודע לכך. לידיעתכם, ניתן לאהוב את ילדכם ולהראות לו אהבה, ללא דאגות וחרדות.\n\nתופעת לוואי רצינית כתוצאה מסטרס ודאגנות יתר היא: מחלות שונות - חולשה כללית, בעיות לב, בעיות עור, בעיות בנשימה, בעיות בלחץ הדם, בעיות במפרקים ובעמוד השדרה.\n\nעל פי מחקר ה CDC :\n\n85% מן המחלות הם תוצאה של מתח.\n\nהנה 10 טיפים מנצחים (מתוך 30) לנטרול מתחים:\n\n1. תאמר לעצמך: \"ואם זה יקרה - אז מה?\"\n\nלדוגמה: \"לא אספיק לסיים את המטלה בזמן\". ← ואם זה יקרה - אז מה ?← \"הבוס יכעס עלי\". ← ואם זה יקרה - אז מה? ← \"הוא לא יעריך אותי\".← ואם זה יקרה - אז מה? ← \"הוא יעכב את הקידום שלי\"← ואם זה יקרה - אז מה?\" (וכך הלאה....).\n\nלרוב, לאנשים יש נטיה לחשוב דווקא על הגרוע ביותר.\n\nהאם יכול להיות שהבוס לא יכעס, אלא דווקא יבין אותך?\n\nבוודאי שזה יכול להיות. מומלץ תמיד לחשוב על אפשרות חיובית. ואז, הסיכוי שהיא תתגשם יהיה גדול יותר.\n\n2. תראה את חצי הכוס המלאה\n\nבמקום לחשוב שזה לא ילך, תחשוב שזה ילך, שזה יצליח. ואז, תת המודע שלך יכוון אותך להצלחה.\n\nלדוגמה: במקום לחשוב שתיכשל בראיון עבודה, תחשוב שתצליח. ואז הסיכויים להצלחה יגדלו.\n\nוגם אם לא תצליח - אז מה? יהיו עוד ראיונות עבודה. מכל ראיון עבודה אתה מפיק תועלת כלשהי. אתה לומד מה לשפר אצלך.\n\n3. תאמין בעצמך!\n\nאתה יכול הרבה יותר ממה שאתה חושב. כמו שהנרי פורד אמר: \"גם אם תאמין שאתה יכול, וגם אם תאמין שאתה לא יכול, בכל מקרה אתה צודק\". אז אם בכל מקרה אתה צודק, עדיף שתחשוב שאתה יכול ושתצליח!\n\n4. כשיש בעיה, תתיחס אליה כאל אתגר\n\nתאהב אתגרים. דוגמה: הדרך למקום מסוים מסובכת לך, או ארוכה לך? איזה יופי! תנצל הזדמנות זו להכיר דרך חדשה. תראה לעצמך שזה קטן עליך. תהיה גאה בעצמך על שאתה יוצא מאזור הנוחות.\n\n5. כל יום תעשה משהו חדש, או תעשה את אותו הדבר באופן שונה\n\nלדוגמה: תניח את הטלפון במקום שונה ממה שאתה רגיל. נכון, בהתחלה יכול להיות שתחזור לאוטומט הקודם. זה חלק מהתהליך. תן לזה זמן. אפשר להתרגל לכל דבר חדש.\n\nדוגמה נוספת: אם אתה לובש קודם חולצה, ואח\"כ מכנסיים - תלבש קודם מכנסיים, ואח\"כ חולצה. העיקר שיהיה שינוי כלשהו.\n\nתתמיד בעשיית שינויים.\n\n6. תפסיק להסביר את עצמך\n\nהסברים הם התגוננות. במקום להסביר - תעשה.\n\nלדוגמה: שפכת בטעות כוס קפה (וגם הכוס נשברה). במקום להסביר שמישהו הניח אותה בקצה השולחן, מאחורי בקבוק שלא ניתן לראות דרכו וכו' וכו', תגיד \"אני מצטער\". תקום, ותנקה.\n\nדוגמה נוספת: במקום להסביר למה העסק תקוע - תעשה משהו כדי לקדם אותו.\n\n7. תתכונן ליום גשום\n\nתלמד למנוע בעיות, מאשר לחכות שיקרו, ואז קשה יותר לפתור אותן.\n\nבדיוק כמו שאתה אף פעם לא נתקע בלי דלק באוטו, כי אתה יודע יפה מאוד, שאם לא תתדלק, האוטו יפסיק לנסוע באמצע הדרך. ואז תצטרך לקחת ג'ריקן, להגיע לתחנת דלק קרובה (שיכול להיות שהיא רחוקה מהמקום ההוא), וגם לסחוב אותו בחזרה.\n\n8. כל יום תודה על 5 דברים שקרו לך (או 5 דברים שיש לך)\n\nפרופ' טל בן שחר ממליץ על כך בחום. זוהי אחת השיטות החזקות ביותר למניעת דאגה, וליצירת הרגשה טובה. הרבה גורואים מכל העולם ממליצים על זה.\n\n9. אם אתה פרפקציוניסט, תבדוק היכן אתה יכול לשחרר\n\nמומלץ לשחרר בהדרגה. למשל, אם עד כה הרצפה היתה חייבת להיות נקיה, מעכשיו תחשוב שרצפה נקיה לא מביאה אושר, או אהבה, או הערכה עצמית. אז תחשוב שגם אם הרצפה לא מי יודע מה, אתה מרגיש טוב עם עצמך.\n\nתעשה רשימה של דברים שאתה מקפיד לעשות באופן מושלם, ותחליט באלו מהם אתה מוכן לשחרר.\n\nהערה חשובה לזוגות: גם אם בן הזוג/בת הזוג לא ממש מסודרים - שחררו. אפשרו להם להיות הם. בדיוק כמו שהם לא דורשים מכם להיות מבולגנים, כך גם אתם אל תדרשו מהם להיות מסודרים. אין חוק שקובע שסדר עדיף על בלאגן.\n\n10. תחייך - גם אם לא בא לך\n\n\"חיוך הוא הקו העקום היחיד שיכול ליישר כמעט כל דבר,\" אמרה פיליס דילר. היא צודקת.\n\nהחיוך משחרר אנדורפינים (חומרים כימיים במוח, היוצרים תחושה טובה, ומשפרים את מצב הרוח).\n\nזה גם לא עולה כסף...חח\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nednamaim@gmail.com"}, {"slug": "30-דרכים-למנוע-סטרס-חלק-ב", "title": "30 דרכים למנוע סטרס - חלק ב'", "category": "סטרס", "date": "", "excerpt": "10 דרכים נוספות (11–20) למנוע סטרס, חרדה ודאגה — חלק ב'.", "content": "טיפול במצבי לחץ וסטרס\n\nלידיעתכם, מצבי סטרס עלולים לגרום לדיכאון, חרדה, לחצים לא ברורים, תקיעויות למיניהן, פחדים וכו'. בנוסף, סטרס יוצר בעיות בריאותיות רבות. לכן, החשיבות למניעת מצבים אלה גדולה במיוחד.\n\nהנה 10 דרכים נוספות למנוע סטרס, חרדה, דאגה: (המאמר כתוב בלשון זכר. כמובן שהוא מיועד לשני המינים)\n\n11. תהנה מעבודתך ותעסיק את עצמך בדברים שאתה אוהב\n\nכאשר יש לנו תעסוקה, ואנו גם נהנים ממנה, המוח מפריש חומרים שיוצרים תחושה נעימה. במקרה כזה, אי אפשר לייצר חרדה. אי אפשר להרגיש גם טוב וגם רע באותו זמן.\n\nחשוב לציין שלתחושות בנוגע לעבודה יש משמעות קריטית לגבי מצב רוחנו. אם כבר אתה יוצא לעבודה, תהנה ממנה. זו אחריותך. אף אחד אחר לא אחראי להנאתך. ואם לא נהנית, תשאל את עצמך מה אתה יכול לעשות חדש כדי לשפר את זה.\n\n12. תקדיש חצי שעה ביום לנשימות איטיות\n\nככל שננשום לאט יותר, כך נהיה רגועים יותר. תרגול קבוע של נשימות יביא לרגיעה אוטומטית.\n\n13. תיזכר בחוויות נעימות שהיו לך בעבר\n\nברגע שנקדיש זמן להרהורים על חוויות נעימות, הגוף יגיב באופן אוטומטי בצורה חיובית. לדוגמה: תחשבו על תינוק שהחזקתם בידיים, או על הריח שלו, או על הצחקוקים שלו. נכון שזה עושה לכם טוב?\n\n14. תעשה ספורט מתון\n\nמומלץ לעשות מתיחות על בסיס יומי. כל ספורט מתון מומלץ מאוד. חשוב להקפיד על עשייה יומיומית, ועל הנאה מכך. גם אם ההתחלה מפחידה, כבר לאחר שבועיים תרגישו בהבדל. ישנו משפט האומר: \"היום הוא המחר שממנו חששת אתמול\". זאת אומרת, פחדת מהרבה דברים, אך הם לא התממשו. כך גם לגבי עשיית ספורט. תתחיל, ותראה שהשד איננו נורא כל כך כמו שחשבת. אפילו להיפך: אתה תרגיש נפלא.\n\n15. תרשום את מטלותיך\n\nתעשה לך מנהג קבוע: לרשום את כל מה שיש לך לעשות. כל פעם שסיימת שני דברים, תעשה רשימה חדשה, זה נותן הרגשה טובה.\n\n16. תחמיא לעצמך\n\nאנשים ביקורתיים אינם יודעים להחמיא – לא לעצמם ולא לאחרים. אין פלא שהם מרגישים רע. המחשבות שלהם נמצאות בשלילי. לכן, מעכשיו תעשה סוויץ בראש: תחמיא גם לעצמך וגם לאחרים. אני יודעת שיש כאלה שקשה להם. דווקא מי שקשה לו – זקוק לזה יותר. כמו שכבר נאמר: ההתחלה קשה, אך אח\"כ אפשר לקטוף את הפירות.\n\n17. צא לטיולים\n\nטיולים מרחיבים את הדעת ואת הנפש. כמובן, יש לתכנן מראש את הטיול, על מנת ליהנות ממנו בכל רגע.\n\n18. תשקיע בעצמך\n\nאנשים רבים חושבים רק על הילדים, ומשקיעים את כל כולם בילדים, ואת עצמם הם מזניחים. אין טעות גדולה מזו. אם לא תשקיע בעצמך, כיצד ילדיך ילמדו להשקיע בעצמם?\n\n19. תהיה גמיש מחשבתית\n\nב-NLP קיימת הנחת יסוד האומרת: הצד הגמיש יותר במערכת, הוא בעל השליטה. מומלץ שיהיו לך מינימום 3 אפשרויות פעולה על כל סיטואציה. באופן כזה, לא תצטרך להחליט או זה או זה, אלא, תהיה גם אפשרות נוספת. כמובן, ככל שיהיו יותר אפשרויות, כך יהיה יותר קל.\n\n20. תקשיב למוזיקה שמחה\n\nשירי דיכאון יכולים להיות יפים, אך הם יוצרים דיכאון. האם אתה מעוניין בזה? בוודאי שלא. לכן, תכין לך דיסק של שירים שאתה אוהב, שירים שמחים, שמרקידים את הלב. תכין דיסק אחד לבית ודיסק אחד לאוטו.\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nednamaim@gmail.com"}, {"slug": "30-דרכים-למניעת-סטרס-חלק-ג", "title": "30 דרכים למניעת סטרס - חלק ג'", "category": "סטרס", "date": "", "excerpt": "10 טיפים נוספים (21–30) למניעת לחץ, דאגנות יתר, סטרס וחרדות — חלק ג'.", "content": "איך למנוע לחץ, דאגנות יתר, סטרס וחרדות\n\nהנה 10 טיפים נוספים למניעת סטרס, דאגה, דאגנות יתר, חרדות:\n\n21. תסלח לעצמך\n\nאנשים שסולחים לעצמם על טעויות, לוקחים את החיים יותר בקלות.\n\n22. תגשים את עצמך\n\nהגשמה עצמית מפרישה חומרים כימיים טובים למוח ויוצרת רוגע.\n\n23. תציב לעצמך מטרות\n\nהצבת מטרות מסיטה את המחשבות לכיוון מסוים (חיובי), ובכך מונעת מחשבות שליליות.\n\n24. תפסיק להאשים\n\nאנשים רבים מאשימים את כל העולם: את המורים, את הרופאים, את חברי הכנסת, את המוכר ועוד\n\nועוד. מחשבות כאלה מכוונות את תשומת הלב להרגל של האשמות.\n\n25. תקבל את עצמך כמו שאתה\n\nאנשים רבים רוצים להיות משהו אחר ממה שהם. רצון זה אינו מתאים לנפש האדם. זה\n\nגורם לסטרס רב ולדאגנות יתר. כשתקבל את עצמך כמו שאתה, ואיך שאתה, תרגיש שלווה.\n\n27. תעריך את עצמך\n\nחוסר הערכה עצמית יוצר בריחה. אדם הבורח הוא בעצם בורח מעצמו, ובסוף הוא מגלה שאין לו לאן\n\nלברוח. כך נוצר סטרס.\n\n28. תקשיב לעצמך ולאחרים\n\nכאשר אנו מקשיבים באמת לעצמנו, אנו מגלים שאנו יכולים להקשיב גם לאחרים. כאשר הראש\n\nמתפנה להקשבה נפתח מקום לשקט נפשי.\n\n29. תפסיק להתחשבן עם העבר\n\nגם אם מצבך כיום הוא תוצאה של מה שעשו לך בעבר, תשכח מזה ותתחיל מחדש. אנשים המתחשבנים עם העבר, לא שמים לב שבינתיים הם מפסידים את ההוה וגם את העתיד. ממציא הNLP אמר: \"מכירים את המשפט: יום אחד תסתכל אחורה ותצחק. אז למה לחכות?\"\n\n30 קח אחריות על רגשותיך\n\nתפסיק לעשות \"רגשי\" לאחרים. סחטנות רגשית היא אחד הדברים המונעים חוסן נפשי. במקום לספר לאחרים מה קרה לך בגללם, ואיזה צרות היו לך בגלל ההתנהגות שלהם, קח אחריות על רגשותיך. תחליט שכל מה שקורה לך מבחינה רגשית הוא באחריותך, ואף אחד אחר אינו אחראי לכך.\n\nבמידה שאתה בכל זאת (למרות 30 הטיפים שקיבלת) לא מאושר ולא רגוע, סימן שעשית משהו לא נכון. יכול להיות שיש לך אמונות שיוצרות התנגדות פנימית בתוכך. תודה בזה, ותחליט שאתה לוקח עזרה מאיש מקצוע. בשיטת NLP ותרפיית קו הזמן קיימות טכניקות מדהימות לשינוי בעוצמה, לרוגע, לשלווה, לאושר ולשלמות.\n\nזכור: הכל אפשרי!\n\nעדנה מימון/ טריינר ב-NLP, מאסטר ב-NLP, מאסטר קאוצ', מאסטר בתרפיית קו הזמן, מאסטר בהיפנותרפיה, לטיפול ברגשות שליליים וטיפול בטראומות, חרדות, פחדים, פוביות, ושינוי בשיטת פסיכומטפוריקה לשינוי רגשי והתנהגותי. מנהלת את: מכללת אמביציות. מנחה סדנאות לניהול ושליטה בכעסים, שיפור הזוגיות, ביטחון עצמי ומורה לNLP מטעם ממציא ה NLP.\n\n050-7378535\n\nלדף רשימת סדנאות NLP\n\nלמאמר: ביטחון עצמי ודימוי עצמי\n\nלתגובות משתתפי סדנת בטחון עצמי ודימוי עצמי"}] as const;

export const articles: Article[] = articlesData.map(a => ({
  slug: a.slug,
  title: a.title,
  category: a.category,
  date: a.date,
  excerpt: a.excerpt,
  content: a.content,
}));

export function getArticleBySlug(slug: string): Article | undefined {
  return articles.find((a) => a.slug === slug);
}

export function getArticlesByCategory(category: string): Article[] {
  return articles.filter((a) => a.category === category);
}
